/* AUTO-GENERATED — Idaho Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["ID"] = {"code":"ID","name":"Idaho","agency":"Idaho DMV","agencyShort":"DMV","handbook":"https://itd.idaho.gov/wp-content/uploads/2025/10/CDL-manual.pdf","links":{},"en":[{"q":"On Idaho highways, what is the maximum legal width of a vehicle, including its load?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"Idaho Code 49-1010 limits the total width of any vehicle, including its load, to 8 feet 6 inches (102 inches). Wider loads require an oversize permit. Source: Idaho Code 49-1010 (Size of Vehicles and Loads).","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle and its load on Idaho highways?","options":["13 feet 6 inches","14 feet","15 feet","13 feet"],"answer":1,"explanation":"Idaho Code 49-1010 sets the maximum height of a vehicle, including the load, at 14 feet. Loads taller than 14 feet need an overheight permit. Source: Idaho Code 49-1010.","handbook":"","hbref":""},{"q":"What is the maximum gross weight on a single axle in Idaho?","options":["18,000 pounds","22,400 pounds","20,000 pounds","21,500 pounds"],"answer":2,"explanation":"Idaho Code 49-1001 sets the maximum single axle gross weight at 20,000 pounds. Source: Idaho Code 49-1001 (Allowable Gross Loads).","handbook":"","hbref":""},{"q":"What is the maximum gross weight allowed on a tandem axle in Idaho?","options":["34,000 pounds","36,000 pounds","32,000 pounds","40,000 pounds"],"answer":0,"explanation":"Under Idaho Code 49-1001, a set of tandem axles may carry up to 34,000 pounds, matching the federal standard. Source: Idaho Code 49-1001.","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle or combination weight allowed on Idaho's portion of the U.S. federal interstate and defense highway system without a permit?","options":["80,000 pounds","105,500 pounds","90,000 pounds","129,000 pounds"],"answer":0,"explanation":"Idaho Code 49-1001 caps gross vehicle or combination weight on the federal interstate and defense highways at 80,000 pounds, consistent with federal law. Source: Idaho Code 49-1001.","handbook":"","hbref":""},{"q":"On Idaho's general (non-interstate) state highways, what is the maximum gross vehicle or combination weight allowed under the basic statute before resorting to a special excess-weight permit?","options":["80,000 pounds","129,000 pounds","100,000 pounds","105,500 pounds"],"answer":3,"explanation":"Idaho Code 49-1001 allows a maximum gross vehicle or combination weight of 105,500 pounds, except that the limit drops to 80,000 pounds on the federal interstate and defense highways. Source: Idaho Code 49-1001.","handbook":"","hbref":""},{"q":"What is the maximum gross weight permitted on a single wheel in Idaho?","options":["8,000 pounds","12,000 pounds","10,000 pounds","6,000 pounds"],"answer":2,"explanation":"Idaho Code 49-1001 sets the maximum single wheel gross weight at 10,000 pounds. Source: Idaho Code 49-1001.","handbook":"","hbref":""},{"q":"Idaho uses the federal bridge weight formula to determine the maximum weight allowed on a group of consecutive axles. Which formula does Idaho Code adopt?","options":["W = 500((LN/N-1) + 12N + 36)","W = 1000(L + N + 20)","W = 34,000 + (N x 12)","W = 250(LN + 12 + 36N)"],"answer":0,"explanation":"Idaho Code 49-1001(1) adopts the federal bridge formula W = 500((LN/N-1) + 12N + 36), where W is the max weight, L is the distance in feet between the extremes of the axle group, and N is the number of axles. Source: Idaho Code 49-1001(1).","handbook":"","hbref":""},{"q":"In Idaho's bridge formula, what does the variable 'L' represent?","options":["The legal load rating of the trailer","The distance in feet between the extremes of a group of two or more consecutive axles","The length of the longest single axle group only","The licensed gross weight of the vehicle"],"answer":1,"explanation":"In the formula W = 500((LN/N-1) + 12N + 36), 'L' is the distance in feet between the extremes of any group of two or more consecutive axles, 'N' is the number of axles, and 'W' is the maximum weight. Source: Idaho Code 49-1001(1).","handbook":"","hbref":""},{"q":"Two consecutive sets of tandem axles may each carry 34,000 pounds in Idaho only if the overall distance between the first and last axles of those tandem sets is at least how many feet?","options":["30 feet","36 feet","40 feet","34 feet"],"answer":1,"explanation":"Idaho Code 49-1001(1)(b) allows two consecutive tandem sets to carry 34,000 pounds each provided the distance between the first and last axles of those sets is 36 feet or more. Source: Idaho Code 49-1001(1)(b).","handbook":"","hbref":""},{"q":"A semitrailer operating on routes that are part of the national network in Idaho may not exceed what length?","options":["48 feet","53 feet","57 feet","45 feet"],"answer":1,"explanation":"Idaho Code 49-1010 limits a semitrailer operating on the national network (and related access routes) to 53 feet in length. Source: Idaho Code 49-1010.","handbook":"","hbref":""},{"q":"Under Idaho Code, a load on a vehicle generally may not extend beyond the front of the vehicle more than how many feet?","options":["3 feet","4 feet","6 feet","2 feet"],"answer":1,"explanation":"Idaho Code 49-1010 prohibits a load from extending beyond the front of a vehicle more than 4 feet. Source: Idaho Code 49-1010.","handbook":"","hbref":""},{"q":"A vehicle combination hauling a reducible load may operate at a gross weight above 105,500 pounds in Idaho, but not exceeding what weight, and only on designated non-interstate routes with proper registration and permit?","options":["129,000 pounds","117,000 pounds","140,000 pounds","125,500 pounds"],"answer":0,"explanation":"Idaho Code 49-1001(1)(c) allows reducible loads above 105,500 pounds but not exceeding 129,000 pounds on non-interstate highways when the vehicle is registered, complies with the weight formula and length restrictions, and operates on designated routes per Idaho Code 49-1004. Source: Idaho Code 49-1001(1)(c) and 49-1004.","handbook":"","hbref":""},{"q":"Who issues the special-route annual permit that authorizes a registered combination to haul reducible loads between 105,501 and 129,000 pounds in Idaho?","options":["The county sheriff of each county on the route","The Federal Highway Administration","The Idaho Transportation Department or, at its discretion, a local public highway agency","Any commercial truck stop weigh station"],"answer":2,"explanation":"Idaho Code 49-1004 provides that special-route permits for loads from 105,501 up to 129,000 pounds are issued by the Idaho Transportation Department, or in its discretion by a local public highway agency, on routes designated by the department or local authorities. Source: Idaho Code 49-1004.","handbook":"","hbref":""},{"q":"Which is generally required before a vehicle that exceeds Idaho's legal size or weight limits may move on the highway?","options":["A valid oversize/overweight permit obtained before the move","A change to a Class A CDL","A federal waiver from the FMCSA","Only a verbal okay from a port-of-entry officer"],"answer":0,"explanation":"Idaho Code 49-1004 and ITD permitting rules require an oversize and/or overweight permit, obtained before the movement, to operate a vehicle exceeding the legal size or weight limits; the permit must be carried in the vehicle. Source: Idaho Code 49-1004; ITD permit rules (IDAPA 39.03.03).","handbook":"","hbref":""},{"q":"Idaho law gives a weight variance (a separate, more generous axle-spacing table) on non-interstate highways to vehicles hauling certain commodities. Which group of commodities is covered?","options":["Logs, pulp wood, rough lumber, poles, ores, sand and gravel, and agricultural commodities including livestock","Refrigerated groceries and bottled beverages","New automobiles and recreational vehicles","Hazardous materials and bulk fuel only"],"answer":0,"explanation":"Idaho Code 49-1001(2) provides a special allowed-load table for vehicles hauling logs, pulp wood, stull, rough lumber, poles or piling; ores, concentrates, sand and gravel and aggregates in bulk; or agricultural commodities including livestock. Source: Idaho Code 49-1001(2).","handbook":"","hbref":""},{"q":"The special weight allowances for logs, ores, sand/gravel and agricultural commodities in Idaho Code 49-1001(2) do NOT apply once the total gross weight is intended to exceed what figure, as declared by the operator?","options":["80,000 pounds","79,000 pounds","105,500 pounds","84,000 pounds"],"answer":1,"explanation":"Idaho Code 49-1001(2) states that the commodity weight allowances do not apply if the total gross weight is intended to exceed 79,000 pounds as declared by the operator. Source: Idaho Code 49-1001(2).","handbook":"","hbref":""},{"q":"At an Idaho port of entry, a loaded vehicle may not proceed past the scale when the weight of a single axle exceeds the maximum limit by how much?","options":["500 pounds or more","1,000 pounds or more","2,000 pounds or more","5,000 pounds or more"],"answer":2,"explanation":"Idaho Code 49-1001(8) provides that a vehicle may not proceed past a port of entry when a single axle exceeds the maximum by 2,000 pounds or more, or when gross/axle-group weight exceeds the maximum by 7% or more. Source: Idaho Code 49-1001(8).","handbook":"","hbref":""},{"q":"At an Idaho port of entry, by what percentage over the maximum allowable gross or axle-group weight will a vehicle be stopped and required to come into compliance before continuing?","options":["7 percent or more","5 percent or more","10 percent or more","15 percent or more"],"answer":0,"explanation":"Idaho Code 49-1001(8) requires a vehicle to be brought into compliance at the scale when its gross vehicle weight or a combination of axles exceeds the maximum allowable weight by 7 percent or more (a single axle threshold is 2,000 pounds). Source: Idaho Code 49-1001(8).","handbook":"","hbref":""},{"q":"Idaho requires escorts (pilot/flag cars) for over-width permitted loads. At what load width does Idaho generally require at least one pilot/escort vehicle?","options":["Over 8 feet 6 inches wide","Over 10 feet wide","Over 12 feet wide","Over 16 feet wide"],"answer":2,"explanation":"Under ITD's oversize movement rules, a load wider than 12 feet generally requires one pilot/escort vehicle, and loads over 14 feet wide require two. Flags are required on the corners of over-width loads, and an OVERSIZE LOAD sign and amber lights are required on escorts. Source: ITD permit rules (IDAPA 39.03.05 / Pilot-Escort requirements).","handbook":"","hbref":""},{"q":"In Idaho, a CDL is required to operate any single vehicle with a Gross Vehicle Weight Rating (GVWR) of how many pounds or more (towing nothing over 10,000 lbs)?","options":["16,001 pounds","26,001 pounds","33,001 pounds","10,001 pounds"],"answer":1,"explanation":"Idaho adopts the federal threshold: a Class B CDL is required for any single vehicle with a GVWR of 26,001 lbs or more (Idaho CDL Manual, ITD; 49 CFR 383.91).","handbook":"","hbref":""},{"q":"Which Idaho CDL class is required to drive a combination vehicle with a GCWR of 26,001 lbs or more where the towed unit(s) exceed 10,000 lbs GVWR?","options":["Class C","Class B","Class A","Class D"],"answer":2,"explanation":"A Class A CDL covers combination vehicles with a GCWR of 26,001 lbs or more provided the GVWR of the vehicle(s) towed is more than 10,000 lbs (Idaho CDL Manual, ITD).","handbook":"","hbref":""},{"q":"Under Idaho rules, a vehicle designed to transport 16 or more passengers (including the driver) but under the Class A/B weight limits requires which CDL class?","options":["Class C","Class A","Class B","No CDL required"],"answer":0,"explanation":"A Class C CDL is required for vehicles that do not meet Class A or B criteria but are designed to carry 16 or more passengers including the driver, or carry placardable hazardous materials (Idaho CDL Manual, ITD).","handbook":"","hbref":""},{"q":"Which endorsement letter does Idaho assign to the authority to drive tank (tanker) vehicles carrying liquids or gases in bulk?","options":["T","N","X","H"],"answer":1,"explanation":"The N endorsement is for tank vehicles. (T = doubles/triples, H = hazmat, X = combined tank and hazmat.) Source: Idaho CDL Manual, ITD; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"In Idaho, the 'T' endorsement authorizes the holder to operate which type of vehicle?","options":["Tank vehicles","Vehicles carrying hazardous materials","Double and triple trailers","Vehicles carrying 16+ passengers"],"answer":2,"explanation":"The T endorsement covers double and triple trailers and requires passing a knowledge test only (Idaho CDL Manual, ITD; 49 CFR 383.93).","handbook":"","hbref":""},{"q":"To obtain an Idaho HazMat (H) endorsement, an applicant must pass a knowledge test and also complete what additional federal requirement?","options":["A behind-the-wheel skills test","A TSA security threat assessment (background check)","A vision waiver application","A second medical exam"],"answer":1,"explanation":"Idaho requires the H endorsement applicant to pass a knowledge test and clear a TSA Security Threat Assessment (fingerprint-based background check) under the USA PATRIOT Act (Idaho CDL Manual, ITD; 49 CFR 1572).","handbook":"","hbref":""},{"q":"In Idaho, before issuing a school bus (S) endorsement, which other endorsement must the applicant also hold or obtain?","options":["N (Tank)","T (Doubles/Triples)","P (Passenger)","H (HazMat)"],"answer":2,"explanation":"The S (school bus) endorsement requires the P (passenger) endorsement, plus a knowledge test and a skills test in a school bus (Idaho CDL Manual, ITD; 49 CFR 383.123).","handbook":"","hbref":""},{"q":"Which Idaho CDL endorsement requires both a knowledge test and a behind-the-wheel skills test in a representative vehicle?","options":["N (Tank)","P (Passenger)","T (Doubles/Triples)","H (HazMat)"],"answer":1,"explanation":"The P (passenger) endorsement requires passing a knowledge test and a skills test in a passenger vehicle; N, T, and H are knowledge-test-only endorsements (Idaho CDL Manual, ITD; 49 CFR 383.93).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Idaho CDL for driving a commercial vehicle only within Idaho (intrastate)?","options":["16 years old","18 years old","19 years old","21 years old"],"answer":1,"explanation":"Idaho allows an intrastate CDL at age 18; the applicant must also hold a valid Idaho Class D license and have one year of licensed driving experience (Idaho CDL Manual, ITD; Idaho Code 49-305).","handbook":"","hbref":""},{"q":"What minimum age does Idaho (following federal law) require to drive a commercial vehicle across state lines (interstate)?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"Interstate commercial driving requires a minimum age of 21; an 18-year-old Idaho CDL holder is restricted to intrastate operation (Idaho CDL Manual, ITD; 49 CFR 391.11).","handbook":"","hbref":""},{"q":"A HazMat (H) endorsement in Idaho may not be issued to an applicant who is younger than what age?","options":["18","19","21","25"],"answer":2,"explanation":"Because hazmat transport for hire generally involves interstate commerce and a TSA assessment, the H endorsement requires the applicant to be at least 21 (Idaho CDL Manual, ITD; 49 CFR 383/1572).","handbook":"","hbref":""},{"q":"Under federal rules adopted in Idaho, how long must a driver hold a Commercial Learner's Permit (CLP) before being eligible to take the CDL skills test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"The CLP must be held for a minimum of 14 days before the skills test may be taken (Idaho CDL Manual, ITD; 49 CFR 383.25).","handbook":"","hbref":""},{"q":"For how long is an Idaho Commercial Learner's Permit (CLP) valid before it must be renewed?","options":["90 days","180 days","1 year","2 years"],"answer":1,"explanation":"An Idaho CLP is valid for 180 days and may be renewed one time for an additional 180 days without retaking the general knowledge test (Idaho CDL Manual, ITD; 49 CFR 383.25).","handbook":"","hbref":""},{"q":"While driving on an Idaho Commercial Learner's Permit (CLP), the holder must always be accompanied by what?","options":["Any licensed adult age 25 or older","A CDL holder of the proper class/endorsement seated next to the driver","A DMV examiner","No one; solo driving is allowed"],"answer":1,"explanation":"A CLP holder may operate a CMV only when accompanied by a person who holds a valid CDL for the vehicle type and is seated beside the driver (Idaho CDL Manual, ITD; 49 CFR 383.25).","handbook":"","hbref":""},{"q":"Which document is NOT among those an Idaho DMV requires to apply for a CDL?","options":["Proof of identity","Proof of Social Security number","Proof of Idaho residency and lawful presence","A signed letter from a current employer"],"answer":3,"explanation":"Idaho requires proof of identity, Social Security number, Idaho residency, and lawful presence/citizenship; an employer letter is not required (Idaho CDL Manual / ITD DMV requirements).","handbook":"","hbref":""},{"q":"Since February 7, 2022, a first-time Idaho CDL applicant must complete Entry-Level Driver Training (ELDT) provided by an entity listed where?","options":["The Idaho State Police academy roster","The FMCSA Training Provider Registry (TPR)","The Idaho Transportation Department school list","Any accredited community college"],"answer":1,"explanation":"ELDT must be completed through a provider listed on the FMCSA Training Provider Registry before taking the skills test, effective Feb 7, 2022 (Idaho CDL Manual, ITD; 49 CFR 380 Subpart F).","handbook":"","hbref":""},{"q":"Which of the following does Idaho's adopted ELDT rule NOT require training for before testing?","options":["Obtaining a Class A CDL for the first time","Upgrading a Class B CDL to a Class A CDL","Renewing an existing CDL with no new endorsements","Obtaining a first-time HazMat (H) endorsement"],"answer":2,"explanation":"ELDT applies to first-time CDLs, Class B-to-A upgrades, and first-time P, S, or H endorsements; a straight renewal with no new privileges does not require ELDT (Idaho CDL Manual, ITD; 49 CFR 380).","handbook":"","hbref":""},{"q":"When self-certifying medical status in Idaho, a driver who operates only within Idaho but is exempt from state medical-card requirements selects which category?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":3,"explanation":"The four self-certification categories are NI, EI, NA, and EA; a driver operating exclusively intrastate and exempt from state medical certification selects Excepted Intrastate (EA) (Idaho CDL Manual, ITD; 49 CFR 383.71).","handbook":"","hbref":""},{"q":"An Idaho CDL applicant who will drive across state lines and is subject to the DOT physical requirement must self-certify in which category?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":0,"explanation":"A driver in interstate commerce subject to 49 CFR Part 391 selects Non-Excepted Interstate (NI) and must keep a valid medical examiner's certificate on file (Idaho CDL Manual, ITD; 49 CFR 383.71).","handbook":"","hbref":""},{"q":"Idaho offers a special restricted CDL valid only twice in a lifetime for farm-related service work within 150 miles. What is it called?","options":["A Provisional CDL","A Seasonal (restricted) CDL","An Apprentice CDL","A Limited Hardship CDL"],"answer":1,"explanation":"Idaho's Seasonal restricted CDL serves farm-related service industries, is valid up to 180 days in a 12-month period within 150 miles, and may be obtained only twice in a lifetime (ITD DMV CDL requirements; Idaho Code Title 49).","handbook":"","hbref":""},{"q":"While operating a commercial motor vehicle in Idaho, a CDL driver is considered legally over the limit and subject to disqualification at what blood alcohol concentration (BAC)?","options":["0.04 or more","0.08 or more","0.02 or more","0.10 or more"],"answer":0,"explanation":"Idaho sets the BAC limit for operating a commercial motor vehicle at 0.04 or more (half the 0.08 limit for non-commercial drivers). Source: Idaho Code 49-335; Idaho CDL Manual (ITD).","handbook":"","hbref":""},{"q":"In Idaho, a CDL holder convicted of a first major offense such as DUI while driving a non-placarded CMV is disqualified for at least how long?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"A first major offense (DUI, refusal, leaving the scene, using a CMV in a felony, etc.) carries a minimum 1-year CDL disqualification in Idaho. Source: Idaho Code 49-335; Idaho CDL Manual.","handbook":"","hbref":""},{"q":"If an Idaho CDL driver commits a first major offense (such as DUI) while the CMV is transporting hazardous materials required to be placarded, the minimum disqualification increases to:","options":["3 years","1 year","2 years","5 years"],"answer":0,"explanation":"Idaho extends the first-major-offense disqualification from 1 year to a minimum of 3 years when the violation occurs while transporting placarded hazardous materials. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Idaho law, what is the disqualification period for a CDL holder convicted of a SECOND major offense (e.g., a second DUI) in a separate incident?","options":["Lifetime disqualification","10 years","5 years","3 years"],"answer":0,"explanation":"Two major offenses arising from separate incidents result in a lifetime CDL disqualification in Idaho (mirroring 49 CFR 383.51), though a 10-year reinstatement program may be available. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Idaho CDL driver who refuses to submit to an evidentiary test for alcohol or drugs under the implied-consent law faces a CDL disqualification of at least:","options":["1 year","90 days","6 months","30 days"],"answer":0,"explanation":"Refusing the required BAC/drug test is treated as a major offense in Idaho, carrying the same minimum 1-year CDL disqualification as a DUI conviction (3 years if placarded hazmat). Source: Idaho Code 49-335 and 18-8002 (implied consent).","handbook":"","hbref":""},{"q":"By driving on Idaho roads, a person operating a motor vehicle is deemed to have given consent to evidentiary alcohol/drug testing. This principle is known as:","options":["Implied consent","Probable cause","Due process","Administrative review"],"answer":0,"explanation":"Idaho's implied-consent law (Idaho Code 18-8002) deems any driver to have consented to evidentiary testing; refusal triggers CDL disqualification and license suspension. Source: Idaho Code 18-8002; Idaho CDL Manual.","handbook":"","hbref":""},{"q":"In Idaho, being convicted of TWO serious traffic violations in separate incidents within a 3-year period while driving a CMV results in a CDL disqualification of:","options":["60 days","30 days","120 days","90 days"],"answer":0,"explanation":"Two serious traffic violations within 3 years disqualify the driver for at least 60 days in Idaho. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Idaho CDL driver convicted of THREE serious traffic violations in separate incidents within a 3-year period is disqualified for:","options":["120 days","60 days","1 year","180 days"],"answer":0,"explanation":"A third serious traffic violation within 3 years raises the disqualification to at least 120 days in Idaho. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for an Idaho CDL holder?","options":["Speeding 15 or more mph over the posted limit","Speeding 5 mph over the posted limit","A parking violation","An expired registration sticker"],"answer":0,"explanation":"Excessive speeding, defined as 15 mph or more over the posted limit, is a serious traffic violation in Idaho. Two or three within 3 years trigger 60/120-day disqualifications. Source: Idaho Code 49-335; Idaho CDL Manual.","handbook":"","hbref":""},{"q":"Which violation below is also counted as a SERIOUS traffic violation that can lead to CDL disqualification in Idaho?","options":["Following too closely (tailgating)","Driving 3 mph under the limit","Failing to signal a turn at an empty intersection","A broken taillight"],"answer":0,"explanation":"Following too closely is on Idaho's serious-traffic-violation list, along with reckless driving, improper or erratic lane changes, and excessive speeding. Source: Idaho Code 49-335; Idaho CDL Manual.","handbook":"","hbref":""},{"q":"Texting while driving a CMV and driving a CMV without obtaining the proper CDL are both categorized by Idaho/FMCSA rules as:","options":["Serious traffic violations","Major offenses","Out-of-service violations","Railroad-crossing violations"],"answer":0,"explanation":"Texting while driving a CMV and operating a CMV without the proper CDL/class are serious traffic violations (not major offenses), counting toward the 60/120-day disqualification thresholds. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a FIRST railroad-highway grade crossing violation committed while driving a CMV, an Idaho CDL driver is disqualified for:","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad grade crossing violation carries a minimum 60-day CDL disqualification in Idaho. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Idaho CDL driver convicted of a SECOND railroad-highway grade crossing violation within a 3-year period is disqualified for:","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"A second railroad grade crossing violation within 3 years results in a minimum 120-day disqualification in Idaho. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the disqualification period for a THIRD or subsequent railroad-highway grade crossing violation within a 3-year period in Idaho?","options":["1 year","120 days","180 days","60 days"],"answer":0,"explanation":"A third or subsequent railroad grade crossing violation within 3 years disqualifies the Idaho CDL driver for at least 1 year. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"An Idaho CDL driver convicted of a FIRST violation of an out-of-service (OOS) order while driving a non-hazmat, non-passenger CMV is disqualified for at least:","options":["180 days","60 days","90 days","30 days"],"answer":0,"explanation":"A first out-of-service order violation carries a minimum 180-day disqualification (up to 1 year) in Idaho. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Idaho, a SECOND out-of-service order violation in separate incidents within a 10-year period results in a disqualification of:","options":["2 to 5 years","180 days to 1 year","1 year","3 to 5 years"],"answer":0,"explanation":"A second OOS-order violation within 10 years disqualifies the driver for not less than 2 years and not more than 5 years in Idaho. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If an Idaho CDL driver's FIRST out-of-service order violation occurs while transporting placarded hazardous materials or carrying 16 or more passengers, the minimum disqualification is:","options":["180 days, up to 2 years","60 days, up to 1 year","30 days, up to 6 months","1 year, up to 3 years"],"answer":0,"explanation":"When a first OOS violation involves placarded hazmat or 16+ passengers, the disqualification is not less than 180 days and not more than 2 years. Source: Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Besides driver disqualification, an Idaho CDL driver who violates an out-of-service order is subject to a federal civil penalty of at least:","options":["$2,500 for a first conviction","$1,000 for a first conviction","$500 for a first conviction","$5,000 for a first conviction"],"answer":0,"explanation":"An out-of-service order violation carries a civil penalty of not less than $2,500 for a first conviction (and not less than $5,000 for subsequent convictions), in addition to disqualification. Source: Idaho Code 49-335; 49 CFR 383.53.","handbook":"","hbref":""},{"q":"Under the rules that apply to Idaho CMV drivers, the maximum civil penalty a DRIVER can face for texting while operating a commercial motor vehicle is approximately:","options":["$2,750","$500","$11,000","$1,000"],"answer":0,"explanation":"A CMV driver who texts while driving can face a civil penalty of up to about $2,750, while an employer who allows/requires it can be fined up to about $11,000. Two convictions in 3 years also bring a 60-day disqualification. Source: FMCSA No-Texting Rule (49 CFR 392.80); Idaho CDL Manual.","handbook":"","hbref":""},{"q":"A CDL driver in Idaho who uses a hand-held mobile telephone while driving a CMV and accumulates two such convictions in separate incidents within 3 years faces a disqualification of:","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Using a hand-held phone while driving a CMV is a serious traffic violation; two convictions within 3 years bring a 60-day disqualification (120 days for three). Source: FMCSA mobile phone rule (49 CFR 392.82); Idaho Code 49-335; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under the Idaho CDL manual's railroad-crossing rules, a driver of a placarded HazMat vehicle or a bus carrying passengers must stop how far from the nearest rail?","options":["Within 50 feet but not less than 15 feet","Within 100 feet but not less than 50 feet","Within 25 feet but not less than 5 feet","Within 75 feet but not less than 25 feet"],"answer":0,"explanation":"Idaho follows the federal standard (49 CFR 392.10) adopted in the Idaho CDL Manual: buses carrying passengers and placarded HazMat vehicles must stop within 50 feet but not less than 15 feet from the nearest rail. Idaho Code 49-648/49-650 use the identical 15-to-50-foot stopping band. Source: Idaho CDL Manual (ITD); Idaho Code 49-648.","handbook":"","hbref":""},{"q":"When an Idaho bus or placarded vehicle is required to stop at a railroad crossing, which action must the driver perform while any part of the vehicle is on the tracks?","options":["Not change gears while crossing","Sound the horn continuously","Shift into the lowest gear midway across","Switch off the four-way flashers"],"answer":0,"explanation":"Idaho's CDL manual (mirroring 49 CFR 392.10) directs that the driver pick a gear that will pull the unit completely across without shifting, and not change gears while any part of the vehicle is on the crossing. Source: Idaho CDL Manual (ITD); Idaho Code 49-649.","handbook":"","hbref":""},{"q":"Before crossing the tracks at a required stop, the Idaho CDL manual says a bus or placarded-HazMat driver must use which warning equipment as the vehicle approaches the crossing?","options":["Activate the four-way (hazard) flashers","Place three reflective triangles","Sound a long blast on the air horn","Turn on the high-beam headlights"],"answer":0,"explanation":"Idaho's CDL manual instructs drivers required to stop at railroad crossings to turn on the four-way emergency flashers when approaching and stopping, to warn following traffic. Source: Idaho CDL Manual (ITD), railroad-crossing section.","handbook":"","hbref":""},{"q":"Under Idaho's 'Move Over' law (Idaho Code 49-624), when you approach a stopped police, emergency, tow, or highway incident-response vehicle that is displaying flashing lights on a highway with two or more lanes in your direction, you must:","options":["Reduce speed below the posted limit and, if in the adjacent lane, change into a non-adjacent lane when possible","Maintain the posted speed but sound your horn","Stop completely until the emergency vehicle moves","Change lanes only if directed by an officer"],"answer":0,"explanation":"Idaho Code 49-624 requires drivers to slow below the posted speed limit and, on a multi-lane highway, vacate the lane adjacent to the stationary emergency/tow/incident-response vehicle (with flashing lights) by moving to a non-adjacent lane as soon as it is reasonably possible. Source: Idaho Code 49-624.","handbook":"","hbref":""},{"q":"Idaho's Move Over law (49-624) applies to stationary vehicles displaying flashing lights. Which of the following is NOT a vehicle type specifically protected by the statute?","options":["A private passenger car stopped for a flat tire","A tow truck","A highway incident-response vehicle","An authorized emergency vehicle"],"answer":0,"explanation":"Idaho Code 49-624 protects stationary police vehicles, authorized emergency vehicles, tow trucks, and highway incident-response vehicles that are displaying flashing lights. An ordinary private passenger car is not named in the Move Over statute. Source: Idaho Code 49-624.","handbook":"","hbref":""},{"q":"On a two-lane highway with only one lane in each direction, Idaho's Move Over law requires a driver passing a stationary emergency vehicle with flashing lights to:","options":["Reduce speed below the posted limit and maintain a safe speed until completely past the vehicle","Come to a full stop and wait","Cross the centerline into oncoming lanes to give room","Continue at the posted speed without slowing"],"answer":0,"explanation":"Where moving over is impossible (one lane each direction), Idaho Code 49-624 requires the driver to reduce speed below the posted limit and proceed with caution at a safe speed until completely past the stationary vehicle. Source: Idaho Code 49-624.","handbook":"","hbref":""},{"q":"Under Idaho Code 49-1422, the driver of a vehicle meeting an oncoming stopped school bus with its red visual signals actuated is NOT required to stop only when the highway has:","options":["More than three lanes","More than two lanes","A painted center turn lane","Any divided median of any width"],"answer":0,"explanation":"Idaho Code 49-1422 states that oncoming traffic on a highway of more than three (3) lanes is not required to stop when meeting a school bus with signals actuated. Idaho ties the exception to lane count (>3 lanes), not merely to a median. Source: Idaho Code 49-1422.","handbook":"","hbref":""},{"q":"On a standard two-lane Idaho road, the driver of a vehicle that meets OR overtakes a school bus stopped with its red visual signals flashing must:","options":["Stop before reaching the bus and not proceed until the signals stop or the bus moves","Slow to 20 mph and pass with caution","Stop only if children are visible","Stop only if overtaking from behind, not if meeting it"],"answer":0,"explanation":"Idaho Code 49-1422 requires a driver meeting or overtaking from either direction to stop before reaching a school bus displaying the visual signals of 49-915, and not to proceed until the bus resumes motion or the signals are no longer actuated (except the >3-lane oncoming exception). Source: Idaho Code 49-1422.","handbook":"","hbref":""},{"q":"Until July 1, 2026, under Idaho Code 49-654, a five-or-more-axle truck over 26,000 lbs is limited on interstate highways in NONURBAN areas to a maximum speed of:","options":["10 mph less than the limit for lighter vehicles","Exactly 65 mph everywhere","5 mph less than the limit for lighter vehicles","The same speed as passenger cars"],"answer":0,"explanation":"Under the version of Idaho Code 49-654 in effect through June 30, 2026, heavy trucks (5+ axles, over 26,000 lbs) may not exceed 10 mph less than lighter vehicles on nonurban interstates. House Bill 664 equalizes these limits effective July 1, 2026. Source: Idaho Code 49-654; HB664 (2026).","handbook":"","hbref":""},{"q":"Effective July 1, 2026, Idaho House Bill 664 changes the speed rule for heavy trucks (5+ axles, over 26,000 lbs) so that on interstates, state highways, and other locations their maximum lawful speed will be:","options":["The same as for vehicles under five axles and 26,000 lbs or less","Still 10 mph less than passenger cars on nonurban interstates","Capped at 70 mph statewide regardless of the posted limit","Capped at 65 mph in all urban areas only"],"answer":0,"explanation":"HB664 amends Idaho Code 49-654 so that, effective July 1, 2026, heavy trucks are subject to the same posted maximum speed limits as lighter vehicles, eliminating the prior 10-mph-less and 65-mph-urban truck caps. Source: Idaho HB664 (2026); Idaho Code 49-654.","handbook":"","hbref":""},{"q":"Under Idaho Code 49-654, the maximum speed limit that may be posted on Idaho interstate highways (for lighter vehicles, following an engineering study) is:","options":["80 mph","75 mph","70 mph","85 mph"],"answer":0,"explanation":"Idaho Code 49-654 sets a baseline of 75 mph on interstates but authorizes ITD to raise the limit up to 80 mph on interstate highways after an engineering and traffic study; 80 mph is posted on many rural Idaho interstate segments. Source: Idaho Code 49-654; ITD.","handbook":"","hbref":""},{"q":"Under Idaho Code 49-654, in the absence of a posted limit, the default maximum speed in any residential, business, or urban district is:","options":["35 mph","25 mph","30 mph","20 mph"],"answer":0,"explanation":"Idaho Code 49-654 sets the default maximum at 35 mph in any residential, business, or urban district unless otherwise posted. Source: Idaho Code 49-654.","handbook":"","hbref":""},{"q":"Idaho Code 49-630 governs lane use on Idaho highways. A vehicle moving slower than the normal flow of traffic, such as a loaded truck climbing a grade, must:","options":["Drive in the right-hand lane or as close as practicable to the right edge","Use the center lane to balance traffic","Stay in the left lane to keep the right lane clear for merging","Pick any lane as long as it signals"],"answer":0,"explanation":"Idaho Code 49-630 requires any vehicle proceeding at less than the normal speed of traffic to be driven in the right-hand lane available, or as close as practicable to the right curb/edge, except when passing or preparing to turn left. Source: Idaho Code 49-630.","handbook":"","hbref":""},{"q":"On a divided or one-way road, the Idaho CDL manual directs a stopped commercial vehicle to place its three emergency warning devices at which distances toward approaching traffic?","options":["10 feet, 100 feet, and 200 feet toward the approaching traffic","10 feet, 50 feet, and 100 feet toward the approaching traffic","15 feet, 100 feet, and 300 feet toward the approaching traffic","25 feet, 100 feet, and 500 feet toward the approaching traffic"],"answer":0,"explanation":"On a one-way or divided highway, the Idaho CDL manual (per 49 CFR 392.22) requires warning devices at 10 feet, 100 feet, and 200 feet from the vehicle toward the approaching traffic. Source: Idaho CDL Manual (ITD).","handbook":"","hbref":""},{"q":"On a two-lane, two-way Idaho road, where does the Idaho CDL manual say to place the three required warning devices for a stopped CMV?","options":["Within 10 feet of the vehicle, and 100 feet behind and 100 feet ahead of it","All three within 10 feet of the rear of the vehicle","At 50 feet, 200 feet, and 500 feet behind only","100 feet, 200 feet, and 300 feet behind the vehicle"],"answer":0,"explanation":"On a two-lane, two-way road the Idaho CDL manual (per 49 CFR 392.22) requires one device within 10 feet of the vehicle on the traffic side, one about 100 feet behind, and one about 100 feet ahead, on the shoulder or in the lane of stoppage. Source: Idaho CDL Manual (ITD).","handbook":"","hbref":""},{"q":"If a CMV is stopped on an Idaho two-lane road within 500 feet of a hill, curve, or other obstruction, the Idaho CDL manual says to:","options":["Move the rear warning device back to between 100 and 500 feet to give drivers more warning","Leave all three triangles at the standard 10/100/100-foot spots","Stack all three devices directly behind the vehicle","Remove the triangles and rely only on flashers"],"answer":0,"explanation":"When stopped within 500 feet of a hill, curve, or obstruction that limits sight distance, the Idaho CDL manual (per 49 CFR 392.22) directs moving the rear-most warning device back down the road to a point 100 to 500 feet from the vehicle so approaching drivers get adequate warning. Source: Idaho CDL Manual (ITD).","handbook":"","hbref":""},{"q":"The Idaho CDL manual requires a stopped CMV to display its warning devices (flares or triangles) within what time after stopping on a highway?","options":["10 minutes","5 minutes","15 minutes","30 minutes"],"answer":0,"explanation":"The Idaho CDL manual (per 49 CFR 392.22) requires emergency warning devices to be placed within 10 minutes of stopping on the traveled portion or shoulder of a highway. Source: Idaho CDL Manual (ITD).","handbook":"","hbref":""},{"q":"US-95 grades such as the Lewiston Grade and White Bird Grade are notable in Idaho for steep mountain descents. What safety feature do these grades provide for trucks that lose braking ability?","options":["Emergency escape (runaway-truck) ramps","Mandatory toll booths for heavy trucks","A statewide truck-route ban detouring around them","Electronic speed governors built into the road"],"answer":0,"explanation":"Idaho's steep US-95 mountain grades (Lewiston Grade, White Bird Grade) are equipped with emergency escape/runaway-truck ramps that use long gravel beds to stop a vehicle that has lost its brakes. ITD posts advance signage for these descents. Source: Idaho Transportation Department (ITD), US-95 escape-ramp projects.","handbook":"","hbref":""},{"q":"Idaho has no toll roads or toll-financed interstate bridges on its state highway system. For a CDL driver planning a route across Idaho, this means:","options":["No tolls are charged on Idaho's interstates or state highways","Tolls are charged only on interstate bridges over the Snake River","Heavy trucks pay a per-mile toll on I-84","Tolls apply only in the Boise metro bypass"],"answer":0,"explanation":"Idaho operates no toll roads or toll bridges on its public highway system; interstates and state highways are toll-free. CDL drivers should instead plan around oversize/overweight permit and restricted-route requirements administered by ITD, not tolls. Source: Idaho Transportation Department (ITD).","handbook":"","hbref":""},{"q":"Which agency is the State Driver Licensing Agency responsible for issuing Commercial Driver's Licenses in Idaho?","options":["The Idaho Transportation Department (ITD)","The Idaho State Police Commercial Vehicle Services","The Federal Motor Carrier Safety Administration","The Idaho Department of Motor Vehicle Safety"],"answer":0,"explanation":"The Idaho Transportation Department (ITD) DMV is Idaho's State Driver Licensing Agency and issues CDLs. Source: ITD DMV Commercial Driver's License (CDL) page; ITD 'Ten Steps to Getting an Idaho CDL.'","handbook":"","hbref":""},{"q":"In Idaho, where does a CDL applicant actually go to apply, take written tests, and have the license issued?","options":["A privately run ITD testing franchise","A county sheriff's driver's licensing (DMV) office","An FMCSA field office","The ITD headquarters in Boise only"],"answer":1,"explanation":"Idaho driver licensing is county-administered: applicants go to a county sheriff's driver's licensing office, which handles the CDL application, knowledge tests, and issuance while ITD processes records. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 4.","handbook":"","hbref":""},{"q":"Before being licensed, every new Idaho CDL applicant must first obtain which credential to practice and to take the skills test?","options":["A Commercial Learner's Permit (CLP)","A Class D instruction permit","A federal interstate authority card","A provisional commercial endorsement"],"answer":0,"explanation":"Idaho requires applicants to obtain a Commercial Learner's Permit (CLP) to obtain or upgrade a commercial license and to practice on public roads before the skills test. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 5.","handbook":"","hbref":""},{"q":"How long is an Idaho Commercial Learner's Permit (CLP) valid once issued?","options":["180 days","90 days","Two years","One year"],"answer":3,"explanation":"Idaho's CLP is valid for one year (Idaho's term differs from the 180-day minimum used by some states). Source: ITD 'Ten Easy Steps to a C.D.L.' Step 5.","handbook":"","hbref":""},{"q":"Under federal rules applied in Idaho, how long must an applicant hold a CLP before being allowed to take the CDL skills test?","options":["At least 30 days","At least 10 days","At least 14 days","At least 60 days"],"answer":2,"explanation":"FMCSA rules adopted by Idaho require holding the CLP for a minimum of 14 days before taking a skills test, even when only upgrading an existing CDL. Source: ITD 'Ten Easy Steps to a C.D.L.' Steps 5 and 9.","handbook":"","hbref":""},{"q":"The Idaho CDL skills test is made up of which three parts?","options":["Written test, eye exam, and road test","Air brake test, backing test, and weigh-station test","Pre-trip inspection, simulator test, and night driving","Pre-trip inspection, basic vehicle control, and on-road driving"],"answer":3,"explanation":"Idaho follows the FMCSA three-part skills test: pre-trip (vehicle) inspection, basic vehicle control (closed-course maneuvers), and the on-road driving test. Source: ITD CDL manual; ITD 'Ten Easy Steps to a C.D.L.' Steps 6-9.","handbook":"","hbref":""},{"q":"On test day in Idaho, how much time is an applicant given to complete the pre-trip vehicle inspection?","options":["45 minutes","15 minutes","60 minutes","30 minutes"],"answer":0,"explanation":"Idaho allows 45 minutes to complete the pre-trip inspection portion on test day; an improper brake check is a common cause of failure. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 6.","handbook":"","hbref":""},{"q":"In the Idaho basic-control (backing) portion, which two maneuvers are required of all applicants?","options":["Alley dock and parallel park","Straight line back and alley dock","Straight line back and offset back","Parallel park and serpentine"],"answer":2,"explanation":"Idaho requires the straight line back and offset back of every applicant; the examiner then selects either the alley dock or the parallel park. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 7 (Chapter 12 maneuvers).","handbook":"","hbref":""},{"q":"Which training must an Idaho CDL applicant complete from a registered provider before being eligible to take the skills test?","options":["A state-approved defensive driving course","An ITD safety orientation seminar","An OSHA commercial vehicle course","Entry-Level Driver Training (ELDT)"],"answer":3,"explanation":"Since February 7, 2022, applicants must complete Entry-Level Driver Training (ELDT) from a provider on FMCSA's Training Provider Registry before taking required skills tests. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 5; FMCSA ELDT rule.","handbook":"","hbref":""},{"q":"In Idaho's CDL self-certification, how many driving categories must an applicant choose from?","options":["Two","Three","Five","Four"],"answer":3,"explanation":"Idaho CDL holders must self-certify to one of four categories: interstate non-excepted, interstate excepted, intrastate non-excepted, or intrastate excepted. Source: ITD 'Medical Cards & Self Certification Categories' chart; FMCSA 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which self-certification category is described by Idaho as the medical-card-required 'gold standard' for most CDL drivers, allowing driving across state lines?","options":["Interstate excepted","Intrastate non-excepted","Interstate non-excepted","Intrastate excepted"],"answer":2,"explanation":"Idaho labels interstate non-excepted the 'gold standard': the driver is medically certified and may cross state lines and haul anything. Source: ITD 'Medical Cards & Self Certification Categories' chart.","handbook":"","hbref":""},{"q":"Which Idaho self-certification category requires a valid DOT medical certificate even though all driving stays within Idaho?","options":["Intrastate excepted","Intrastate non-excepted","Interstate excepted","Non-CDL excepted"],"answer":1,"explanation":"Intrastate non-excepted drivers stay within Idaho but are still medically certified (e.g., hauling non-exempt commodities), and this adds a 'K' (intrastate-only) restriction. Source: ITD 'Medical Cards & Self Certification Categories' chart.","handbook":"","hbref":""},{"q":"Which restriction does Idaho add to a CDL when a driver self-certifies to an intrastate category?","options":["An 'L' restriction (no air brakes)","A 'K' restriction (intrastate operation only)","An 'E' restriction (automatic transmission only)","An 'O' restriction (no fifth-wheel)"],"answer":1,"explanation":"Self-certifying to either intrastate category (excepted or non-excepted) adds a 'K' restriction limiting the driver to intrastate operation. Source: ITD 'Medical Cards & Self Certification Categories' chart; 49 CFR 383.95.","handbook":"","hbref":""},{"q":"A non-excepted Idaho CDL holder obtains a new DOT medical examiner's certificate. What must they do with it?","options":["Submit a copy to the county DMV/ITD so it is added to the driving record","Keep it only in the truck for roadside inspections","Mail the original to FMCSA in Washington, D.C.","File it with their employer instead of the state"],"answer":0,"explanation":"Non-excepted CDL holders must submit (provide) a copy of the ME certificate to the county DMV/ITD when obtained and at each renewal so it is posted to the driving record. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 4.","handbook":"","hbref":""},{"q":"A DOT medical examiner's certificate used for an Idaho CDL may be issued for a maximum of how long?","options":["Up to 12 months","Up to 36 months","Up to 24 months","Up to 48 months"],"answer":2,"explanation":"A DOT physical/medical examiner's certificate is valid for up to 24 months; an examiner may issue it for less time to monitor a medical condition. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 2.","handbook":"","hbref":""},{"q":"The medical provider who performs the DOT physical for an Idaho CDL applicant must be listed where?","options":["On the Idaho Board of Medicine CDL panel","On the National Registry of Certified Medical Examiners","On the ITD list of approved physicians","On the FMCSA carrier safety roster"],"answer":1,"explanation":"The examining provider must be listed on FMCSA's National Registry of Certified Medical Examiners; using an unregistered provider can lead to a CDL downgrade. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 2; ITD medical certificate notice.","handbook":"","hbref":""},{"q":"How long do an Idaho applicant's passed CDL knowledge (written) test results remain valid before all written tests must be retaken?","options":["One year from the date passed","Six months from the date passed","Two years from the date passed","90 days from the date passed"],"answer":0,"explanation":"Knowledge test results stay valid for one year from the date passed; if the CDL is not obtained within that year, all written tests must be retaken. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 4.","handbook":"","hbref":""},{"q":"If an Idaho applicant fails a CDL knowledge (written) test, how soon may they retake it?","options":["The same day","After three days","After seven days","After fourteen days"],"answer":1,"explanation":"An applicant who fails a written test may re-test after three days (and pay the per-test fee again). Source: ITD 'Ten Easy Steps to a C.D.L.' Step 4.","handbook":"","hbref":""},{"q":"After passing the skills test, what is the validity period of a standard newly issued Idaho CDL?","options":["Two years only","One year only","Four years (with an eight-year option also available)","Six years fixed"],"answer":2,"explanation":"Idaho issues the CDL for four years; ITD also offers an eight-year option. The driver must return to the county DMV to have the license issued after passing. Source: ITD 'Ten Steps to Getting an Idaho CDL' Step 10.","handbook":"","hbref":""},{"q":"Idaho's CDL skills test fee charged by the examiner is governed how under Idaho Code?","options":["It is a flat federally fixed amount in every state","It is waived for all first-time applicants","It is set solely by the applicant's training school","It is capped and may not exceed a maximum set by Idaho Code per test"],"answer":3,"explanation":"The examiner-set skills test fee is capped by Idaho Code (not to exceed the statutory maximum per test), separate from the small county portion. Exact dollar amounts can change. Source: ITD 'Ten Easy Steps to a C.D.L.' Step 9.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина транспортного средства, включая груз, на автодорогах штата Айдахо?","options":["8 футов 6 дюймов","8 футов 0 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Idaho Code 49-1010 ограничивает общую ширину любого транспортного средства, включая его груз, до 8 футов 6 дюймов (102 inches). Для более широких грузов требуется разрешение на негабаритный груз. Источник: Idaho Code 49-1010 (Size of Vehicles and Loads)."},"1":{"q":"Какова максимальная разрешённая высота транспортного средства и его груза на автодорогах штата Айдахо?","options":["13 футов 6 дюймов","14 футов","15 футов","13 футов"],"explanation":"Idaho Code 49-1010 устанавливает максимальную высоту транспортного средства, включая груз, в 14 футов. Для грузов выше 14 футов требуется разрешение на превышение высоты. Источник: Idaho Code 49-1010."},"2":{"q":"Каков максимальный полный вес на одну ось в штате Айдахо?","options":["18,000 фунтов","22,400 фунтов","20,000 фунтов","21,500 фунтов"],"explanation":"Idaho Code 49-1001 устанавливает максимальный полный вес на одиночную ось в 20,000 фунтов. Источник: Idaho Code 49-1001 (Allowable Gross Loads)."},"3":{"q":"Каков максимальный полный вес, допустимый на сдвоенную ось (тандем) в штате Айдахо?","options":["34,000 фунтов","36,000 фунтов","32,000 фунтов","40,000 фунтов"],"explanation":"Согласно Idaho Code 49-1001, комплект сдвоенных осей (тандем) может нести до 34,000 фунтов, что соответствует федеральному стандарту. Источник: Idaho Code 49-1001."},"4":{"q":"Каков максимальный полный вес транспортного средства или автопоезда, допустимый без разрешения на участке федеральной системы межштатных и оборонных автомагистралей США, проходящем по территории Айдахо?","options":["80,000 фунтов","105,500 фунтов","90,000 фунтов","129,000 фунтов"],"explanation":"Idaho Code 49-1001 ограничивает полный вес транспортного средства или автопоезда на федеральных межштатных и оборонных автомагистралях до 80,000 фунтов, в соответствии с федеральным законом. Источник: Idaho Code 49-1001."},"5":{"q":"Каков максимальный полный вес транспортного средства или автопоезда, допустимый на обычных (не межштатных) автодорогах штата Айдахо согласно базовому закону, прежде чем потребуется специальное разрешение на превышение веса?","options":["80,000 фунтов","129,000 фунтов","100,000 фунтов","105,500 фунтов"],"explanation":"Idaho Code 49-1001 разрешает максимальный полный вес транспортного средства или автопоезда в 105,500 фунтов, за исключением того, что на федеральных межштатных и оборонных автомагистралях предел снижается до 80,000 фунтов. Источник: Idaho Code 49-1001."},"6":{"q":"Каков максимальный полный вес, допустимый на одно колесо в штате Айдахо?","options":["8,000 фунтов","12,000 фунтов","10,000 фунтов","6,000 фунтов"],"explanation":"Idaho Code 49-1001 устанавливает максимальный полный вес на одно колесо в 10,000 фунтов. Источник: Idaho Code 49-1001."},"7":{"q":"В Айдахо используется федеральная мостовая формула веса для определения максимального веса, допустимого на группу последовательных осей. Какую формулу принимает Idaho Code?","options":["W = 500((LN/N-1) + 12N + 36)","W = 1000(L + N + 20)","W = 34,000 + (N x 12)","W = 250(LN + 12 + 36N)"],"explanation":"Idaho Code 49-1001(1) принимает федеральную мостовую формулу W = 500((LN/N-1) + 12N + 36), где W — максимальный вес, L — расстояние в футах между крайними осями группы, а N — количество осей. Источник: Idaho Code 49-1001(1)."},"8":{"q":"Что обозначает переменная «L» в мостовой формуле штата Айдахо?","options":["Допустимую нагрузочную способность прицепа","Расстояние в футах между крайними осями группы из двух или более последовательных осей","Длину только самой длинной одиночной группы осей","Зарегистрированный полный вес транспортного средства"],"explanation":"В формуле W = 500((LN/N-1) + 12N + 36) «L» — это расстояние в футах между крайними осями любой группы из двух или более последовательных осей, «N» — количество осей, а «W» — максимальный вес. Источник: Idaho Code 49-1001(1)."},"9":{"q":"Два последовательных комплекта сдвоенных осей могут нести по 34,000 фунтов каждый в штате Айдахо только при условии, что общее расстояние между первой и последней осями этих тандемных комплектов составляет не менее скольких футов?","options":["30 футов","36 футов","40 футов","34 фута"],"explanation":"Idaho Code 49-1001(1)(b) разрешает двум последовательным тандемным комплектам нести по 34,000 фунтов каждый при условии, что расстояние между первой и последней осями этих комплектов составляет 36 футов или более. Источник: Idaho Code 49-1001(1)(b)."},"10":{"q":"Полуприцеп, эксплуатируемый на маршрутах, входящих в национальную сеть автодорог в штате Айдахо, не может превышать какую длину?","options":["48 футов","53 фута","57 футов","45 футов"],"explanation":"Idaho Code 49-1010 ограничивает полуприцеп, эксплуатируемый в национальной сети (и на связанных подъездных маршрутах), длиной 53 фута. Источник: Idaho Code 49-1010."},"11":{"q":"Согласно Idaho Code, груз на транспортном средстве, как правило, не может выступать за переднюю часть транспортного средства более чем на сколько футов?","options":["3 фута","4 фута","6 футов","2 фута"],"explanation":"Idaho Code 49-1010 запрещает грузу выступать за переднюю часть транспортного средства более чем на 4 фута. Источник: Idaho Code 49-1010."},"12":{"q":"Автопоезд, перевозящий делимый груз, может эксплуатироваться с полным весом выше 105,500 фунтов в штате Айдахо, но не превышающим какой вес, и только на специально обозначенных не межштатных маршрутах при наличии надлежащей регистрации и разрешения?","options":["129,000 фунтов","117,000 фунтов","140,000 фунтов","125,500 фунтов"],"explanation":"Idaho Code 49-1001(1)(c) разрешает делимые грузы свыше 105,500 фунтов, но не превышающие 129,000 фунтов, на не межштатных автодорогах, если транспортное средство зарегистрировано, соответствует весовой формуле и ограничениям по длине и эксплуатируется на обозначенных маршрутах согласно Idaho Code 49-1004. Источник: Idaho Code 49-1001(1)(c) и 49-1004."},"13":{"q":"Кто выдаёт специальное годовое разрешение на маршрут, дающее зарегистрированному автопоезду право перевозить делимые грузы от 105,501 до 129,000 фунтов в штате Айдахо?","options":["Шериф каждого округа на маршруте","Federal Highway Administration","Idaho Transportation Department или, по его усмотрению, местное государственное дорожное агентство","Любая весовая станция на коммерческой стоянке грузовиков"],"explanation":"Idaho Code 49-1004 предусматривает, что специальные разрешения на маршрут для грузов от 105,501 до 129,000 фунтов выдаются Idaho Transportation Department или, по его усмотрению, местным государственным дорожным агентством на маршрутах, обозначенных департаментом или местными органами. Источник: Idaho Code 49-1004."},"14":{"q":"Что, как правило, требуется, прежде чем транспортное средство, превышающее установленные в Айдахо предельные значения размеров или веса, сможет двигаться по автодороге?","options":["Действующее разрешение на негабаритный/перевесный груз, полученное до начала движения","Замена на CDL класса A","Федеральное освобождение от FMCSA","Только устное согласие сотрудника пункта въезда"],"explanation":"Idaho Code 49-1004 и правила выдачи разрешений ITD требуют наличия разрешения на негабаритный и/или перевесный груз, полученного до начала движения, для эксплуатации транспортного средства, превышающего установленные пределы размеров или веса; разрешение должно находиться в транспортном средстве. Источник: Idaho Code 49-1004; правила выдачи разрешений ITD (IDAPA 39.03.03)."},"15":{"q":"Закон Айдахо предоставляет весовую льготу (отдельную, более щедрую таблицу межосевых расстояний) на не межштатных автодорогах транспортным средствам, перевозящим определённые виды грузов. Какая группа грузов охватывается этой льготой?","options":["Брёвна, балансовая древесина, необработанный пиломатериал, столбы, руда, песок и гравий, а также сельскохозяйственные товары, включая скот","Охлаждённые продукты и бутилированные напитки","Новые легковые автомобили и дома на колёсах","Только опасные материалы и наливное топливо"],"explanation":"Idaho Code 49-1001(2) предусматривает специальную таблицу допустимых нагрузок для транспортных средств, перевозящих брёвна, балансовую древесину, кряжи, необработанный пиломатериал, столбы или сваи; руду, концентраты, песок и гравий, а также заполнители навалом; или сельскохозяйственные товары, включая скот. Источник: Idaho Code 49-1001(2)."},"16":{"q":"Специальные весовые льготы для брёвен, руды, песка/гравия и сельскохозяйственных товаров согласно Idaho Code 49-1001(2) НЕ применяются, как только общий полный вес, по заявлению оператора, должен превысить какое значение?","options":["80,000 фунтов","79,000 фунтов","105,500 фунтов","84,000 фунтов"],"explanation":"Idaho Code 49-1001(2) устанавливает, что весовые льготы для товаров не применяются, если общий полный вес, по заявлению оператора, должен превысить 79,000 фунтов. Источник: Idaho Code 49-1001(2)."},"17":{"q":"На пункте въезда в штат Айдахо гружёное транспортное средство не может проехать за весы, когда вес одной оси превышает максимальный предел на сколько?","options":["500 фунтов или более","1,000 фунтов или более","2,000 фунтов или более","5,000 фунтов или более"],"explanation":"Idaho Code 49-1001(8) предусматривает, что транспортное средство не может проехать за пункт въезда, когда одна ось превышает максимум на 2,000 фунтов или более, либо когда полный вес/вес группы осей превышает максимум на 7% или более. Источник: Idaho Code 49-1001(8)."},"18":{"q":"На пункте въезда в штат Айдахо при каком превышении максимально допустимого полного веса или веса группы осей транспортное средство будет остановлено и обязано привести себя в соответствие с нормами, прежде чем продолжить движение?","options":["7 процентов или более","5 процентов или более","10 процентов или более","15 процентов или более"],"explanation":"Idaho Code 49-1001(8) требует приведения транспортного средства в соответствие с нормами на весах, когда его полный вес или вес комбинации осей превышает максимально допустимый вес на 7 процентов или более (порог для одиночной оси составляет 2,000 фунтов). Источник: Idaho Code 49-1001(8)."},"19":{"q":"Айдахо требует сопровождения (машин сопровождения/прикрытия) для негабаритных по ширине грузов, перевозимых по разрешению. При какой ширине груза Айдахо, как правило, требует хотя бы одну машину сопровождения/прикрытия?","options":["Шире 8 футов 6 дюймов","Шире 10 футов","Шире 12 футов","Шире 16 футов"],"explanation":"Согласно правилам ITD о перевозке негабаритных грузов, груз шире 12 футов, как правило, требует одной машины сопровождения/прикрытия, а грузы шире 14 футов требуют двух. На углах негабаритных по ширине грузов обязательны флажки, а на машинах сопровождения обязательны знак OVERSIZE LOAD и жёлтые проблесковые маячки. Источник: правила выдачи разрешений ITD (IDAPA 39.03.05 / требования к машинам сопровождения)."},"20":{"q":"В штате Айдахо CDL требуется для управления любым одиночным транспортным средством с полной разрешённой массой (GVWR) от скольких фунтов и выше (при буксировке прицепа не тяжелее 10,000 lbs)?","options":["16,001 фунтов","26,001 фунтов","33,001 фунтов","10,001 фунтов"],"explanation":"Айдахо принимает федеральный порог: CDL класса B требуется для любого одиночного транспортного средства с GVWR 26,001 lbs или более (Idaho CDL Manual, ITD; 49 CFR 383.91)."},"21":{"q":"Какой класс CDL в Айдахо требуется для управления составным транспортным средством с GCWR 26,001 lbs или более, где буксируемое звено (звенья) превышает GVWR 10,000 lbs?","options":["Класс C","Класс B","Класс A","Класс D"],"explanation":"CDL класса A охватывает составные транспортные средства с GCWR 26,001 lbs или более при условии, что GVWR буксируемого транспортного средства (средств) превышает 10,000 lbs (Idaho CDL Manual, ITD)."},"22":{"q":"Согласно правилам Айдахо, транспортное средство, рассчитанное на перевозку 16 или более пассажиров (включая водителя), но не достигающее весовых пределов классов A/B, требует какого класса CDL?","options":["Класс C","Класс A","Класс B","CDL не требуется"],"explanation":"CDL класса C требуется для транспортных средств, которые не отвечают критериям класса A или B, но рассчитаны на перевозку 16 или более пассажиров, включая водителя, либо перевозят опасные материалы, требующие размещения информационных табличек (Idaho CDL Manual, ITD)."},"23":{"q":"Какую буквенную отметку Айдахо присваивает праву управления автоцистернами (танкерами), перевозящими жидкости или газы навалом/наливом?","options":["T","N","X","H"],"explanation":"Отметка N предназначена для автоцистерн. (T = сдвоенные/строенные прицепы, H = опасные материалы (HazMat), X = совмещённая отметка цистерны и опасных материалов.) Источник: Idaho CDL Manual, ITD; 49 CFR 383.93."},"24":{"q":"В штате Айдахо отметка «T» даёт владельцу право управлять каким типом транспортного средства?","options":["Автоцистернами","Транспортными средствами, перевозящими опасные материалы","Сдвоенными и строенными прицепами","Транспортными средствами, перевозящими 16+ пассажиров"],"explanation":"Отметка T охватывает сдвоенные и строенные прицепы и требует сдачи только теоретического экзамена (Idaho CDL Manual, ITD; 49 CFR 383.93)."},"25":{"q":"Чтобы получить в Айдахо отметку HazMat (H), заявитель должен сдать теоретический экзамен, а также выполнить какое дополнительное федеральное требование?","options":["Практический экзамен по вождению","Оценку угрозы безопасности TSA (проверку благонадёжности)","Подачу заявления на освобождение по зрению","Повторный медицинский осмотр"],"explanation":"Айдахо требует, чтобы заявитель на отметку H сдал теоретический экзамен и прошёл оценку угрозы безопасности TSA (проверку благонадёжности на основе отпечатков пальцев) согласно закону USA PATRIOT Act (Idaho CDL Manual, ITD; 49 CFR 1572)."},"26":{"q":"В штате Айдахо, прежде чем выдать отметку для школьного автобуса (S), какую другую отметку заявитель также должен иметь или получить?","options":["N (Цистерна)","T (Сдвоенные/строенные)","P (Пассажирская)","H (HazMat)"],"explanation":"Отметка S (школьный автобус) требует наличия отметки P (пассажирская), а также сдачи теоретического экзамена и практического экзамена на школьном автобусе (Idaho CDL Manual, ITD; 49 CFR 383.123)."},"27":{"q":"Какая отметка CDL в Айдахо требует как теоретического экзамена, так и практического экзамена по вождению на репрезентативном транспортном средстве?","options":["N (Цистерна)","P (Пассажирская)","T (Сдвоенные/строенные)","H (HazMat)"],"explanation":"Отметка P (пассажирская) требует сдачи теоретического экзамена и практического экзамена на пассажирском транспортном средстве; N, T и H — отметки, требующие только теоретического экзамена (Idaho CDL Manual, ITD; 49 CFR 383.93)."},"28":{"q":"Каков минимальный возраст для получения CDL в Айдахо для управления коммерческим транспортным средством только в пределах штата Айдахо (внутриштатные перевозки)?","options":["16 лет","18 лет","19 лет","21 год"],"explanation":"Айдахо разрешает выдачу внутриштатного CDL в возрасте 18 лет; заявитель также должен иметь действующее водительское удостоверение класса D штата Айдахо и один год стажа вождения с правами (Idaho CDL Manual, ITD; Idaho Code 49-305)."},"29":{"q":"Какой минимальный возраст требует Айдахо (следуя федеральному закону) для управления коммерческим транспортным средством с пересечением границ штатов (межштатные перевозки)?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Межштатные коммерческие перевозки требуют минимального возраста 21 год; владелец CDL штата Айдахо в возрасте 18 лет ограничен внутриштатными перевозками (Idaho CDL Manual, ITD; 49 CFR 391.11)."},"30":{"q":"Отметка HazMat (H) в Айдахо не может быть выдана заявителю, который младше какого возраста?","options":["18","19","21","25"],"explanation":"Поскольку перевозка опасных материалов по найму, как правило, связана с межштатной коммерцией и оценкой TSA, отметка H требует, чтобы заявителю было не менее 21 года (Idaho CDL Manual, ITD; 49 CFR 383/1572)."},"31":{"q":"Согласно федеральным правилам, принятым в Айдахо, как долго водитель должен владеть ученическим коммерческим разрешением (CLP), прежде чем получить право сдавать практический экзамен на CDL?","options":["Не менее 7 дней","Не менее 14 дней","Не менее 30 дней","Не менее 60 дней"],"explanation":"CLP должно находиться во владении не менее 14 дней, прежде чем можно будет сдавать практический экзамен (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"32":{"q":"В течение какого срока действует ученическое коммерческое разрешение (CLP) штата Айдахо, прежде чем его необходимо будет продлить?","options":["90 дней","180 дней","1 год","2 года"],"explanation":"CLP штата Айдахо действует 180 дней и может быть продлено один раз ещё на 180 дней без повторной сдачи общего теоретического экзамена (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"33":{"q":"Управляя транспортным средством по ученическому коммерческому разрешению (CLP) штата Айдахо, владелец всегда должен сопровождаться кем?","options":["Любым взрослым с водительскими правами в возрасте 25 лет или старше","Владельцем CDL надлежащего класса/отметки, сидящим рядом с водителем","Экзаменатором DMV","Никем; разрешено вождение в одиночку"],"explanation":"Владелец CLP может управлять CMV только в сопровождении лица, имеющего действующий CDL для данного типа транспортного средства и сидящего рядом с водителем (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"34":{"q":"Какой документ НЕ входит в число тех, которые требует Idaho DMV для подачи заявления на CDL?","options":["Подтверждение личности","Подтверждение номера Social Security","Подтверждение проживания в Айдахо и законного нахождения","Подписанное письмо от текущего работодателя"],"explanation":"Айдахо требует подтверждения личности, номера Social Security, проживания в Айдахо и законного нахождения/гражданства; письмо от работодателя не требуется (Idaho CDL Manual / требования ITD DMV)."},"35":{"q":"С 7 февраля 2022 года заявитель, впервые получающий CDL в Айдахо, должен пройти обучение водителей начального уровня (ELDT), предоставляемое организацией, внесённой в какой реестр?","options":["Список Idaho State Police academy","Реестр поставщиков обучения FMCSA (TPR)","Список школ Idaho Transportation Department","Любой аккредитованный общественный колледж"],"explanation":"ELDT должно быть пройдено через поставщика, внесённого в FMCSA Training Provider Registry, до сдачи практического экзамена, начиная с 7 февраля 2022 года (Idaho CDL Manual, ITD; 49 CFR 380 Subpart F)."},"36":{"q":"Для чего из перечисленного принятое в Айдахо правило ELDT НЕ требует прохождения обучения перед тестированием?","options":["Получение CDL класса A впервые","Повышение CDL с класса B до класса A","Продление существующего CDL без новых отметок","Получение отметки HazMat (H) впервые"],"explanation":"ELDT применяется к получению CDL впервые, повышению с класса B до класса A и получению впервые отметок P, S или H; обычное продление без новых прав не требует ELDT (Idaho CDL Manual, ITD; 49 CFR 380)."},"37":{"q":"При самостоятельной сертификации медицинского статуса в Айдахо водитель, который осуществляет перевозки только в пределах Айдахо, но освобождён от требований штата о медицинской карте, выбирает какую категорию?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Четыре категории самостоятельной сертификации — это NI, EI, NA и EA; водитель, осуществляющий перевозки исключительно в пределах штата и освобождённый от медицинской сертификации штата, выбирает Excepted Intrastate (EA) (Idaho CDL Manual, ITD; 49 CFR 383.71)."},"38":{"q":"Заявитель на CDL в Айдахо, который будет осуществлять перевозки с пересечением границ штатов и подпадает под требование о прохождении медосмотра DOT, должен самостоятельно сертифицироваться по какой категории?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Водитель в межштатной коммерции, подпадающий под 49 CFR Part 391, выбирает Non-Excepted Interstate (NI) и должен хранить действующий медицинский сертификат экзаменатора в деле (Idaho CDL Manual, ITD; 49 CFR 383.71)."},"39":{"q":"Айдахо предлагает специальный ограниченный CDL, действительный только дважды в течение жизни, для работ по обслуживанию сельскохозяйственной отрасли в пределах 150 миль. Как он называется?","options":["Временный CDL (Provisional)","Сезонный (ограниченный) CDL","Ученический CDL (Apprentice)","Ограниченный CDL по нужде (Limited Hardship)"],"explanation":"Сезонный ограниченный CDL штата Айдахо служит для обслуживания сельскохозяйственных отраслей, действителен до 180 дней в течение 12-месячного периода в пределах 150 миль и может быть получен только дважды в течение жизни (требования ITD DMV к CDL; Idaho Code Title 49)."},"40":{"q":"При управлении коммерческим транспортным средством в Айдахо водитель с CDL считается превысившим допустимый предел и подлежит дисквалификации при какой концентрации алкоголя в крови (BAC)?","options":["0.04 или выше","0.08 или выше","0.02 или выше","0.10 или выше"],"explanation":"Айдахо устанавливает предел BAC для управления коммерческим транспортным средством на уровне 0.04 или выше (половина предела 0.08 для некоммерческих водителей). Источник: Idaho Code 49-335; Idaho CDL Manual (ITD)."},"41":{"q":"В Айдахо владелец CDL, осуждённый за первое тяжкое нарушение, такое как DUI (вождение в нетрезвом виде), при управлении CMV без информационных табличек, дисквалифицируется на срок не менее скольких?","options":["1 год","60 дней","6 месяцев","3 года"],"explanation":"Первое тяжкое нарушение (DUI, отказ от теста, оставление места происшествия, использование CMV при совершении тяжкого преступления и т. д.) влечёт за собой минимальную дисквалификацию CDL на 1 год в Айдахо. Источник: Idaho Code 49-335; Idaho CDL Manual."},"42":{"q":"Если водитель с CDL в Айдахо совершает первое тяжкое нарушение (например, DUI) в то время, когда CMV перевозит опасные материалы, требующие размещения информационных табличек, минимальный срок дисквалификации увеличивается до:","options":["3 года","1 год","2 года","5 лет"],"explanation":"Айдахо продлевает дисквалификацию за первое тяжкое нарушение с 1 года до минимум 3 лет, когда нарушение происходит во время перевозки опасных материалов с информационными табличками. Источник: Idaho Code 49-335; 49 CFR 383.51."},"43":{"q":"Согласно закону Айдахо, каков срок дисквалификации для владельца CDL, осуждённого за ВТОРОЕ тяжкое нарушение (например, второе DUI) в отдельном инциденте?","options":["Пожизненная дисквалификация","10 лет","5 лет","3 года"],"explanation":"Два тяжких нарушения, возникших в результате отдельных инцидентов, приводят к пожизненной дисквалификации CDL в Айдахо (отражая 49 CFR 383.51), хотя может быть доступна программа восстановления через 10 лет. Источник: Idaho Code 49-335; 49 CFR 383.51."},"44":{"q":"Водитель с CDL в Айдахо, который отказывается пройти доказательственный тест на алкоголь или наркотики согласно закону о подразумеваемом согласии, сталкивается с дисквалификацией CDL на срок не менее:","options":["1 год","90 дней","6 месяцев","30 дней"],"explanation":"Отказ от обязательного теста на BAC/наркотики рассматривается как тяжкое нарушение в Айдахо, влекущее ту же минимальную дисквалификацию CDL на 1 год, что и осуждение за DUI (3 года при перевозке опасных грузов с табличками). Источник: Idaho Code 49-335 и 18-8002 (подразумеваемое согласие)."},"45":{"q":"Управляя транспортным средством по дорогам Айдахо, лицо считается давшим согласие на доказательственное тестирование на алкоголь/наркотики. Этот принцип известен как:","options":["Подразумеваемое согласие","Вероятная причина","Надлежащая правовая процедура","Административный пересмотр"],"explanation":"Закон Айдахо о подразумеваемом согласии (Idaho Code 18-8002) считает любого водителя давшим согласие на доказательственное тестирование; отказ влечёт дисквалификацию CDL и приостановление действия прав. Источник: Idaho Code 18-8002; Idaho CDL Manual."},"46":{"q":"В Айдахо осуждение за ДВА серьёзных нарушения правил дорожного движения в отдельных инцидентах в течение 3-летнего периода при управлении CMV приводит к дисквалификации CDL на:","options":["60 дней","30 дней","120 дней","90 дней"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение 3 лет дисквалифицируют водителя не менее чем на 60 дней в Айдахо. Источник: Idaho Code 49-335; 49 CFR 383.51."},"47":{"q":"Водитель с CDL в Айдахо, осуждённый за ТРИ серьёзных нарушения правил дорожного движения в отдельных инцидентах в течение 3-летнего периода, дисквалифицируется на:","options":["120 дней","60 дней","1 год","180 дней"],"explanation":"Третье серьёзное нарушение правил дорожного движения в течение 3 лет повышает дисквалификацию до не менее чем 120 дней в Айдахо. Источник: Idaho Code 49-335; 49 CFR 383.51."},"48":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение правил дорожного движения для владельца CDL в Айдахо?","options":["Превышение скорости на 15 или более mph сверх установленного предела","Превышение скорости на 5 mph сверх установленного предела","Нарушение правил парковки","Просроченная регистрационная наклейка"],"explanation":"Чрезмерное превышение скорости, определяемое как 15 mph или более сверх установленного предела, является серьёзным нарушением правил дорожного движения в Айдахо. Два или три таких нарушения в течение 3 лет влекут дисквалификацию на 60/120 дней. Источник: Idaho Code 49-335; Idaho CDL Manual."},"49":{"q":"Какое из приведённых ниже нарушений также засчитывается как СЕРЬЁЗНОЕ нарушение правил дорожного движения, которое может привести к дисквалификации CDL в Айдахо?","options":["Движение на слишком близком расстоянии (несоблюдение дистанции)","Движение со скоростью на 3 mph ниже предела","Неподача сигнала о повороте на пустом перекрёстке","Неисправный задний фонарь"],"explanation":"Несоблюдение дистанции входит в список серьёзных нарушений правил дорожного движения в Айдахо, наряду с неосторожным вождением, неправильной или беспорядочной сменой полосы движения и чрезмерным превышением скорости. Источник: Idaho Code 49-335; Idaho CDL Manual."},"50":{"q":"Отправка текстовых сообщений за рулём CMV и управление CMV без получения надлежащего CDL — оба эти действия классифицируются правилами Айдахо/FMCSA как:","options":["Серьёзные нарушения правил дорожного движения","Тяжкие нарушения","Нарушения предписания о выводе из эксплуатации","Нарушения на железнодорожных переездах"],"explanation":"Отправка текстовых сообщений за рулём CMV и управление CMV без надлежащего CDL/класса являются серьёзными нарушениями правил дорожного движения (а не тяжкими нарушениями), засчитываемыми в счёт порогов дисквалификации на 60/120 дней. Источник: Idaho Code 49-335; 49 CFR 383.51."},"51":{"q":"За ПЕРВОЕ нарушение на железнодорожно-дорожном переезде, совершённое за рулём CMV, водитель с CDL в Айдахо дисквалифицируется на:","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде влечёт минимальную дисквалификацию CDL на 60 дней в Айдахо. Источник: Idaho Code 49-335; 49 CFR 383.51."},"52":{"q":"Водитель с CDL в Айдахо, осуждённый за ВТОРОЕ нарушение на железнодорожно-дорожном переезде в течение 3-летнего периода, дисквалифицируется на:","options":["120 дней","60 дней","1 год","90 дней"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет приводит к минимальной дисквалификации на 120 дней в Айдахо. Источник: Idaho Code 49-335; 49 CFR 383.51."},"53":{"q":"Каков срок дисквалификации за ТРЕТЬЕ или последующее нарушение на железнодорожно-дорожном переезде в течение 3-летнего периода в Айдахо?","options":["1 год","120 дней","180 дней","60 дней"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение 3 лет дисквалифицирует водителя с CDL в Айдахо не менее чем на 1 год. Источник: Idaho Code 49-335; 49 CFR 383.51."},"54":{"q":"Водитель с CDL в Айдахо, осуждённый за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (OOS) при управлении CMV без опасных грузов и без пассажиров, дисквалифицируется на срок не менее:","options":["180 дней","60 дней","90 дней","30 дней"],"explanation":"Первое нарушение предписания о выводе из эксплуатации влечёт минимальную дисквалификацию на 180 дней (до 1 года) в Айдахо. Источник: Idaho Code 49-335; 49 CFR 383.51."},"55":{"q":"В Айдахо ВТОРОЕ нарушение предписания о выводе из эксплуатации в отдельных инцидентах в течение 10-летнего периода приводит к дисквалификации на:","options":["От 2 до 5 лет","От 180 дней до 1 года","1 год","От 3 до 5 лет"],"explanation":"Второе нарушение предписания OOS в течение 10 лет дисквалифицирует водителя на срок не менее 2 лет и не более 5 лет в Айдахо. Источник: Idaho Code 49-335; 49 CFR 383.51."},"56":{"q":"Если ПЕРВОЕ нарушение предписания о выводе из эксплуатации водителем с CDL в Айдахо происходит во время перевозки опасных материалов с информационными табличками или при перевозке 16 или более пассажиров, минимальная дисквалификация составляет:","options":["180 дней, до 2 лет","60 дней, до 1 года","30 дней, до 6 месяцев","1 год, до 3 лет"],"explanation":"Когда первое нарушение OOS связано с опасными грузами с табличками или 16+ пассажирами, дисквалификация составляет не менее 180 дней и не более 2 лет. Источник: Idaho Code 49-335; 49 CFR 383.51."},"57":{"q":"Помимо дисквалификации водителя, водитель с CDL в Айдахо, нарушивший предписание о выводе из эксплуатации, подлежит федеральному гражданско-правовому штрафу в размере не менее:","options":["$2,500 за первое осуждение","$1,000 за первое осуждение","$500 за первое осуждение","$5,000 за первое осуждение"],"explanation":"Нарушение предписания о выводе из эксплуатации влечёт гражданско-правовой штраф в размере не менее $2,500 за первое осуждение (и не менее $5,000 за последующие осуждения), в дополнение к дисквалификации. Источник: Idaho Code 49-335; 49 CFR 383.53."},"58":{"q":"Согласно правилам, применимым к водителям CMV в Айдахо, максимальный гражданско-правовой штраф, с которым может столкнуться ВОДИТЕЛЬ за отправку текстовых сообщений при управлении коммерческим транспортным средством, составляет приблизительно:","options":["$2,750","$500","$11,000","$1,000"],"explanation":"Водитель CMV, отправляющий текстовые сообщения за рулём, может столкнуться с гражданско-правовым штрафом в размере до примерно $2,750, в то время как работодатель, который допускает/требует этого, может быть оштрафован на сумму до примерно $11,000. Два осуждения в течение 3 лет также влекут дисквалификацию на 60 дней. Источник: FMCSA No-Texting Rule (49 CFR 392.80); Idaho CDL Manual."},"59":{"q":"Водитель с CDL в Айдахо, который пользуется мобильным телефоном в руке во время управления CMV и накапливает два таких осуждения в отдельных инцидентах в течение 3 лет, сталкивается с дисквалификацией на:","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Использование телефона в руке во время управления CMV является серьёзным нарушением правил дорожного движения; два осуждения в течение 3 лет влекут дисквалификацию на 60 дней (120 дней за три). Источник: FMCSA mobile phone rule (49 CFR 392.82); Idaho Code 49-335; 49 CFR 383.51."},"60":{"q":"Согласно правилам о железнодорожных переездах в руководстве Idaho CDL, водитель транспортного средства с табличками HazMat или автобуса с пассажирами обязан остановиться на каком расстоянии от ближайшего рельса?","options":["В пределах 50 feet, но не ближе 15 feet","В пределах 100 feet, но не ближе 50 feet","В пределах 25 feet, но не ближе 5 feet","В пределах 75 feet, но не ближе 25 feet"],"explanation":"Айдахо следует федеральному стандарту (49 CFR 392.10), принятому в руководстве Idaho CDL Manual: автобусы с пассажирами и транспортные средства с табличками HazMat должны останавливаться в пределах 50 feet, но не ближе 15 feet от ближайшего рельса. Idaho Code 49-648/49-650 используют идентичный диапазон остановки от 15 до 50 feet. Источник: Idaho CDL Manual (ITD); Idaho Code 49-648."},"61":{"q":"Когда автобус или транспортное средство с табличками в Айдахо обязано остановиться на железнодорожном переезде, какое действие водитель должен выполнить, пока любая часть транспортного средства находится на путях?","options":["Не переключать передачи во время пересечения","Непрерывно подавать звуковой сигнал","Переключиться на самую низкую передачу на середине пересечения","Выключить аварийную сигнализацию (четырёхстороннюю)"],"explanation":"Руководство Idaho CDL (отражающее 49 CFR 392.10) предписывает водителю выбрать передачу, которая позволит провести транспортное средство полностью через переезд без переключения, и не переключать передачи, пока любая часть транспортного средства находится на переезде. Источник: Idaho CDL Manual (ITD); Idaho Code 49-649."},"62":{"q":"Перед пересечением путей при обязательной остановке руководство Idaho CDL указывает, что водитель автобуса или транспортного средства с табличками HazMat должен использовать какое предупреждающее оборудование по мере приближения к переезду?","options":["Включить четырёхстороннюю (аварийную) сигнализацию","Выставить три светоотражающих треугольника","Подать длинный звуковой сигнал пневматическим клаксоном","Включить фары дальнего света"],"explanation":"Руководство Idaho CDL предписывает водителям, обязанным останавливаться на железнодорожных переездах, включать четырёхстороннюю аварийную сигнализацию при приближении и остановке, чтобы предупредить движущийся сзади транспорт. Источник: Idaho CDL Manual (ITD), раздел о железнодорожных переездах."},"63":{"q":"Согласно закону Айдахо «Move Over» (Idaho Code 49-624), когда вы приближаетесь к остановившемуся полицейскому, аварийному, эвакуационному автомобилю или автомобилю реагирования на дорожные происшествия, у которого включены мигающие огни, на шоссе с двумя или более полосами в вашем направлении, вы обязаны:","options":["Снизить скорость ниже установленного предела и, если вы находитесь в соседней полосе, по возможности перестроиться в несоседнюю полосу","Сохранять установленную скорость, но подать звуковой сигнал","Полностью остановиться, пока аварийный автомобиль не уедет","Перестраиваться, только если этого требует сотрудник"],"explanation":"Idaho Code 49-624 требует, чтобы водители снижали скорость ниже установленного предела и на многополосном шоссе освобождали полосу, прилегающую к неподвижному аварийному/эвакуационному автомобилю или автомобилю реагирования на происшествия (с мигающими огнями), перестраиваясь в несоседнюю полосу, как только это станет разумно возможным. Источник: Idaho Code 49-624."},"64":{"q":"Закон Айдахо «Move Over» (49-624) применяется к неподвижным транспортным средствам с включёнными мигающими огнями. Что из перечисленного НЕ является типом транспортного средства, конкретно защищённым этим законом?","options":["Частный легковой автомобиль, остановившийся из-за спущенного колеса","Эвакуатор","Автомобиль реагирования на дорожные происшествия","Уполномоченный аварийный автомобиль"],"explanation":"Idaho Code 49-624 защищает неподвижные полицейские автомобили, уполномоченные аварийные автомобили, эвакуаторы и автомобили реагирования на дорожные происшествия, у которых включены мигающие огни. Обычный частный легковой автомобиль не упоминается в законе Move Over. Источник: Idaho Code 49-624."},"65":{"q":"На двухполосном шоссе с одной полосой в каждом направлении закон Айдахо Move Over требует, чтобы водитель, проезжающий мимо неподвижного аварийного автомобиля с мигающими огнями:","options":["Снизил скорость ниже установленного предела и сохранял безопасную скорость, пока полностью не проедет транспортное средство","Полностью остановился и подождал","Пересёк осевую линию на встречные полосы, чтобы дать пространство","Продолжил движение с установленной скоростью без снижения"],"explanation":"Там, где перестроение невозможно (по одной полосе в каждом направлении), Idaho Code 49-624 требует, чтобы водитель снизил скорость ниже установленного предела и двигался с осторожностью на безопасной скорости, пока полностью не проедет неподвижное транспортное средство. Источник: Idaho Code 49-624."},"66":{"q":"Согласно Idaho Code 49-1422, водитель транспортного средства, встречающий едущий навстречу остановившийся школьный автобус с включёнными красными визуальными сигналами, НЕ обязан останавливаться только тогда, когда на шоссе:","options":["Более трёх полос","Более двух полос","Размеченная центральная полоса для поворота","Любая разделительная полоса любой ширины"],"explanation":"Idaho Code 49-1422 устанавливает, что встречный транспорт на шоссе с более чем тремя (3) полосами не обязан останавливаться при встрече со школьным автобусом с включёнными сигналами. Айдахо привязывает это исключение к количеству полос (>3 полос), а не просто к наличию разделительной полосы. Источник: Idaho Code 49-1422."},"67":{"q":"На стандартной двухполосной дороге в Айдахо водитель транспортного средства, который встречает ИЛИ обгоняет школьный автобус, остановившийся с мигающими красными визуальными сигналами, обязан:","options":["Остановиться, не доезжая до автобуса, и не продолжать движение, пока сигналы не выключатся или автобус не тронется","Снизить скорость до 20 mph и проехать с осторожностью","Останавливаться, только если видны дети","Останавливаться, только если обгоняет сзади, но не если встречает его"],"explanation":"Idaho Code 49-1422 требует, чтобы водитель, встречающий или обгоняющий с любого направления, остановился, не доезжая до школьного автобуса с включёнными визуальными сигналами по 49-915, и не продолжал движение, пока автобус не тронется или сигналы не будут выключены (за исключением случая со встречным транспортом при >3 полосах). Источник: Idaho Code 49-1422."},"68":{"q":"До July 1, 2026, согласно Idaho Code 49-654, грузовик с пятью или более осями весом свыше 26,000 lbs ограничен на межштатных автомагистралях в НЕГОРОДСКИХ районах максимальной скоростью:","options":["На 10 mph меньше предела для более лёгких транспортных средств","Ровно 65 mph везде","На 5 mph меньше предела для более лёгких транспортных средств","Той же скоростью, что и легковые автомобили"],"explanation":"Согласно редакции Idaho Code 49-654, действующей до June 30, 2026, тяжёлые грузовики (5+ осей, свыше 26,000 lbs) не могут превышать скорость на 10 mph меньше, чем у более лёгких транспортных средств на негородских межштатных автомагистралях. House Bill 664 уравнивает эти пределы с July 1, 2026. Источник: Idaho Code 49-654; HB664 (2026)."},"69":{"q":"С July 1, 2026, House Bill 664 Айдахо меняет правило о скорости для тяжёлых грузовиков (5+ осей, свыше 26,000 lbs) так, что на межштатных автомагистралях, шоссе штата и в других местах их максимальная разрешённая скорость будет:","options":["Такой же, как для транспортных средств с менее чем пятью осями и весом 26,000 lbs или меньше","По-прежнему на 10 mph меньше, чем у легковых автомобилей на негородских межштатных автомагистралях","Ограничена 70 mph по всему штату независимо от установленного предела","Ограничена 65 mph только во всех городских районах"],"explanation":"HB664 вносит поправки в Idaho Code 49-654 так, что с July 1, 2026, на тяжёлые грузовики распространяются те же установленные максимальные пределы скорости, что и на более лёгкие транспортные средства, устраняя прежние ограничения на 10 mph меньше и 65 mph в городе для грузовиков. Источник: Idaho HB664 (2026); Idaho Code 49-654."},"70":{"q":"Согласно Idaho Code 49-654, максимальный предел скорости, который может быть установлен на межштатных автомагистралях Айдахо (для более лёгких транспортных средств, после инженерного исследования), составляет:","options":["80 mph","75 mph","70 mph","85 mph"],"explanation":"Idaho Code 49-654 устанавливает базовый уровень 75 mph на межштатных автомагистралях, но уполномочивает ITD повышать предел до 80 mph на межштатных автомагистралях после инженерного и дорожного исследования; 80 mph установлено на многих сельских участках межштатных автомагистралей Айдахо. Источник: Idaho Code 49-654; ITD."},"71":{"q":"Согласно Idaho Code 49-654, при отсутствии установленного предела максимальная скорость по умолчанию в любом жилом, деловом или городском районе составляет:","options":["35 mph","25 mph","30 mph","20 mph"],"explanation":"Idaho Code 49-654 устанавливает максимум по умолчанию 35 mph в любом жилом, деловом или городском районе, если не указано иное. Источник: Idaho Code 49-654."},"72":{"q":"Idaho Code 49-630 регулирует использование полос на шоссе Айдахо. Транспортное средство, движущееся медленнее обычного потока транспорта, например, гружёный грузовик, поднимающийся в гору, должно:","options":["Двигаться в правой полосе или как можно ближе к правому краю","Использовать центральную полосу для балансировки потока","Оставаться в левой полосе, чтобы правая полоса была свободна для въезда","Выбирать любую полосу при условии подачи сигнала"],"explanation":"Idaho Code 49-630 требует, чтобы любое транспортное средство, движущееся медленнее обычной скорости потока, двигалось в правой доступной полосе или как можно ближе к правому бордюру/краю, за исключением случаев обгона или подготовки к повороту налево. Источник: Idaho Code 49-630."},"73":{"q":"На дороге с разделительной полосой или дороге с односторонним движением руководство Idaho CDL предписывает остановившемуся коммерческому транспортному средству выставить три аварийных предупреждающих устройства на каких расстояниях в сторону приближающегося транспорта?","options":["10 feet, 100 feet и 200 feet в сторону приближающегося транспорта","10 feet, 50 feet и 100 feet в сторону приближающегося транспорта","15 feet, 100 feet и 300 feet в сторону приближающегося транспорта","25 feet, 100 feet и 500 feet в сторону приближающегося транспорта"],"explanation":"На дороге с односторонним движением или с разделительной полосой руководство Idaho CDL (согласно 49 CFR 392.22) требует выставлять предупреждающие устройства на 10 feet, 100 feet и 200 feet от транспортного средства в сторону приближающегося транспорта. Источник: Idaho CDL Manual (ITD)."},"74":{"q":"На двухполосной дороге с двусторонним движением в Айдахо, где руководство Idaho CDL предписывает выставить три обязательных предупреждающих устройства для остановившегося CMV?","options":["В пределах 10 feet от транспортного средства, а также на 100 feet сзади и 100 feet впереди него","Все три в пределах 10 feet от задней части транспортного средства","На 50 feet, 200 feet и 500 feet только сзади","На 100 feet, 200 feet и 300 feet сзади транспортного средства"],"explanation":"На двухполосной дороге с двусторонним движением руководство Idaho CDL (согласно 49 CFR 392.22) требует одно устройство в пределах 10 feet от транспортного средства со стороны движения, одно примерно на 100 feet сзади и одно примерно на 100 feet впереди, на обочине или в полосе остановки. Источник: Idaho CDL Manual (ITD)."},"75":{"q":"Если CMV остановился на двухполосной дороге Айдахо в пределах 500 feet от холма, поворота или другого препятствия, руководство Idaho CDL предписывает:","options":["Отодвинуть заднее предупреждающее устройство назад на расстояние от 100 до 500 feet, чтобы дать водителям больше времени на предупреждение","Оставить все три треугольника на стандартных позициях 10/100/100 feet","Сложить все три устройства прямо за транспортным средством","Убрать треугольники и полагаться только на аварийную сигнализацию"],"explanation":"Когда транспортное средство остановилось в пределах 500 feet от холма, поворота или препятствия, ограничивающего видимость, руководство Idaho CDL (согласно 49 CFR 392.22) предписывает отодвинуть заднее предупреждающее устройство дальше по дороге на расстояние от 100 до 500 feet от транспортного средства, чтобы приближающиеся водители получили достаточное предупреждение. Источник: Idaho CDL Manual (ITD)."},"76":{"q":"Руководство Idaho CDL требует, чтобы остановившийся CMV выставил свои предупреждающие устройства (фальшфейеры или треугольники) в течение какого времени после остановки на шоссе?","options":["10 минут","5 минут","15 минут","30 минут"],"explanation":"Руководство Idaho CDL (согласно 49 CFR 392.22) требует, чтобы аварийные предупреждающие устройства были выставлены в течение 10 минут после остановки на проезжей части или обочине шоссе. Источник: Idaho CDL Manual (ITD)."},"77":{"q":"Спуски US-95, такие как Lewiston Grade и White Bird Grade, известны в Айдахо крутыми горными спусками. Какую функцию безопасности эти спуски обеспечивают для грузовиков, потерявших способность торможения?","options":["Аварийные тормозные (улавливающие) съезды для грузовиков","Обязательные пункты оплаты проезда для тяжёлых грузовиков","Запрет грузового маршрута в масштабах штата с объездом вокруг них","Встроенные в дорогу электронные ограничители скорости"],"explanation":"Крутые горные спуски US-95 в Айдахо (Lewiston Grade, White Bird Grade) оборудованы аварийными улавливающими съездами для грузовиков, в которых используются длинные гравийные полосы для остановки транспортного средства, потерявшего тормоза. ITD устанавливает заблаговременные предупреждающие знаки для этих спусков. Источник: Idaho Transportation Department (ITD), проекты улавливающих съездов US-95."},"78":{"q":"В Айдахо нет платных дорог или платных межштатных мостов в системе шоссе штата. Для водителя CDL, планирующего маршрут через Айдахо, это означает:","options":["На межштатных автомагистралях или шоссе штата Айдахо плата за проезд не взимается","Плата за проезд взимается только на межштатных мостах через реку Snake","Тяжёлые грузовики платят попилометражную плату на I-84","Плата за проезд применяется только на объездной дороге метрополии Boise"],"explanation":"В Айдахо нет платных дорог или платных мостов в общественной системе шоссе; межштатные автомагистрали и шоссе штата бесплатны. Вместо этого водителям CDL следует планировать маршрут с учётом требований к разрешениям на негабаритные/перегруженные грузы и ограничениям маршрута, администрируемым ITD, а не платы за проезд. Источник: Idaho Transportation Department (ITD)."},"79":{"q":"Какое агентство является государственным агентством по лицензированию водителей (State Driver Licensing Agency), ответственным за выдачу коммерческих водительских удостоверений (CDL) в Айдахо?","options":["Idaho Transportation Department (ITD)","Idaho State Police Commercial Vehicle Services","Federal Motor Carrier Safety Administration","Idaho Department of Motor Vehicle Safety"],"explanation":"DMV при Idaho Transportation Department (ITD) является государственным агентством по лицензированию водителей Айдахо и выдаёт CDL. Источник: страница ITD DMV Commercial Driver's License (CDL); ITD «Ten Steps to Getting an Idaho CDL»."},"80":{"q":"Куда в Айдахо фактически обращается соискатель CDL, чтобы подать заявление, сдать письменные тесты и получить удостоверение?","options":["В частную тестовую франшизу ITD","В офис лицензирования водителей (DMV) при шерифе округа","В полевой офис FMCSA","Только в штаб-квартиру ITD в Boise"],"explanation":"Лицензирование водителей в Айдахо администрируется на уровне округов: соискатели обращаются в офис лицензирования водителей при шерифе округа, который обрабатывает заявление на CDL, тесты на знания и выдачу, в то время как ITD обрабатывает записи. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 4."},"81":{"q":"Прежде чем получить удостоверение, каждый новый соискатель CDL в Айдахо должен сначала получить какой документ, чтобы тренироваться и сдать тест на навыки?","options":["Commercial Learner's Permit (CLP)","Учебное разрешение класса D","Карту федеральных межштатных полномочий","Временную коммерческую отметку"],"explanation":"Айдахо требует, чтобы соискатели получили Commercial Learner's Permit (CLP) для получения или повышения категории коммерческого удостоверения и для тренировки на дорогах общего пользования перед тестом на навыки. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 5."},"82":{"q":"Как долго действителен Commercial Learner's Permit (CLP) Айдахо после выдачи?","options":["180 days","90 days","Два года","Один год"],"explanation":"CLP Айдахо действителен в течение одного года (срок Айдахо отличается от минимума в 180 days, используемого в некоторых штатах). Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 5."},"83":{"q":"Согласно федеральным правилам, применяемым в Айдахо, как долго соискатель должен владеть CLP, прежде чем ему будет разрешено сдавать тест на навыки CDL?","options":["Не менее 30 days","Не менее 10 days","Не менее 14 days","Не менее 60 days"],"explanation":"Правила FMCSA, принятые Айдахо, требуют владения CLP минимум 14 days, прежде чем сдавать тест на навыки, даже при повышении категории существующего CDL. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаги 5 и 9."},"84":{"q":"Тест на навыки CDL в Айдахо состоит из каких трёх частей?","options":["Письменный тест, проверка зрения и дорожный тест","Тест пневматических тормозов, тест на задний ход и тест на весовой станции","Предрейсовый осмотр, тест на симуляторе и вождение ночью","Предрейсовый осмотр, базовое управление транспортным средством и вождение на дороге"],"explanation":"Айдахо следует трёхчастному тесту на навыки FMCSA: предрейсовый осмотр (транспортного средства), базовое управление транспортным средством (манёвры на закрытой площадке) и дорожный тест по вождению. Источник: руководство ITD CDL; ITD «Ten Easy Steps to a C.D.L.» Шаги 6-9."},"85":{"q":"В день теста в Айдахо сколько времени даётся соискателю на выполнение предрейсового осмотра транспортного средства?","options":["45 минут","15 минут","60 минут","30 минут"],"explanation":"Айдахо отводит 45 минут на выполнение части с предрейсовым осмотром в день теста; неправильная проверка тормозов является частой причиной провала. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 6."},"86":{"q":"В части с базовым управлением (задний ход) в Айдахо какие два манёвра обязательны для всех соискателей?","options":["Постановка в док через проезд и параллельная парковка","Движение задним ходом по прямой и постановка в док через проезд","Движение задним ходом по прямой и задний ход со смещением","Параллельная парковка и змейка"],"explanation":"Айдахо требует от каждого соискателя движения задним ходом по прямой и заднего хода со смещением; затем экзаменатор выбирает либо постановку в док через проезд, либо параллельную парковку. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 7 (манёвры главы 12)."},"87":{"q":"Какое обучение должен пройти соискатель CDL в Айдахо у зарегистрированного провайдера, прежде чем получить право сдавать тест на навыки?","options":["Одобренный штатом курс безопасного вождения","Семинар по ориентации по безопасности ITD","Курс OSHA по коммерческим транспортным средствам","Entry-Level Driver Training (ELDT)"],"explanation":"С February 7, 2022, соискатели должны пройти Entry-Level Driver Training (ELDT) у провайдера из реестра провайдеров обучения FMCSA (Training Provider Registry), прежде чем сдавать обязательные тесты на навыки. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 5; правило FMCSA ELDT."},"88":{"q":"В самосертификации CDL Айдахо из скольких категорий вождения должен выбрать соискатель?","options":["Двух","Трёх","Пяти","Четырёх"],"explanation":"Владельцы CDL в Айдахо должны самостоятельно сертифицироваться по одной из четырёх категорий: межштатная неисключённая, межштатная исключённая, внутриштатная неисключённая или внутриштатная исключённая. Источник: таблица ITD «Medical Cards & Self Certification Categories»; FMCSA 49 CFR 383.71."},"89":{"q":"Какая категория самосертификации описывается Айдахо как «золотой стандарт» с обязательной медицинской справкой для большинства водителей CDL, позволяющий ездить через границы штатов?","options":["Межштатная исключённая","Внутриштатная неисключённая","Межштатная неисключённая","Внутриштатная исключённая"],"explanation":"Айдахо называет межштатную неисключённую категорию «золотым стандартом»: водитель медицински сертифицирован и может пересекать границы штатов и перевозить любые грузы. Источник: таблица ITD «Medical Cards & Self Certification Categories»."},"90":{"q":"Какая категория самосертификации Айдахо требует действующей медицинской справки DOT, даже несмотря на то, что всё вождение остаётся в пределах Айдахо?","options":["Внутриштатная исключённая","Внутриштатная неисключённая","Межштатная исключённая","Не-CDL исключённая"],"explanation":"Водители внутриштатной неисключённой категории остаются в пределах Айдахо, но всё равно медицински сертифицированы (например, перевозя неосвобождённые грузы), и это добавляет ограничение «K» (только внутриштатное вождение). Источник: таблица ITD «Medical Cards & Self Certification Categories»."},"91":{"q":"Какое ограничение Айдахо добавляет к CDL, когда водитель самостоятельно сертифицируется по внутриштатной категории?","options":["Ограничение «L» (без пневматических тормозов)","Ограничение «K» (только внутриштатная эксплуатация)","Ограничение «E» (только автоматическая коробка передач)","Ограничение «O» (без седельно-сцепного устройства)"],"explanation":"Самосертификация по любой внутриштатной категории (исключённой или неисключённой) добавляет ограничение «K», ограничивающее водителя внутриштатной эксплуатацией. Источник: таблица ITD «Medical Cards & Self Certification Categories»; 49 CFR 383.95."},"92":{"q":"Владелец неисключённого CDL в Айдахо получает новую медицинскую справку от медицинского эксперта DOT. Что он должен с ней сделать?","options":["Представить копию в окружной DMV/ITD, чтобы она была добавлена в водительскую запись","Хранить её только в грузовике для придорожных проверок","Отправить оригинал в FMCSA в Washington, D.C.","Сдать её работодателю вместо штата"],"explanation":"Владельцы неисключённого CDL должны представить (предоставить) копию справки от медицинского эксперта (ME) в окружной DMV/ITD при её получении и при каждом продлении, чтобы она была занесена в водительскую запись. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 4."},"93":{"q":"Справка от медицинского эксперта DOT, используемая для CDL в Айдахо, может быть выдана максимум на какой срок?","options":["До 12 months","До 36 months","До 24 months","До 48 months"],"explanation":"Медицинская справка/справка от медицинского эксперта DOT действительна до 24 months; эксперт может выдать её на меньший срок для наблюдения за медицинским состоянием. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 2."},"94":{"q":"Медицинский специалист, который проводит медосмотр DOT для соискателя CDL в Айдахо, должен быть внесён в какой список?","options":["В панель CDL Idaho Board of Medicine","В National Registry of Certified Medical Examiners","В список одобренных врачей ITD","В реестр безопасности перевозчиков FMCSA"],"explanation":"Проводящий осмотр специалист должен быть внесён в National Registry of Certified Medical Examiners FMCSA; использование незарегистрированного специалиста может привести к понижению категории CDL. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 2; уведомление ITD о медицинских справках."},"95":{"q":"Как долго результаты сданного теста на знания CDL (письменного) соискателя в Айдахо остаются действительными, прежде чем все письменные тесты нужно будет пересдавать?","options":["Один год с даты сдачи","Шесть месяцев с даты сдачи","Два года с даты сдачи","90 days с даты сдачи"],"explanation":"Результаты теста на знания остаются действительными в течение одного года с даты сдачи; если CDL не получено в течение этого года, все письменные тесты нужно пересдавать. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 4."},"96":{"q":"Если соискатель в Айдахо проваливает тест на знания CDL (письменный), как скоро он может его пересдать?","options":["В тот же день","Через три дня","Через семь дней","Через четырнадцать дней"],"explanation":"Соискатель, проваливший письменный тест, может пересдать его через три дня (и снова оплатить плату за каждый тест). Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 4."},"97":{"q":"После сдачи теста на навыки каков срок действия стандартного вновь выданного CDL в Айдахо?","options":["Только два года","Только один год","Четыре года (также доступен вариант на восемь лет)","Фиксированные шесть лет"],"explanation":"Айдахо выдаёт CDL на четыре года; ITD также предлагает вариант на восемь лет. Водитель должен вернуться в окружной DMV, чтобы получить удостоверение после сдачи. Источник: ITD «Ten Steps to Getting an Idaho CDL» Шаг 10."},"98":{"q":"Как регулируется согласно Idaho Code плата за тест на навыки CDL в Айдахо, взимаемая экзаменатором?","options":["Это фиксированная федеральная сумма в каждом штате","Она не взимается со всех соискателей, сдающих впервые","Она устанавливается исключительно учебной школой соискателя","Она ограничена и не может превышать максимум, установленный Idaho Code за каждый тест"],"explanation":"Плата за тест на навыки, устанавливаемая экзаменатором, ограничена Idaho Code (не должна превышать установленный законом максимум за каждый тест), отдельно от небольшой окружной доли. Точные суммы в долларах могут меняться. Источник: ITD «Ten Easy Steps to a C.D.L.» Шаг 9."}},"tr":{"0":{"q":"Idaho karayollarında, yükü dahil bir aracın izin verilen azami genişliği nedir?","options":["8 feet 6 inch","8 feet 0 inch","9 feet 0 inch","10 feet 0 inch"],"explanation":"Idaho Code 49-1010, yükü dahil herhangi bir aracın toplam genişliğini 8 feet 6 inch (102 inches) ile sınırlar. Daha geniş yükler için bir geniş boyut (oversize) izni gerekir. Kaynak: Idaho Code 49-1010 (Araçların ve Yüklerin Boyutu)."},"1":{"q":"Idaho karayollarında bir aracın ve yükünün izin verilen azami yüksekliği nedir?","options":["13 feet 6 inches","14 feet","15 feet","13 feet"],"explanation":"Idaho Code 49-1010, yük dahil bir aracın azami yüksekliğini 14 feet olarak belirler. 14 feet'ten daha yüksek yükler için bir aşırı yükseklik (overheight) izni gerekir. Kaynak: Idaho Code 49-1010."},"2":{"q":"Idaho'da tek bir aks üzerindeki azami brüt ağırlık nedir?","options":["18,000 pounds","22,400 pounds","20,000 pounds","21,500 pounds"],"explanation":"Idaho Code 49-1001, azami tek aks brüt ağırlığını 20,000 pounds olarak belirler. Kaynak: Idaho Code 49-1001 (İzin Verilen Brüt Yükler)."},"3":{"q":"Idaho'da ikiz aks (tandem axle) üzerinde izin verilen azami brüt ağırlık nedir?","options":["34,000 pounds","36,000 pounds","32,000 pounds","40,000 pounds"],"explanation":"Idaho Code 49-1001 uyarınca, bir ikiz aks (tandem) takımı, federal standartla uyumlu olarak en fazla 34,000 pounds taşıyabilir. Kaynak: Idaho Code 49-1001."},"4":{"q":"Idaho'nun A.B.D. federal eyaletlerarası ve savunma karayolu sistemine ait bölümünde, izin almadan izin verilen azami brüt araç veya kombinasyon ağırlığı nedir?","options":["80,000 pounds","105,500 pounds","90,000 pounds","129,000 pounds"],"explanation":"Idaho Code 49-1001, federal eyaletlerarası ve savunma karayollarındaki brüt araç veya kombinasyon ağırlığını, federal yasayla uyumlu olarak 80,000 pounds ile sınırlar. Kaynak: Idaho Code 49-1001."},"5":{"q":"Idaho'nun genel (eyaletlerarası olmayan) eyalet karayollarında, özel bir aşırı ağırlık iznine başvurmadan önce temel yasa uyarınca izin verilen azami brüt araç veya kombinasyon ağırlığı nedir?","options":["80,000 pounds","129,000 pounds","100,000 pounds","105,500 pounds"],"explanation":"Idaho Code 49-1001, azami brüt araç veya kombinasyon ağırlığı olarak 105,500 pounds'a izin verir; ancak bu sınır federal eyaletlerarası ve savunma karayollarında 80,000 pounds'a düşer. Kaynak: Idaho Code 49-1001."},"6":{"q":"Idaho'da tek bir tekerlek üzerinde izin verilen azami brüt ağırlık nedir?","options":["8,000 pounds","12,000 pounds","10,000 pounds","6,000 pounds"],"explanation":"Idaho Code 49-1001, azami tek tekerlek brüt ağırlığını 10,000 pounds olarak belirler. Kaynak: Idaho Code 49-1001."},"7":{"q":"Idaho, art arda gelen bir aks grubu üzerinde izin verilen azami ağırlığı belirlemek için federal köprü ağırlık formülünü kullanır. Idaho Code hangi formülü benimser?","options":["W = 500((LN/N-1) + 12N + 36)","W = 1000(L + N + 20)","W = 34,000 + (N x 12)","W = 250(LN + 12 + 36N)"],"explanation":"Idaho Code 49-1001(1), federal köprü formülü W = 500((LN/N-1) + 12N + 36) formülünü benimser; burada W azami ağırlık, L aks grubunun uçları arasındaki feet cinsinden mesafe ve N aks sayısıdır. Kaynak: Idaho Code 49-1001(1)."},"8":{"q":"Idaho'nun köprü formülünde, 'L' değişkeni neyi temsil eder?","options":["Treylerin yasal yük derecelendirmesi","Art arda gelen iki veya daha fazla akstan oluşan bir grubun uçları arasındaki feet cinsinden mesafe","Yalnızca en uzun tek aks grubunun uzunluğu","Aracın ruhsatlı brüt ağırlığı"],"explanation":"W = 500((LN/N-1) + 12N + 36) formülünde 'L', art arda gelen iki veya daha fazla akstan oluşan herhangi bir grubun uçları arasındaki feet cinsinden mesafe, 'N' aks sayısı ve 'W' azami ağırlıktır. Kaynak: Idaho Code 49-1001(1)."},"9":{"q":"Idaho'da art arda gelen iki ikiz aks takımının her biri 34,000 pounds taşıyabilir; ancak yalnızca bu ikiz aks takımlarının ilk ve son aksları arasındaki toplam mesafe en az kaç feet ise mümkündür?","options":["30 feet","36 feet","40 feet","34 feet"],"explanation":"Idaho Code 49-1001(1)(b), art arda gelen iki ikiz aks takımının, bu takımların ilk ve son aksları arasındaki mesafenin 36 feet veya daha fazla olması koşuluyla her birinin 34,000 pounds taşımasına izin verir. Kaynak: Idaho Code 49-1001(1)(b)."},"10":{"q":"Idaho'da ulusal ağın (national network) parçası olan güzergahlarda çalışan bir yarı treyler (semitrailer) hangi uzunluğu aşamaz?","options":["48 feet","53 feet","57 feet","45 feet"],"explanation":"Idaho Code 49-1010, ulusal ağda (ve ilgili erişim güzergahlarında) çalışan bir yarı treyleri 53 feet uzunlukla sınırlar. Kaynak: Idaho Code 49-1010."},"11":{"q":"Idaho Code uyarınca, bir araç üzerindeki yük genel olarak aracın önünden kaç feet'ten fazla taşamaz?","options":["3 feet","4 feet","6 feet","2 feet"],"explanation":"Idaho Code 49-1010, bir yükün aracın önünden 4 feet'ten fazla taşmasını yasaklar. Kaynak: Idaho Code 49-1010."},"12":{"q":"Bir araç kombinasyonu, indirgenebilir bir yük taşırken Idaho'da 105,500 pounds'un üzerinde bir brüt ağırlıkta çalışabilir; ancak hangi ağırlığı aşmamak ve yalnızca uygun tescil ve izinle belirlenmiş eyaletlerarası olmayan güzergahlarda olmak kaydıyla?","options":["129,000 pounds","117,000 pounds","140,000 pounds","125,500 pounds"],"explanation":"Idaho Code 49-1001(1)(c), aracın tescilli olması, ağırlık formülüne ve uzunluk kısıtlamalarına uyması ve Idaho Code 49-1004 uyarınca belirlenmiş güzergahlarda çalışması koşuluyla, eyaletlerarası olmayan karayollarında 105,500 pounds'un üzerinde ancak 129,000 pounds'u aşmayan indirgenebilir yüklere izin verir. Kaynak: Idaho Code 49-1001(1)(c) ve 49-1004."},"13":{"q":"Idaho'da tescilli bir kombinasyona 105,501 ile 129,000 pounds arasında indirgenebilir yük taşıma yetkisi veren özel güzergah yıllık iznini kim verir?","options":["Güzergahtaki her ilçenin (county) şerifi","Federal Karayolu İdaresi (Federal Highway Administration)","Idaho Ulaştırma Departmanı (Idaho Transportation Department) veya kendi takdirine bağlı olarak yerel bir kamu karayolu kurumu","Herhangi bir ticari kamyon durağı tartı istasyonu"],"explanation":"Idaho Code 49-1004, 105,501'den 129,000 pounds'a kadar olan yükler için özel güzergah izinlerinin, departman veya yerel yetkililerce belirlenen güzergahlarda Idaho Ulaştırma Departmanı (Idaho Transportation Department) tarafından veya kendi takdirine bağlı olarak yerel bir kamu karayolu kurumu tarafından verildiğini öngörür. Kaynak: Idaho Code 49-1004."},"14":{"q":"Idaho'nun yasal boyut veya ağırlık sınırlarını aşan bir aracın karayolunda hareket edebilmesi için genellikle hangisi gereklidir?","options":["Hareketten önce alınmış geçerli bir geniş boyut/aşırı ağırlık (oversize/overweight) izni","Class A CDL'ye geçiş","FMCSA'dan federal bir muafiyet (waiver)","Yalnızca bir giriş kapısı (port-of-entry) memurundan sözlü onay"],"explanation":"Idaho Code 49-1004 ve ITD izin kuralları, yasal boyut veya ağırlık sınırlarını aşan bir aracı kullanmak için hareketten önce alınmış bir geniş boyut ve/veya aşırı ağırlık (oversize/overweight) izni gerektirir; izin araçta bulundurulmalıdır. Kaynak: Idaho Code 49-1004; ITD izin kuralları (IDAPA 39.03.03)."},"15":{"q":"Idaho yasası, belirli emtiaları taşıyan araçlara eyaletlerarası olmayan karayollarında bir ağırlık istisnası (ayrı, daha cömert bir aks aralığı tablosu) tanır. Hangi emtia grubu kapsam dahilindedir?","options":["Tomruklar, kağıt hamuru odunu, ham kereste, direkler, cevherler, kum ve çakıl ve canlı hayvan dahil tarımsal emtialar","Soğutulmuş bakkaliye ürünleri ve şişelenmiş içecekler","Yeni otomobiller ve karavanlar (recreational vehicles)","Yalnızca tehlikeli maddeler ve dökme yakıt"],"explanation":"Idaho Code 49-1001(2); tomruk, kağıt hamuru odunu, kütük, ham kereste, direk veya kazık; cevher, konsantre, kum ve çakıl ile dökme agrega; ya da canlı hayvan dahil tarımsal emtia taşıyan araçlar için özel bir izin verilen yük tablosu sağlar. Kaynak: Idaho Code 49-1001(2)."},"16":{"q":"Idaho Code 49-1001(2)'deki tomruk, cevher, kum/çakıl ve tarımsal emtialara ilişkin özel ağırlık izinleri, operatörün beyanına göre toplam brüt ağırlığın hangi rakamı aşması amaçlandığında artık geçerli DEĞİLDİR?","options":["80,000 pounds","79,000 pounds","105,500 pounds","84,000 pounds"],"explanation":"Idaho Code 49-1001(2), operatörün beyanına göre toplam brüt ağırlığın 79,000 pounds'u aşması amaçlanıyorsa emtia ağırlık izinlerinin geçerli olmadığını belirtir. Kaynak: Idaho Code 49-1001(2)."},"17":{"q":"Bir Idaho giriş kapısında (port of entry), yüklü bir araç, tek bir aksın ağırlığı azami sınırı ne kadar aştığında tartıyı geçemez?","options":["500 pounds veya daha fazla","1,000 pounds veya daha fazla","2,000 pounds veya daha fazla","5,000 pounds veya daha fazla"],"explanation":"Idaho Code 49-1001(8), tek bir aksın azami sınırı 2,000 pounds veya daha fazla aşması, ya da brüt/aks grubu ağırlığının azami sınırı %7 veya daha fazla aşması durumunda aracın bir giriş kapısını geçemeyeceğini öngörür. Kaynak: Idaho Code 49-1001(8)."},"18":{"q":"Bir Idaho giriş kapısında (port of entry), azami izin verilen brüt veya aks grubu ağırlığının yüzde kaç üzerinde bir araç durdurulur ve devam etmeden önce uygunluğa getirilmesi istenir?","options":["Yüzde 7 veya daha fazla","Yüzde 5 veya daha fazla","Yüzde 10 veya daha fazla","Yüzde 15 veya daha fazla"],"explanation":"Idaho Code 49-1001(8), brüt araç ağırlığının veya bir aks kombinasyonunun azami izin verilen ağırlığı yüzde 7 veya daha fazla aşması durumunda aracın tartıda uygunluğa getirilmesini gerektirir (tek aks eşiği 2,000 pounds'tur). Kaynak: Idaho Code 49-1001(8)."},"19":{"q":"Idaho, izinli aşırı genişlikteki yükler için refakat araçları (pilot/bayrak araçları) gerektirir. Idaho genel olarak hangi yük genişliğinde en az bir pilot/refakat aracı gerektirir?","options":["8 feet 6 inches genişlikten fazla","10 feet genişlikten fazla","12 feet genişlikten fazla","16 feet genişlikten fazla"],"explanation":"ITD'nin geniş boyut hareket kuralları uyarınca, 12 feet'ten daha geniş bir yük genellikle bir pilot/refakat aracı gerektirir ve 14 feet'ten daha geniş yükler iki tane gerektirir. Aşırı genişlikteki yüklerin köşelerinde bayraklar gereklidir ve refakat araçlarında bir OVERSIZE LOAD tabelası ile sarı (amber) ışıklar gereklidir. Kaynak: ITD izin kuralları (IDAPA 39.03.05 / Pilot-Refakat gereklilikleri)."},"20":{"q":"Idaho'da, kaç pounds veya daha fazla Brüt Araç Ağırlık Derecelendirmesine (GVWR) sahip herhangi bir tekil aracı kullanmak için bir CDL gereklidir (10,000 lbs'in üzerinde bir şey çekmeden)?","options":["16,001 pounds","26,001 pounds","33,001 pounds","10,001 pounds"],"explanation":"Idaho federal eşiği benimser: 26,001 lbs veya daha fazla GVWR'ye sahip herhangi bir tekil araç için bir Class B CDL gereklidir (Idaho CDL Manual, ITD; 49 CFR 383.91)."},"21":{"q":"Çekilen ünitelerin GVWR'sinin 10,000 lbs'i aştığı ve GCWR'si 26,001 lbs veya daha fazla olan bir kombinasyon aracı kullanmak için hangi Idaho CDL sınıfı gereklidir?","options":["Class C","Class B","Class A","Class D"],"explanation":"Bir Class A CDL, çekilen aracın/araçların GVWR'sinin 10,000 lbs'ten fazla olması koşuluyla GCWR'si 26,001 lbs veya daha fazla olan kombinasyon araçlarını kapsar (Idaho CDL Manual, ITD)."},"22":{"q":"Idaho kuralları uyarınca, 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ancak Class A/B ağırlık sınırlarının altında olan bir araç hangi CDL sınıfını gerektirir?","options":["Class C","Class A","Class B","CDL gerekmez"],"explanation":"Class A veya B kriterlerini karşılamayan ancak sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da plakart gerektiren tehlikeli madde taşıyan araçlar için bir Class C CDL gereklidir (Idaho CDL Manual, ITD)."},"23":{"q":"Idaho, dökme halde sıvı veya gaz taşıyan tank (tanker) araçlarını kullanma yetkisine hangi onay harfini atar?","options":["T","N","X","H"],"explanation":"N onayı tank araçları içindir. (T = ikili/üçlü, H = hazmat, X = tank ve hazmat birleşik.) Kaynak: Idaho CDL Manual, ITD; 49 CFR 383.93."},"24":{"q":"Idaho'da 'T' onayı, sahibine hangi tür aracı kullanma yetkisi verir?","options":["Tank araçları","Tehlikeli madde taşıyan araçlar","İkili ve üçlü treylerler","16+ yolcu taşıyan araçlar"],"explanation":"T onayı ikili ve üçlü treylerleri kapsar ve yalnızca bir bilgi testini geçmeyi gerektirir (Idaho CDL Manual, ITD; 49 CFR 383.93)."},"25":{"q":"Bir Idaho HazMat (H) onayı almak için, başvuru sahibi bir bilgi testini geçmeli ve ayrıca hangi ek federal gerekliliği tamamlamalıdır?","options":["Direksiyon başında bir beceri testi","Bir TSA güvenlik tehdidi değerlendirmesi (geçmiş kontrolü)","Bir görme muafiyeti (vision waiver) başvurusu","İkinci bir tıbbi muayene"],"explanation":"Idaho, H onayı başvuru sahibinin bir bilgi testini geçmesini ve USA PATRIOT Act kapsamında bir TSA Güvenlik Tehdidi Değerlendirmesini (parmak izine dayalı geçmiş kontrolü) geçmesini gerektirir (Idaho CDL Manual, ITD; 49 CFR 1572)."},"26":{"q":"Idaho'da bir okul otobüsü (S) onayı verilmeden önce, başvuru sahibinin ayrıca hangi diğer onaya sahip olması veya bunu alması gerekir?","options":["N (Tank)","T (İkili/Üçlü)","P (Yolcu)","H (HazMat)"],"explanation":"S (okul otobüsü) onayı, P (yolcu) onayının yanı sıra bir bilgi testi ve bir okul otobüsünde bir beceri testi gerektirir (Idaho CDL Manual, ITD; 49 CFR 383.123)."},"27":{"q":"Hangi Idaho CDL onayı, temsili bir araçta hem bir bilgi testi hem de direksiyon başında bir beceri testi gerektirir?","options":["N (Tank)","P (Yolcu)","T (İkili/Üçlü)","H (HazMat)"],"explanation":"P (yolcu) onayı, bir yolcu aracında bir bilgi testini ve bir beceri testini geçmeyi gerektirir; N, T ve H yalnızca bilgi testi gerektiren onaylardır (Idaho CDL Manual, ITD; 49 CFR 383.93)."},"28":{"q":"Yalnızca Idaho içinde (eyalet içi/intrastate) ticari bir araç kullanmak için bir Idaho CDL almanın asgari yaşı nedir?","options":["16 yaşında","18 yaşında","19 yaşında","21 yaşında"],"explanation":"Idaho, 18 yaşında eyalet içi (intrastate) bir CDL'ye izin verir; başvuru sahibinin ayrıca geçerli bir Idaho Class D ehliyetine sahip olması ve bir yıllık ehliyetli sürüş deneyiminin bulunması gerekir (Idaho CDL Manual, ITD; Idaho Code 49-305)."},"29":{"q":"Idaho (federal yasayı izleyerek), eyalet sınırları ötesinde (eyaletlerarası/interstate) ticari bir araç kullanmak için hangi asgari yaşı gerektirir?","options":["18 yaşında","19 yaşında","20 yaşında","21 yaşında"],"explanation":"Eyaletlerarası ticari sürüş, asgari 21 yaş gerektirir; 18 yaşındaki bir Idaho CDL sahibi eyalet içi (intrastate) çalışmayla sınırlıdır (Idaho CDL Manual, ITD; 49 CFR 391.11)."},"30":{"q":"Idaho'da bir HazMat (H) onayı, kaç yaşından küçük bir başvuru sahibine verilemez?","options":["18","19","21","25"],"explanation":"Ücret karşılığı hazmat taşımacılığı genellikle eyaletlerarası ticareti ve bir TSA değerlendirmesini içerdiğinden, H onayı başvuru sahibinin en az 21 yaşında olmasını gerektirir (Idaho CDL Manual, ITD; 49 CFR 383/1572)."},"31":{"q":"Idaho'da benimsenen federal kurallar uyarınca, bir sürücünün CDL beceri testine girme hakkına sahip olmadan önce bir Ticari Öğrenci İzni (CLP) ne kadar süre elinde bulundurması gerekir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Beceri testine girilmeden önce CLP'nin en az 14 gün süreyle elde tutulması gerekir (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"32":{"q":"Bir Idaho Ticari Öğrenci İzni (CLP), yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["90 gün","180 gün","1 yıl","2 yıl"],"explanation":"Bir Idaho CLP'si 180 gün geçerlidir ve genel bilgi testi yeniden alınmadan bir kez daha 180 gün için yenilenebilir (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"33":{"q":"Bir Idaho Ticari Öğrenci İzni (CLP) ile araç kullanırken, izin sahibine her zaman ne eşlik etmelidir?","options":["25 yaş veya üzerinde ehliyetli herhangi bir yetişkin","Sürücünün yanında oturan, uygun sınıf/onaya sahip bir CDL sahibi","Bir DMV sınav görevlisi (examiner)","Hiç kimse; tek başına sürüşe izin verilir"],"explanation":"Bir CLP sahibi, yalnızca araç türü için geçerli bir CDL'ye sahip olan ve sürücünün yanında oturan bir kişi eşlik ettiğinde bir CMV kullanabilir (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"34":{"q":"Bir Idaho DMV'sinin CDL başvurusu için talep ettiği belgeler arasında hangisi YOKTUR?","options":["Kimlik kanıtı","Sosyal Güvenlik numarası kanıtı","Idaho ikametgahı ve yasal varlık (lawful presence) kanıtı","Mevcut bir işverenden imzalı bir mektup"],"explanation":"Idaho kimlik, Sosyal Güvenlik numarası, Idaho ikametgahı ve yasal varlık/vatandaşlık kanıtı ister; bir işveren mektubu gerekli değildir (Idaho CDL Manual / ITD DMV gereklilikleri)."},"35":{"q":"7 Şubat 2022'den (February 7, 2022) bu yana, ilk kez başvuran bir Idaho CDL başvuru sahibinin, nerede listelenen bir kuruluş tarafından sağlanan Başlangıç Düzeyi Sürücü Eğitimini (ELDT) tamamlaması gerekir?","options":["Idaho Eyalet Polisi akademi listesi","FMCSA Eğitim Sağlayıcı Kayıt Sistemi (TPR)","Idaho Ulaştırma Departmanı okul listesi","Akredite herhangi bir toplum koleji (community college)"],"explanation":"ELDT, 7 Şubat 2022 (Feb 7, 2022) tarihinden itibaren geçerli olmak üzere, beceri testine girmeden önce FMCSA Eğitim Sağlayıcı Kayıt Sistemi'nde (Training Provider Registry) listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır (Idaho CDL Manual, ITD; 49 CFR 380 Subpart F)."},"36":{"q":"Aşağıdakilerden hangisi için Idaho'nun benimsediği ELDT kuralı, test öncesinde eğitim GEREKTİRMEZ?","options":["İlk kez bir Class A CDL almak","Bir Class B CDL'yi bir Class A CDL'ye yükseltmek","Yeni bir onay olmadan mevcut bir CDL'yi yenilemek","İlk kez bir HazMat (H) onayı almak"],"explanation":"ELDT, ilk kez alınan CDL'ler, Class B'den A'ya yükseltmeler ve ilk kez alınan P, S veya H onayları için geçerlidir; yeni bir ayrıcalık olmadan yapılan düz bir yenileme ELDT gerektirmez (Idaho CDL Manual, ITD; 49 CFR 380)."},"37":{"q":"Idaho'da tıbbi durumu öz beyanla bildirirken (self-certifying), yalnızca Idaho içinde çalışan ancak eyalet tıbbi kart gerekliliklerinden muaf olan bir sürücü hangi kategoriyi seçer?","options":["Muaf Olmayan Eyaletlerarası (NI)","Muaf Eyaletlerarası (EI)","Muaf Olmayan Eyalet İçi (NA)","Muaf Eyalet İçi (EA)"],"explanation":"Dört öz beyan kategorisi NI, EI, NA ve EA'dır; yalnızca eyalet içinde çalışan ve eyalet tıbbi sertifikasyonundan muaf olan bir sürücü Muaf Eyalet İçi (EA) kategorisini seçer (Idaho CDL Manual, ITD; 49 CFR 383.71)."},"38":{"q":"Eyalet sınırları ötesinde araç kullanacak ve DOT fiziksel muayene gerekliliğine tabi olan bir Idaho CDL başvuru sahibi hangi kategoride öz beyanda bulunmalıdır?","options":["Muaf Olmayan Eyaletlerarası (NI)","Muaf Eyaletlerarası (EI)","Muaf Olmayan Eyalet İçi (NA)","Muaf Eyalet İçi (EA)"],"explanation":"49 CFR Part 391'e tabi olarak eyaletlerarası ticarette çalışan bir sürücü, Muaf Olmayan Eyaletlerarası (NI) kategorisini seçer ve dosyasında geçerli bir tıbbi muayene sertifikası bulundurmalıdır (Idaho CDL Manual, ITD; 49 CFR 383.71)."},"39":{"q":"Idaho, 150 mil içinde çiftlikle ilgili hizmet işleri için ömür boyu yalnızca iki kez geçerli olan özel kısıtlı bir CDL sunar. Bunun adı nedir?","options":["Geçici (Provisional) CDL","Mevsimlik (kısıtlı) CDL","Çırak (Apprentice) CDL","Sınırlı Zorluk (Limited Hardship) CDL"],"explanation":"Idaho'nun Mevsimlik kısıtlı CDL'si çiftlikle ilgili hizmet sektörlerine hizmet eder, 12 aylık bir dönemde 150 mil içinde en fazla 180 gün geçerlidir ve ömür boyu yalnızca iki kez alınabilir (ITD DMV CDL gereklilikleri; Idaho Code Title 49)."},"40":{"q":"Idaho'da bir ticari motorlu araç kullanırken, bir CDL sürücüsü hangi kandaki alkol konsantrasyonunda (BAC) yasal olarak sınırın üzerinde sayılır ve diskalifiye edilmeye tabi olur?","options":["0.04 veya daha fazla","0.08 veya daha fazla","0.02 veya daha fazla","0.10 veya daha fazla"],"explanation":"Idaho, bir ticari motorlu araç kullanma için BAC sınırını 0.04 veya daha fazla olarak belirler (ticari olmayan sürücüler için 0.08 olan sınırın yarısı). Kaynak: Idaho Code 49-335; Idaho CDL Manual (ITD)."},"41":{"q":"Idaho'da, plakartsız bir CMV kullanırken DUI gibi ilk büyük suçtan (major offense) mahkum edilen bir CDL sahibi en az ne kadar süre diskalifiye edilir?","options":["1 yıl","60 gün","6 ay","3 yıl"],"explanation":"İlk büyük suç (DUI, test reddi, olay yerini terk etme, bir CMV'yi bir suçta kullanma vb.) Idaho'da asgari 1 yıllık CDL diskalifikasyonu taşır. Kaynak: Idaho Code 49-335; Idaho CDL Manual."},"42":{"q":"Bir Idaho CDL sürücüsü, CMV plakart gerektiren tehlikeli madde taşırken ilk büyük suçu (DUI gibi) işlerse, asgari diskalifikasyon şuna yükselir:","options":["3 yıl","1 yıl","2 yıl","5 yıl"],"explanation":"Idaho, ihlal plakart gerektiren tehlikeli madde taşınırken meydana geldiğinde ilk büyük suç diskalifikasyonunu 1 yıldan asgari 3 yıla çıkarır. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"43":{"q":"Idaho yasasına göre, ayrı bir olayda İKİNCİ bir büyük suçtan (örneğin ikinci bir DUI) mahkum edilen bir CDL sahibi için diskalifikasyon süresi nedir?","options":["Ömür boyu diskalifikasyon","10 yıl","5 yıl","3 yıl"],"explanation":"Ayrı olaylardan kaynaklanan iki büyük suç, Idaho'da ömür boyu CDL diskalifikasyonuyla sonuçlanır (49 CFR 383.51'i yansıtır); ancak 10 yıllık bir yeniden ehliyetlendirme programı mevcut olabilir. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"44":{"q":"Zımni rıza (implied consent) yasası uyarınca alkol veya uyuşturucu için kanıt amaçlı bir testi vermeyi reddeden bir Idaho CDL sürücüsü en az ne kadar CDL diskalifikasyonuyla karşı karşıya kalır:","options":["1 yıl","90 gün","6 ay","30 gün"],"explanation":"Gerekli BAC/uyuşturucu testini reddetmek Idaho'da bir büyük suç olarak ele alınır ve bir DUI mahkumiyetiyle aynı asgari 1 yıllık CDL diskalifikasyonunu taşır (plakart gerektiren hazmat varsa 3 yıl). Kaynak: Idaho Code 49-335 ve 18-8002 (zımni rıza)."},"45":{"q":"Idaho yollarında araç kullanarak, bir motorlu araç kullanan bir kişi kanıt amaçlı alkol/uyuşturucu testine rıza göstermiş sayılır. Bu ilkeye ne ad verilir:","options":["Zımni rıza (implied consent)","Makul şüphe (probable cause)","Adil yargılanma (due process)","İdari inceleme (administrative review)"],"explanation":"Idaho'nun zımni rıza (implied consent) yasası (Idaho Code 18-8002), herhangi bir sürücünün kanıt amaçlı teste rıza göstermiş sayıldığını öngörür; ret, CDL diskalifikasyonunu ve ehliyet askıya alınmasını tetikler. Kaynak: Idaho Code 18-8002; Idaho CDL Manual."},"46":{"q":"Idaho'da, bir CMV kullanırken 3 yıllık bir süre içinde ayrı olaylarda İKİ ciddi trafik ihlalinden mahkum olmak, şu CDL diskalifikasyonuyla sonuçlanır:","options":["60 gün","30 gün","120 gün","90 gün"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, Idaho'da sürücüyü en az 60 gün diskalifiye eder. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"47":{"q":"3 yıllık bir süre içinde ayrı olaylarda ÜÇ ciddi trafik ihlalinden mahkum edilen bir Idaho CDL sürücüsü şu kadar diskalifiye edilir:","options":["120 gün","60 gün","1 yıl","180 gün"],"explanation":"3 yıl içinde üçüncü bir ciddi trafik ihlali, Idaho'da diskalifikasyonu en az 120 güne çıkarır. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"48":{"q":"Aşağıdakilerden hangisi bir Idaho CDL sahibi için CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Belirtilen sınırın 15 veya daha fazla mph üzerinde hız yapmak","Belirtilen sınırın 5 mph üzerinde hız yapmak","Bir park ihlali","Süresi dolmuş bir tescil etiketi"],"explanation":"Belirtilen sınırın 15 mph veya daha fazla üzerinde olarak tanımlanan aşırı hız, Idaho'da ciddi bir trafik ihlalidir. 3 yıl içinde iki veya üç tanesi 60/120 günlük diskalifikasyonları tetikler. Kaynak: Idaho Code 49-335; Idaho CDL Manual."},"49":{"q":"Aşağıdaki ihlallerden hangisi de Idaho'da CDL diskalifikasyonuna yol açabilecek CİDDİ bir trafik ihlali olarak sayılır?","options":["Çok yakın takip etmek (tailgating)","Sınırın 3 mph altında araç kullanmak","Boş bir kavşakta dönüş sinyali vermemek","Kırık bir arka stop lambası"],"explanation":"Çok yakın takip etmek, dikkatsiz sürüş, hatalı veya düzensiz şerit değiştirmeler ve aşırı hızın yanı sıra Idaho'nun ciddi trafik ihlali listesindedir. Kaynak: Idaho Code 49-335; Idaho CDL Manual."},"50":{"q":"Bir CMV kullanırken mesaj yazmak (texting) ve uygun CDL'yi almadan bir CMV kullanmak, Idaho/FMCSA kuralları tarafından her ikisi de şu şekilde kategorize edilir:","options":["Ciddi trafik ihlalleri","Büyük suçlar (major offenses)","Hizmet dışı (out-of-service) ihlalleri","Demiryolu geçidi ihlalleri"],"explanation":"Bir CMV kullanırken mesaj yazmak ve uygun CDL/sınıf olmadan bir CMV kullanmak ciddi trafik ihlalleridir (büyük suçlar değil) ve 60/120 günlük diskalifikasyon eşiklerine sayılır. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"51":{"q":"Bir CMV kullanırken işlenen İLK demiryolu-karayolu hemzemin geçit ihlali için, bir Idaho CDL sürücüsü şu kadar diskalifiye edilir:","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"İlk bir demiryolu hemzemin geçit ihlali, Idaho'da asgari 60 günlük CDL diskalifikasyonu taşır. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"52":{"q":"3 yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlalinden mahkum edilen bir Idaho CDL sürücüsü şu kadar diskalifiye edilir:","options":["120 gün","60 gün","1 yıl","90 gün"],"explanation":"3 yıl içinde ikinci bir demiryolu hemzemin geçit ihlali, Idaho'da asgari 120 günlük bir diskalifikasyonla sonuçlanır. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"53":{"q":"Idaho'da 3 yıllık bir süre içinde ÜÇÜNCÜ veya sonraki bir demiryolu-karayolu hemzemin geçit ihlali için diskalifikasyon süresi nedir?","options":["1 yıl","120 gün","180 gün","60 gün"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demiryolu hemzemin geçit ihlali, Idaho CDL sürücüsünü en az 1 yıl diskalifiye eder. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"54":{"q":"Hazmat olmayan, yolcu olmayan bir CMV kullanırken bir hizmet dışı (OOS) emrinin İLK ihlalinden mahkum edilen bir Idaho CDL sürücüsü en az şu kadar diskalifiye edilir:","options":["180 gün","60 gün","90 gün","30 gün"],"explanation":"İlk bir hizmet dışı emri ihlali, Idaho'da asgari 180 günlük (1 yıla kadar) bir diskalifikasyon taşır. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"55":{"q":"Idaho'da, 10 yıllık bir süre içinde ayrı olaylarda İKİNCİ bir hizmet dışı emri ihlali şu diskalifikasyonla sonuçlanır:","options":["2 ila 5 yıl","180 gün ila 1 yıl","1 yıl","3 ila 5 yıl"],"explanation":"10 yıl içinde ikinci bir OOS emri ihlali, Idaho'da sürücüyü en az 2 yıl ve en fazla 5 yıl diskalifiye eder. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"56":{"q":"Bir Idaho CDL sürücüsünün İLK hizmet dışı emri ihlali, plakart gerektiren tehlikeli madde taşırken veya 16 ya da daha fazla yolcu taşırken meydana gelirse, asgari diskalifikasyon şudur:","options":["180 gün, 2 yıla kadar","60 gün, 1 yıla kadar","30 gün, 6 aya kadar","1 yıl, 3 yıla kadar"],"explanation":"İlk bir OOS ihlali plakart gerektiren hazmat veya 16+ yolcu içerdiğinde, diskalifikasyon en az 180 gün ve en fazla 2 yıldır. Kaynak: Idaho Code 49-335; 49 CFR 383.51."},"57":{"q":"Sürücü diskalifikasyonunun yanı sıra, bir hizmet dışı emrini ihlal eden bir Idaho CDL sürücüsü en az şu kadar federal idari para cezasına tabidir:","options":["İlk mahkumiyet için $2,500","İlk mahkumiyet için $1,000","İlk mahkumiyet için $500","İlk mahkumiyet için $5,000"],"explanation":"Bir hizmet dışı emri ihlali, diskalifikasyona ek olarak, ilk mahkumiyet için en az $2,500 (ve sonraki mahkumiyetler için en az $5,000) idari para cezası taşır. Kaynak: Idaho Code 49-335; 49 CFR 383.53."},"58":{"q":"Idaho CMV sürücülerine uygulanan kurallar uyarınca, bir SÜRÜCÜNÜN ticari bir motorlu araç kullanırken mesaj yazması nedeniyle karşılaşabileceği azami idari para cezası yaklaşık olarak şudur:","options":["$2,750","$500","$11,000","$1,000"],"explanation":"Araç kullanırken mesaj yazan bir CMV sürücüsü yaklaşık $2,750'ye kadar idari para cezasıyla karşılaşabilirken, buna izin veren/bunu gerektiren bir işveren yaklaşık $11,000'e kadar ceza alabilir. 3 yıl içinde iki mahkumiyet ayrıca 60 günlük bir diskalifikasyon getirir. Kaynak: FMCSA No-Texting Rule (49 CFR 392.80); Idaho CDL Manual."},"59":{"q":"Idaho'da bir CMV kullanırken elde tutulan bir cep telefonu kullanan ve 3 yıl içinde ayrı olaylarda iki böyle mahkumiyet biriktiren bir CDL sürücüsü şu diskalifikasyonla karşı karşıya kalır:","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"Bir CMV kullanırken elde tutulan bir telefon kullanmak ciddi bir trafik ihlalidir; 3 yıl içinde iki mahkumiyet 60 günlük bir diskalifikasyon getirir (üç tanesi için 120 gün). Kaynak: FMCSA mobile phone rule (49 CFR 392.82); Idaho Code 49-335; 49 CFR 383.51."},"60":{"q":"Idaho CDL kılavuzunun demiryolu geçidi kurallarına göre, plakart taşıyan bir HazMat aracının veya yolcu taşıyan bir otobüsün sürücüsü en yakın raya ne kadar mesafede durmalıdır?","options":["50 feet içinde ancak 15 feet'ten az olmamak üzere","100 feet içinde ancak 50 feet'ten az olmamak üzere","25 feet içinde ancak 5 feet'ten az olmamak üzere","75 feet içinde ancak 25 feet'ten az olmamak üzere"],"explanation":"Idaho, Idaho CDL Kılavuzu'nda benimsenen federal standardı (49 CFR 392.10) izler: yolcu taşıyan otobüsler ve plakart taşıyan HazMat araçları en yakın raya 50 feet içinde ancak 15 feet'ten az olmamak üzere durmalıdır. Idaho Code 49-648/49-650 aynı 15 ila 50 feet'lik durma aralığını kullanır. Kaynak: Idaho CDL Kılavuzu (ITD); Idaho Code 49-648."},"61":{"q":"Idaho'da bir otobüs veya plakart taşıyan araç demiryolu geçidinde durmak zorunda olduğunda, aracın herhangi bir kısmı raylar üzerindeyken sürücü hangi eylemi gerçekleştirmelidir?","options":["Geçiş sırasında vites değiştirmemek","Korna çalmaya devam etmek","Geçişin ortasında en düşük vitese geçmek","Dörtlü flaşörleri kapatmak"],"explanation":"Idaho'nun CDL kılavuzu (49 CFR 392.10'u yansıtarak), sürücünün aracı vites değiştirmeden tamamen karşıya çekecek bir vites seçmesini ve aracın herhangi bir kısmı geçidin üzerindeyken vites değiştirmemesini öngörür. Kaynak: Idaho CDL Kılavuzu (ITD); Idaho Code 49-649."},"62":{"q":"Zorunlu durma noktasında rayları geçmeden önce, Idaho CDL kılavuzu bir otobüs veya plakart taşıyan HazMat sürücüsünün araç geçide yaklaşırken hangi uyarı ekipmanını kullanması gerektiğini belirtir?","options":["Dörtlü (tehlike) flaşörlerini etkinleştirmek","Üç adet yansıtıcı üçgen yerleştirmek","Hava kornasıyla uzun bir öttürme yapmak","Uzun far ışıklarını açmak"],"explanation":"Idaho'nun CDL kılavuzu, demiryolu geçitlerinde durması gereken sürücülere, arkadan gelen trafiği uyarmak için yaklaşırken ve dururken dörtlü acil durum flaşörlerini açmalarını talimatlandırır. Kaynak: Idaho CDL Kılavuzu (ITD), demiryolu geçidi bölümü."},"63":{"q":"Idaho'nun 'Move Over' yasası (Idaho Code 49-624) uyarınca, yönünüzde iki veya daha fazla şeritli bir karayolunda flaşörlü ışıklar yakan, durmuş bir polis, acil durum, çekici veya karayolu olay müdahale aracına yaklaştığınızda, şunu yapmalısınız:","options":["Hızı belirlenen limitin altına düşürmek ve, bitişik şeritteyseniz, mümkün olduğunda bitişik olmayan bir şeride geçmek","Belirlenen hızı korumak ancak korna çalmak","Acil durum aracı hareket edene kadar tamamen durmak","Yalnızca bir memur tarafından yönlendirilirse şerit değiştirmek"],"explanation":"Idaho Code 49-624, sürücülerin hızı belirlenen hız limitinin altına düşürmelerini ve çok şeritli bir karayolunda, mümkün olur olmaz bitişik olmayan bir şeride geçerek sabit duran acil durum/çekici/olay müdahale aracının (flaşörlü ışıklarla) bitişiğindeki şeridi boşaltmalarını gerektirir. Kaynak: Idaho Code 49-624."},"64":{"q":"Idaho'nun Move Over yasası (49-624) flaşörlü ışıklar yakan sabit duran araçlar için geçerlidir. Aşağıdakilerden hangisi bu yasayla özellikle korunan bir araç türü DEĞİLDİR?","options":["Patlak lastik nedeniyle durmuş özel bir binek otomobil","Bir çekici kamyon","Bir karayolu olay müdahale aracı","Yetkili bir acil durum aracı"],"explanation":"Idaho Code 49-624, flaşörlü ışıklar yakan sabit duran polis araçlarını, yetkili acil durum araçlarını, çekici kamyonları ve karayolu olay müdahale araçlarını korur. Sıradan bir özel binek otomobil Move Over yasasında belirtilmemiştir. Kaynak: Idaho Code 49-624."},"65":{"q":"Her yönde yalnızca bir şeridi olan iki şeritli bir karayolunda, Idaho'nun Move Over yasası, flaşörlü ışıklar yakan sabit duran bir acil durum aracını geçen sürücünün şunu yapmasını gerektirir:","options":["Hızı belirlenen limitin altına düşürmek ve aracı tamamen geçene kadar güvenli bir hızı korumak","Tamamen durmak ve beklemek","Yer açmak için orta çizgiyi geçerek karşı yöndeki şeritlere girmek","Yavaşlamadan belirlenen hızda devam etmek"],"explanation":"Şerit değiştirmenin imkansız olduğu durumlarda (her yönde tek şerit), Idaho Code 49-624 sürücünün hızı belirlenen limitin altına düşürmesini ve sabit duran aracı tamamen geçene kadar güvenli bir hızda dikkatle devam etmesini gerektirir. Kaynak: Idaho Code 49-624."},"66":{"q":"Idaho Code 49-1422 uyarınca, kırmızı görsel sinyalleri etkin durumda olan, durmuş ve karşıdan gelen bir okul otobüsüyle karşılaşan bir aracın sürücüsü, yalnızca karayolu şu özelliğe sahip olduğunda durmak zorunda DEĞİLDİR:","options":["Üçten fazla şerit","İkiden fazla şerit","Boyalı bir orta dönüş şeridi","Herhangi bir genişlikte bölünmüş bir refüj"],"explanation":"Idaho Code 49-1422, üçten (3) fazla şeritli bir karayolundaki karşıdan gelen trafiğin, sinyalleri etkin durumda olan bir okul otobüsüyle karşılaştığında durmak zorunda olmadığını belirtir. Idaho, istisnayı yalnızca bir refüje değil, şerit sayısına (>3 şerit) bağlar. Kaynak: Idaho Code 49-1422."},"67":{"q":"Standart iki şeritli bir Idaho yolunda, kırmızı görsel sinyalleri yanıp sönen durmuş bir okul otobüsüyle karşılaşan VEYA onu geçen bir aracın sürücüsü şunu yapmalıdır:","options":["Otobüse ulaşmadan önce durmak ve sinyaller durana veya otobüs hareket edene kadar devam etmemek","20 mph'ye yavaşlamak ve dikkatle geçmek","Yalnızca çocuklar görünürse durmak","Yalnızca arkadan geçiyorsa durmak, karşılaşıyorsa durmamak"],"explanation":"Idaho Code 49-1422, her iki yönden karşılaşan veya geçen bir sürücünün, 49-915'in görsel sinyallerini gösteren bir okul otobüsüne ulaşmadan önce durmasını ve otobüs harekete geçene veya sinyaller artık etkin olmayana kadar devam etmemesini gerektirir (>3 şeritli karşıdan gelen istisnası hariç). Kaynak: Idaho Code 49-1422."},"68":{"q":"1 Temmuz 2026'ya kadar, Idaho Code 49-654 uyarınca, 26.000 lbs üzerindeki beş veya daha fazla akslı bir kamyon, ŞEHİR DIŞI bölgelerdeki eyaletler arası karayollarında azami şu hızla sınırlıdır:","options":["Daha hafif araçlar için belirlenen limitten 10 mph daha az","Her yerde tam olarak 65 mph","Daha hafif araçlar için belirlenen limitten 5 mph daha az","Binek otomobillerle aynı hız"],"explanation":"30 Haziran 2026'ya kadar yürürlükte olan Idaho Code 49-654 versiyonuna göre, ağır kamyonlar (5+ aks, 26.000 lbs üzeri) şehir dışı eyaletler arası karayollarında daha hafif araçlardan 10 mph daha az hızı aşamaz. House Bill 664, bu limitleri 1 Temmuz 2026 itibarıyla eşitler. Kaynak: Idaho Code 49-654; HB664 (2026)."},"69":{"q":"1 Temmuz 2026 itibarıyla, Idaho House Bill 664, ağır kamyonlar (5+ aks, 26.000 lbs üzeri) için hız kuralını değiştirir; öyle ki eyaletler arası karayollarında, eyalet karayollarında ve diğer yerlerde azami yasal hızları şu olacaktır:","options":["Beş aksın altındaki ve 26.000 lbs veya daha az araçlarla aynı","Şehir dışı eyaletler arası karayollarında hala binek otomobillerden 10 mph daha az","Belirlenen limitten bağımsız olarak eyalet genelinde 70 mph ile sınırlı","Yalnızca tüm şehir bölgelerinde 65 mph ile sınırlı"],"explanation":"HB664, Idaho Code 49-654'ü değiştirir; öyle ki 1 Temmuz 2026 itibarıyla ağır kamyonlar daha hafif araçlarla aynı belirlenen azami hız limitlerine tabi olur ve önceki 10 mph daha az ile 65 mph şehir kamyon sınırları kaldırılır. Kaynak: Idaho HB664 (2026); Idaho Code 49-654."},"70":{"q":"Idaho Code 49-654 uyarınca, Idaho eyaletler arası karayollarında (bir mühendislik çalışmasının ardından, daha hafif araçlar için) belirlenebilecek azami hız limiti şudur:","options":["80 mph","75 mph","70 mph","85 mph"],"explanation":"Idaho Code 49-654, eyaletler arası karayollarında 75 mph'lik bir taban belirler ancak bir mühendislik ve trafik çalışmasının ardından ITD'nin limiti eyaletler arası karayollarında 80 mph'ye kadar yükseltmesine izin verir; 80 mph, birçok kırsal Idaho eyaletler arası karayolu kesiminde belirlenmiştir. Kaynak: Idaho Code 49-654; ITD."},"71":{"q":"Idaho Code 49-654 uyarınca, belirlenmiş bir limit yoksa, herhangi bir konut, ticari veya şehir bölgesinde varsayılan azami hız şudur:","options":["35 mph","25 mph","30 mph","20 mph"],"explanation":"Idaho Code 49-654, aksi belirtilmedikçe herhangi bir konut, ticari veya şehir bölgesinde varsayılan azami hızı 35 mph olarak belirler. Kaynak: Idaho Code 49-654."},"72":{"q":"Idaho Code 49-630, Idaho karayollarındaki şerit kullanımını düzenler. Yüklü bir kamyonun yokuş çıkması gibi, normal trafik akışından daha yavaş hareket eden bir araç şunu yapmalıdır:","options":["Sağ şeritte veya sağ kenara mümkün olduğunca yakın sürmek","Trafiği dengelemek için orta şeridi kullanmak","Sağ şeridi katılım için boş tutmak amacıyla sol şeritte kalmak","Sinyal verdiği sürece herhangi bir şeridi seçmek"],"explanation":"Idaho Code 49-630, normal trafik hızından daha düşük hızla ilerleyen herhangi bir aracın, geçiş yaparken veya sola dönüşe hazırlanırken hariç olmak üzere, mevcut sağ şeritte veya sağ bordüre/kenara mümkün olduğunca yakın sürülmesini gerektirir. Kaynak: Idaho Code 49-630."},"73":{"q":"Bölünmüş veya tek yönlü bir yolda, Idaho CDL kılavuzu, durmuş bir ticari aracın üç acil durum uyarı cihazını yaklaşan trafiğe doğru hangi mesafelere yerleştirmesini öngörür?","options":["Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet","Yaklaşan trafiğe doğru 10 feet, 50 feet ve 100 feet","Yaklaşan trafiğe doğru 15 feet, 100 feet ve 300 feet","Yaklaşan trafiğe doğru 25 feet, 100 feet ve 500 feet"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, Idaho CDL kılavuzu (49 CFR 392.22 uyarınca) uyarı cihazlarının araçtan yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet mesafelere yerleştirilmesini gerektirir. Kaynak: Idaho CDL Kılavuzu (ITD)."},"74":{"q":"İki şeritli, çift yönlü bir Idaho yolunda, Idaho CDL kılavuzu, durmuş bir CMV için gerekli üç uyarı cihazının nereye yerleştirileceğini söyler?","options":["Aracın 10 feet içinde ve onun 100 feet arkasında ve 100 feet önünde","Üçü de aracın arkasının 10 feet içinde","Yalnızca arkada 50 feet, 200 feet ve 500 feet'te","Aracın 100 feet, 200 feet ve 300 feet arkasında"],"explanation":"İki şeritli, çift yönlü bir yolda Idaho CDL kılavuzu (49 CFR 392.22 uyarınca) bir cihazın trafik tarafında aracın 10 feet içine, birinin yaklaşık 100 feet arkasına ve birinin yaklaşık 100 feet önüne, banket üzerinde veya durulan şeritte yerleştirilmesini gerektirir. Kaynak: Idaho CDL Kılavuzu (ITD)."},"75":{"q":"Bir CMV, bir tepe, viraj veya başka bir engele 500 feet mesafede bir Idaho iki şeritli yolunda durmuşsa, Idaho CDL kılavuzu şunu söyler:","options":["Sürücülere daha fazla uyarı vermek için arka uyarı cihazını 100 ile 500 feet arasına geri taşımak","Üç üçgeni de standart 10/100/100 feet noktalarında bırakmak","Üç cihazı da doğrudan aracın arkasına üst üste koymak","Üçgenleri kaldırmak ve yalnızca flaşörlere güvenmek"],"explanation":"Görüş mesafesini kısıtlayan bir tepe, viraj veya engele 500 feet mesafede durduğunda, Idaho CDL kılavuzu (49 CFR 392.22 uyarınca) en arka uyarı cihazının yol boyunca araçtan 100 ila 500 feet uzaktaki bir noktaya geri taşınmasını talimatlandırır, böylece yaklaşan sürücüler yeterli uyarı alır. Kaynak: Idaho CDL Kılavuzu (ITD)."},"76":{"q":"Idaho CDL kılavuzu, durmuş bir CMV'nin uyarı cihazlarını (fişek veya üçgen) bir karayolunda durduktan sonra hangi süre içinde sergilemesini gerektirir?","options":["10 dakika","5 dakika","15 dakika","30 dakika"],"explanation":"Idaho CDL kılavuzu (49 CFR 392.22 uyarınca) acil durum uyarı cihazlarının bir karayolunun gidiş kısmında veya banketinde durduktan sonra 10 dakika içinde yerleştirilmesini gerektirir. Kaynak: Idaho CDL Kılavuzu (ITD)."},"77":{"q":"Lewiston Grade ve White Bird Grade gibi US-95 yokuşları, Idaho'da dik dağ inişleriyle dikkat çeker. Bu yokuşlar fren kabiliyetini kaybeden kamyonlar için hangi güvenlik özelliğini sağlar?","options":["Acil durum kaçış (kontrol dışı kamyon) rampaları","Ağır kamyonlar için zorunlu gişeler","Etrafından dolaşan eyalet çapında bir kamyon güzergahı yasağı","Yola yerleştirilmiş elektronik hız regülatörleri"],"explanation":"Idaho'nun dik US-95 dağ yokuşları (Lewiston Grade, White Bird Grade), frenlerini kaybeden bir aracı durdurmak için uzun çakıl yatakları kullanan acil durum kaçış/kontrol dışı kamyon rampalarıyla donatılmıştır. ITD, bu inişler için önceden uyarı tabelaları yerleştirir. Kaynak: Idaho Transportation Department (ITD), US-95 kaçış rampası projeleri."},"78":{"q":"Idaho'nun eyalet karayolu sisteminde hiçbir paralı yolu veya paralı finanse edilen eyaletler arası köprüsü yoktur. Idaho boyunca bir güzergah planlayan bir CDL sürücüsü için bu şu anlama gelir:","options":["Idaho'nun eyaletler arası karayollarında veya eyalet karayollarında ücret alınmaz","Yalnızca Snake Nehri üzerindeki eyaletler arası köprülerde ücret alınır","Ağır kamyonlar I-84'te mil başına ücret öder","Ücretler yalnızca Boise metropol çevre yolunda geçerlidir"],"explanation":"Idaho, kamuya açık karayolu sisteminde hiçbir paralı yol veya paralı köprü işletmez; eyaletler arası ve eyalet karayolları ücretsizdir. CDL sürücüleri bunun yerine ücretler etrafında değil, ITD tarafından yönetilen aşırı boyut/aşırı ağırlık izni ve kısıtlı güzergah gereksinimleri etrafında plan yapmalıdır. Kaynak: Idaho Transportation Department (ITD)."},"79":{"q":"Idaho'da Ticari Sürücü Belgesi düzenlemekten sorumlu Eyalet Sürücü Belgelendirme Kurumu hangi kurumdur?","options":["Idaho Transportation Department (ITD)","Idaho State Police Commercial Vehicle Services","Federal Motor Carrier Safety Administration","Idaho Department of Motor Vehicle Safety"],"explanation":"Idaho Transportation Department (ITD) DMV, Idaho'nun Eyalet Sürücü Belgelendirme Kurumu'dur ve CDL düzenler. Kaynak: ITD DMV Commercial Driver's License (CDL) sayfası; ITD 'Ten Steps to Getting an Idaho CDL.'"},"80":{"q":"Idaho'da bir CDL başvuru sahibi başvuru yapmak, yazılı testleri vermek ve belgenin düzenlenmesini sağlamak için aslında nereye gider?","options":["Özel olarak işletilen bir ITD test franchise'ı","Bir ilçe şerifinin sürücü belgelendirme (DMV) ofisi","Bir FMCSA saha ofisi","Yalnızca Boise'deki ITD genel merkezi"],"explanation":"Idaho sürücü belgelendirmesi ilçe tarafından yönetilir: başvuru sahipleri, CDL başvurusunu, bilgi testlerini ve belge düzenlemeyi yürüten bir ilçe şerifinin sürücü belgelendirme ofisine gider; ITD ise kayıtları işler. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 4."},"81":{"q":"Belge almadan önce, her yeni Idaho CDL başvuru sahibi pratik yapmak ve beceri testini vermek için önce hangi belgeyi edinmelidir?","options":["Bir Ticari Öğrenci Belgesi (CLP)","Bir Class D öğrenim belgesi","Bir federal eyaletler arası yetki kartı","Bir geçici ticari onay"],"explanation":"Idaho, başvuru sahiplerinin ticari bir belge almak veya yükseltmek ve beceri testinden önce kamuya açık yollarda pratik yapmak için bir Ticari Öğrenci Belgesi (CLP) edinmesini gerektirir. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 5."},"82":{"q":"Bir Idaho Ticari Öğrenci Belgesi (CLP) düzenlendikten sonra ne kadar süre geçerlidir?","options":["180 gün","90 gün","İki yıl","Bir yıl"],"explanation":"Idaho'nun CLP'si bir yıl geçerlidir (Idaho'nun süresi bazı eyaletlerin kullandığı 180 günlük asgariden farklıdır). Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 5."},"83":{"q":"Idaho'da uygulanan federal kurallar uyarınca, bir başvuru sahibi CDL beceri testini vermesine izin verilmeden önce bir CLP'yi ne kadar süre elinde tutmalıdır?","options":["En az 30 gün","En az 10 gün","En az 14 gün","En az 60 gün"],"explanation":"Idaho tarafından benimsenen FMCSA kuralları, yalnızca mevcut bir CDL yükseltilirken bile, bir beceri testi vermeden önce CLP'nin en az 14 gün elde tutulmasını gerektirir. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 5 ve 9."},"84":{"q":"Idaho CDL beceri testi hangi üç bölümden oluşur?","options":["Yazılı test, göz muayenesi ve yol testi","Hava freni testi, geri gitme testi ve tartı istasyonu testi","Sefer öncesi muayene, simülatör testi ve gece sürüşü","Sefer öncesi muayene, temel araç kontrolü ve yolda sürüş"],"explanation":"Idaho, FMCSA üç bölümlü beceri testini izler: sefer öncesi (araç) muayenesi, temel araç kontrolü (kapalı pist manevraları) ve yolda sürüş testi. Kaynak: ITD CDL kılavuzu; ITD 'Ten Easy Steps to a C.D.L.' Adım 6-9."},"85":{"q":"Idaho'da test gününde, bir başvuru sahibine sefer öncesi araç muayenesini tamamlaması için ne kadar süre verilir?","options":["45 dakika","15 dakika","60 dakika","30 dakika"],"explanation":"Idaho, test gününde sefer öncesi muayene bölümünü tamamlamak için 45 dakika tanır; hatalı bir fren kontrolü yaygın bir başarısızlık nedenidir. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 6."},"86":{"q":"Idaho temel kontrol (geri gitme) bölümünde, tüm başvuru sahiplerinden hangi iki manevra istenir?","options":["Dar yola park ve paralel park","Düz çizgide geri gitme ve dar yola park","Düz çizgide geri gitme ve ofset geri gitme","Paralel park ve serpantin"],"explanation":"Idaho, her başvuru sahibinden düz çizgide geri gitme ve ofset geri gitmeyi ister; ardından muayene memuru ya dar yola park ya da paralel parkı seçer. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 7 (Bölüm 12 manevraları)."},"87":{"q":"Bir Idaho CDL başvuru sahibinin beceri testini verebilmek için kayıtlı bir sağlayıcıdan hangi eğitimi tamamlaması gerekir?","options":["Eyalet onaylı bir savunmacı sürüş kursu","Bir ITD güvenlik oryantasyon semineri","Bir OSHA ticari araç kursu","Giriş Düzeyi Sürücü Eğitimi (ELDT)"],"explanation":"7 Şubat 2022'den bu yana, başvuru sahipleri gerekli beceri testlerini vermeden önce FMCSA'nın Eğitim Sağlayıcı Kayıt Defteri'ndeki (Training Provider Registry) bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi'ni (ELDT) tamamlamalıdır. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 5; FMCSA ELDT kuralı."},"88":{"q":"Idaho'nun CDL öz-belgelendirmesinde, bir başvuru sahibi kaç sürüş kategorisinden seçim yapmalıdır?","options":["İki","Üç","Beş","Dört"],"explanation":"Idaho CDL sahipleri dört kategoriden birine öz-belgelendirme yapmalıdır: eyaletler arası istisnasız, eyaletler arası istisnalı, eyalet içi istisnasız veya eyalet içi istisnalı. Kaynak: ITD 'Medical Cards & Self Certification Categories' tablosu; FMCSA 49 CFR 383.71."},"89":{"q":"Idaho tarafından, çoğu CDL sürücüsü için tıbbi kart gerektiren, eyalet sınırlarını aşarak sürüşe izin veren 'altın standart' olarak tanımlanan öz-belgelendirme kategorisi hangisidir?","options":["Eyaletler arası istisnalı","Eyalet içi istisnasız","Eyaletler arası istisnasız","Eyalet içi istisnalı"],"explanation":"Idaho, eyaletler arası istisnasız kategorisini 'altın standart' olarak etiketler: sürücü tıbbi olarak belgelendirilmiştir ve eyalet sınırlarını aşabilir ve her şeyi taşıyabilir. Kaynak: ITD 'Medical Cards & Self Certification Categories' tablosu."},"90":{"q":"Hangi Idaho öz-belgelendirme kategorisi, tüm sürüş Idaho içinde kalsa bile geçerli bir DOT tıbbi sertifikası gerektirir?","options":["Eyalet içi istisnalı","Eyalet içi istisnasız","Eyaletler arası istisnalı","CDL olmayan istisnalı"],"explanation":"Eyalet içi istisnasız sürücüler Idaho içinde kalır ancak yine de tıbbi olarak belgelendirilir (örneğin, muafiyet kapsamında olmayan emtia taşıma) ve bu bir 'K' (yalnızca eyalet içi) kısıtlaması ekler. Kaynak: ITD 'Medical Cards & Self Certification Categories' tablosu."},"91":{"q":"Bir sürücü bir eyalet içi kategoriye öz-belgelendirme yaptığında, Idaho bir CDL'ye hangi kısıtlamayı ekler?","options":["Bir 'L' kısıtlaması (hava freni yok)","Bir 'K' kısıtlaması (yalnızca eyalet içi işletim)","Bir 'E' kısıtlaması (yalnızca otomatik şanzıman)","Bir 'O' kısıtlaması (beşinci teker yok)"],"explanation":"Her iki eyalet içi kategoriye (istisnalı veya istisnasız) öz-belgelendirme yapmak, sürücüyü eyalet içi işletimle sınırlayan bir 'K' kısıtlaması ekler. Kaynak: ITD 'Medical Cards & Self Certification Categories' tablosu; 49 CFR 383.95."},"92":{"q":"İstisnasız bir Idaho CDL sahibi yeni bir DOT tıbbi muayene memuru sertifikası alır. Bununla ne yapmalıdır?","options":["Sürüş kaydına eklenmesi için ilçe DMV/ITD'ye bir kopya sunmak","Yalnızca yol kenarı denetimleri için kamyonda tutmak","Orijinalini Washington, D.C.'deki FMCSA'ya postalamak","Eyalet yerine işvereniyle birlikte dosyalamak"],"explanation":"İstisnasız CDL sahipleri, sürüş kaydına işlenmesi için ME sertifikasının bir kopyasını alındığında ve her yenilemede ilçe DMV/ITD'ye sunmalıdır (sağlamalıdır). Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 4."},"93":{"q":"Bir Idaho CDL için kullanılan bir DOT tıbbi muayene memuru sertifikası en fazla ne kadar süre için düzenlenebilir?","options":["12 aya kadar","36 aya kadar","24 aya kadar","48 aya kadar"],"explanation":"Bir DOT fizik/tıbbi muayene memuru sertifikası 24 aya kadar geçerlidir; bir muayene memuru bir tıbbi durumu izlemek için daha kısa bir süre için düzenleyebilir. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 2."},"94":{"q":"Bir Idaho CDL başvuru sahibi için DOT fizik muayenesini yapan tıbbi sağlayıcı nerede listelenmiş olmalıdır?","options":["Idaho Board of Medicine CDL panelinde","National Registry of Certified Medical Examiners'da","ITD onaylı hekimler listesinde","FMCSA taşıyıcı güvenlik listesinde"],"explanation":"Muayeneyi yapan sağlayıcı FMCSA'nın National Registry of Certified Medical Examiners'ında listelenmiş olmalıdır; kayıtlı olmayan bir sağlayıcı kullanmak bir CDL düşürülmesine yol açabilir. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 2; ITD tıbbi sertifika bildirimi."},"95":{"q":"Bir Idaho başvuru sahibinin geçtiği CDL bilgi (yazılı) test sonuçları, tüm yazılı testlerin yeniden alınması gerekmeden önce ne kadar süre geçerli kalır?","options":["Geçilen tarihten itibaren bir yıl","Geçilen tarihten itibaren altı ay","Geçilen tarihten itibaren iki yıl","Geçilen tarihten itibaren 90 gün"],"explanation":"Bilgi testi sonuçları geçilen tarihten itibaren bir yıl geçerli kalır; CDL o yıl içinde alınmazsa, tüm yazılı testlerin yeniden alınması gerekir. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 4."},"96":{"q":"Bir Idaho başvuru sahibi bir CDL bilgi (yazılı) testinde başarısız olursa, bunu en erken ne zaman tekrar alabilir?","options":["Aynı gün","Üç gün sonra","Yedi gün sonra","On dört gün sonra"],"explanation":"Bir yazılı testte başarısız olan bir başvuru sahibi üç gün sonra yeniden test verebilir (ve test başına ücreti yeniden öder). Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 4."},"97":{"q":"Beceri testini geçtikten sonra, yeni düzenlenmiş standart bir Idaho CDL'nin geçerlilik süresi nedir?","options":["Yalnızca iki yıl","Yalnızca bir yıl","Dört yıl (sekiz yıllık bir seçenek de mevcuttur)","Sabit altı yıl"],"explanation":"Idaho CDL'yi dört yıl için düzenler; ITD ayrıca sekiz yıllık bir seçenek sunar. Sürücü, geçtikten sonra belgenin düzenlenmesi için ilçe DMV'sine geri dönmelidir. Kaynak: ITD 'Ten Steps to Getting an Idaho CDL' Adım 10."},"98":{"q":"Idaho'nun muayene memuru tarafından alınan CDL beceri testi ücreti, Idaho Code uyarınca nasıl düzenlenir?","options":["Her eyalette sabit, federal olarak belirlenmiş bir tutardır","Tüm ilk kez başvuranlar için muaftır","Yalnızca başvuru sahibinin eğitim okulu tarafından belirlenir","Üst sınırı vardır ve test başına Idaho Code tarafından belirlenen bir azamiyi aşamaz"],"explanation":"Muayene memurunca belirlenen beceri testi ücreti, küçük ilçe payından ayrı olarak, Idaho Code tarafından üst sınıra tabidir (test başına yasal azamiyi aşamaz). Tam dolar tutarları değişebilir. Kaynak: ITD 'Ten Easy Steps to a C.D.L.' Adım 9."}},"es":{"0":{"q":"En las carreteras de Idaho, ¿cuál es el ancho máximo legal de un vehículo, incluida su carga?","options":["8 pies 6 pulgadas","8 pies 0 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"El Idaho Code 49-1010 limita el ancho total de cualquier vehículo, incluida su carga, a 8 pies 6 pulgadas (102 inches). Las cargas más anchas requieren un permiso de sobredimensión. Fuente: Idaho Code 49-1010 (Tamaño de Vehículos y Cargas)."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo y su carga en las carreteras de Idaho?","options":["13 pies 6 pulgadas","14 pies","15 pies","13 pies"],"explanation":"El Idaho Code 49-1010 establece la altura máxima de un vehículo, incluida la carga, en 14 pies. Las cargas más altas que 14 pies necesitan un permiso de sobrealtura. Fuente: Idaho Code 49-1010."},"2":{"q":"¿Cuál es el peso bruto máximo sobre un solo eje en Idaho?","options":["18,000 libras","22,400 libras","20,000 libras","21,500 libras"],"explanation":"El Idaho Code 49-1001 establece el peso bruto máximo de un solo eje en 20,000 libras. Fuente: Idaho Code 49-1001 (Cargas Brutas Permitidas)."},"3":{"q":"¿Cuál es el peso bruto máximo permitido sobre un eje tándem en Idaho?","options":["34,000 libras","36,000 libras","32,000 libras","40,000 libras"],"explanation":"Según el Idaho Code 49-1001, un conjunto de ejes tándem puede transportar hasta 34,000 libras, coincidiendo con el estándar federal. Fuente: Idaho Code 49-1001."},"4":{"q":"¿Cuál es el peso bruto máximo del vehículo o de la combinación permitido en la porción de Idaho del sistema federal de carreteras interestatales y de defensa de EE. UU. sin un permiso?","options":["80,000 libras","105,500 libras","90,000 libras","129,000 libras"],"explanation":"El Idaho Code 49-1001 limita el peso bruto del vehículo o de la combinación en las carreteras federales interestatales y de defensa a 80,000 libras, de acuerdo con la ley federal. Fuente: Idaho Code 49-1001."},"5":{"q":"En las carreteras estatales generales (no interestatales) de Idaho, ¿cuál es el peso bruto máximo del vehículo o de la combinación permitido bajo el estatuto básico antes de recurrir a un permiso especial por exceso de peso?","options":["80,000 libras","129,000 libras","100,000 libras","105,500 libras"],"explanation":"El Idaho Code 49-1001 permite un peso bruto máximo del vehículo o de la combinación de 105,500 libras, excepto que el límite baja a 80,000 libras en las carreteras federales interestatales y de defensa. Fuente: Idaho Code 49-1001."},"6":{"q":"¿Cuál es el peso bruto máximo permitido sobre una sola rueda en Idaho?","options":["8,000 libras","12,000 libras","10,000 libras","6,000 libras"],"explanation":"El Idaho Code 49-1001 establece el peso bruto máximo de una sola rueda en 10,000 libras. Fuente: Idaho Code 49-1001."},"7":{"q":"Idaho utiliza la fórmula federal de peso de puentes (bridge weight formula) para determinar el peso máximo permitido sobre un grupo de ejes consecutivos. ¿Qué fórmula adopta el Idaho Code?","options":["W = 500((LN/N-1) + 12N + 36)","W = 1000(L + N + 20)","W = 34,000 + (N x 12)","W = 250(LN + 12 + 36N)"],"explanation":"El Idaho Code 49-1001(1) adopta la fórmula federal de puentes W = 500((LN/N-1) + 12N + 36), donde W es el peso máximo, L es la distancia en pies entre los extremos del grupo de ejes y N es el número de ejes. Fuente: Idaho Code 49-1001(1)."},"8":{"q":"En la fórmula de puentes de Idaho, ¿qué representa la variable 'L'?","options":["La capacidad legal de carga del remolque","La distancia en pies entre los extremos de un grupo de dos o más ejes consecutivos","Solo la longitud del grupo de un solo eje más largo","El peso bruto registrado del vehículo"],"explanation":"En la fórmula W = 500((LN/N-1) + 12N + 36), 'L' es la distancia en pies entre los extremos de cualquier grupo de dos o más ejes consecutivos, 'N' es el número de ejes y 'W' es el peso máximo. Fuente: Idaho Code 49-1001(1)."},"9":{"q":"Dos conjuntos consecutivos de ejes tándem pueden transportar cada uno 34,000 libras en Idaho solo si la distancia total entre el primer y el último eje de esos conjuntos tándem es de al menos cuántos pies?","options":["30 pies","36 pies","40 pies","34 pies"],"explanation":"El Idaho Code 49-1001(1)(b) permite que dos conjuntos tándem consecutivos transporten 34,000 libras cada uno siempre que la distancia entre el primer y el último eje de esos conjuntos sea de 36 pies o más. Fuente: Idaho Code 49-1001(1)(b)."},"10":{"q":"Un semirremolque que opera en rutas que forman parte de la red nacional en Idaho no puede exceder qué longitud?","options":["48 pies","53 pies","57 pies","45 pies"],"explanation":"El Idaho Code 49-1010 limita un semirremolque que opera en la red nacional (y las rutas de acceso relacionadas) a 53 pies de longitud. Fuente: Idaho Code 49-1010."},"11":{"q":"Según el Idaho Code, una carga sobre un vehículo generalmente no puede extenderse más allá de la parte delantera del vehículo más de cuántos pies?","options":["3 pies","4 pies","6 pies","2 pies"],"explanation":"El Idaho Code 49-1010 prohíbe que una carga se extienda más allá de la parte delantera de un vehículo más de 4 pies. Fuente: Idaho Code 49-1010."},"12":{"q":"Una combinación de vehículos que transporta una carga reducible puede operar con un peso bruto superior a 105,500 libras en Idaho, pero sin exceder qué peso, y solo en rutas no interestatales designadas con el registro y el permiso adecuados?","options":["129,000 libras","117,000 libras","140,000 libras","125,500 libras"],"explanation":"El Idaho Code 49-1001(1)(c) permite cargas reducibles superiores a 105,500 libras pero sin exceder 129,000 libras en carreteras no interestatales cuando el vehículo está registrado, cumple con la fórmula de peso y las restricciones de longitud, y opera en rutas designadas según el Idaho Code 49-1004. Fuente: Idaho Code 49-1001(1)(c) y 49-1004."},"13":{"q":"¿Quién emite el permiso anual de ruta especial que autoriza a una combinación registrada a transportar cargas reducibles entre 105,501 y 129,000 libras en Idaho?","options":["El sheriff de cada condado de la ruta","La Federal Highway Administration","El Idaho Transportation Department o, a su discreción, una agencia local de carreteras públicas","Cualquier estación de pesaje de una parada de camiones comercial"],"explanation":"El Idaho Code 49-1004 dispone que los permisos de ruta especial para cargas desde 105,501 hasta 129,000 libras son emitidos por el Idaho Transportation Department, o a su discreción por una agencia local de carreteras públicas, en rutas designadas por el departamento o las autoridades locales. Fuente: Idaho Code 49-1004."},"14":{"q":"¿Cuál de las siguientes opciones se requiere generalmente antes de que un vehículo que excede los límites legales de tamaño o peso de Idaho pueda circular por la carretera?","options":["Un permiso válido de sobredimensión/sobrepeso obtenido antes del traslado","Un cambio a una CDL Clase A","Una exención federal de la FMCSA","Solo una autorización verbal de un oficial del puerto de entrada"],"explanation":"El Idaho Code 49-1004 y las reglas de permisos del ITD requieren un permiso de sobredimensión o sobrepeso, obtenido antes del traslado, para operar un vehículo que excede los límites legales de tamaño o peso; el permiso debe llevarse en el vehículo. Fuente: Idaho Code 49-1004; reglas de permisos del ITD (IDAPA 39.03.03)."},"15":{"q":"La ley de Idaho otorga una variación de peso (una tabla separada y más generosa de espaciado de ejes) en carreteras no interestatales a los vehículos que transportan ciertas mercancías. ¿Qué grupo de mercancías está cubierto?","options":["Troncos, madera para pulpa, madera en bruto, postes, minerales, arena y grava, y productos agrícolas incluido el ganado","Comestibles refrigerados y bebidas embotelladas","Automóviles nuevos y vehículos recreativos","Solo materiales peligrosos y combustible a granel"],"explanation":"El Idaho Code 49-1001(2) ofrece una tabla especial de carga permitida para vehículos que transportan troncos, madera para pulpa, stull, madera en bruto, postes o pilotes; minerales, concentrados, arena y grava y agregados a granel; o productos agrícolas incluido el ganado. Fuente: Idaho Code 49-1001(2)."},"16":{"q":"Las asignaciones especiales de peso para troncos, minerales, arena/grava y productos agrícolas en el Idaho Code 49-1001(2) NO se aplican una vez que el peso bruto total se pretende exceda qué cifra, según lo declarado por el operador?","options":["80,000 libras","79,000 libras","105,500 libras","84,000 libras"],"explanation":"El Idaho Code 49-1001(2) establece que las asignaciones de peso por mercancía no se aplican si el peso bruto total se pretende exceda las 79,000 libras según lo declarado por el operador. Fuente: Idaho Code 49-1001(2)."},"17":{"q":"En un puerto de entrada de Idaho, un vehículo cargado no puede continuar más allá de la báscula cuando el peso de un solo eje excede el límite máximo por cuánto?","options":["500 libras o más","1,000 libras o más","2,000 libras o más","5,000 libras o más"],"explanation":"El Idaho Code 49-1001(8) dispone que un vehículo no puede continuar más allá de un puerto de entrada cuando un solo eje excede el máximo por 2,000 libras o más, o cuando el peso bruto o del grupo de ejes excede el máximo por un 7% o más. Fuente: Idaho Code 49-1001(8)."},"18":{"q":"En un puerto de entrada de Idaho, ¿en qué porcentaje por encima del peso bruto o del grupo de ejes máximo permitido se detendrá un vehículo y se le exigirá ponerse en conformidad antes de continuar?","options":["7 por ciento o más","5 por ciento o más","10 por ciento o más","15 por ciento o más"],"explanation":"El Idaho Code 49-1001(8) exige que un vehículo se ponga en conformidad en la báscula cuando su peso bruto vehicular o una combinación de ejes excede el peso máximo permitido por un 7 por ciento o más (el umbral de un solo eje es de 2,000 libras). Fuente: Idaho Code 49-1001(8)."},"19":{"q":"Idaho requiere escoltas (vehículos piloto/de bandera) para las cargas con permiso de sobreancho. ¿A partir de qué ancho de carga Idaho generalmente requiere al menos un vehículo piloto/escolta?","options":["Más de 8 pies 6 pulgadas de ancho","Más de 10 pies de ancho","Más de 12 pies de ancho","Más de 16 pies de ancho"],"explanation":"Según las reglas de traslado de sobredimensión del ITD, una carga de más de 12 pies de ancho generalmente requiere un vehículo piloto/escolta, y las cargas de más de 14 pies de ancho requieren dos. Se requieren banderas en las esquinas de las cargas de sobreancho, y un letrero de OVERSIZE LOAD y luces ámbar en las escoltas. Fuente: reglas de permisos del ITD (IDAPA 39.03.05 / requisitos de piloto-escolta)."},"20":{"q":"En Idaho, se requiere una CDL para operar cualquier vehículo individual con una Clasificación de Peso Bruto Vehicular (GVWR) de cuántas libras o más (sin remolcar nada de más de 10,000 lbs)?","options":["16,001 libras","26,001 libras","33,001 libras","10,001 libras"],"explanation":"Idaho adopta el umbral federal: se requiere una CDL Clase B para cualquier vehículo individual con una GVWR de 26,001 lbs o más (Idaho CDL Manual, ITD; 49 CFR 383.91)."},"21":{"q":"¿Qué clase de CDL de Idaho se requiere para conducir un vehículo de combinación con una GCWR de 26,001 lbs o más donde la(s) unidad(es) remolcada(s) excede(n) 10,000 lbs de GVWR?","options":["Clase C","Clase B","Clase A","Clase D"],"explanation":"Una CDL Clase A cubre los vehículos de combinación con una GCWR de 26,001 lbs o más siempre que la GVWR del o los vehículos remolcados sea superior a 10,000 lbs (Idaho CDL Manual, ITD)."},"22":{"q":"Según las reglas de Idaho, un vehículo diseñado para transportar 16 o más pasajeros (incluido el conductor) pero por debajo de los límites de peso de Clase A/B requiere qué clase de CDL?","options":["Clase C","Clase A","Clase B","No se requiere CDL"],"explanation":"Se requiere una CDL Clase C para los vehículos que no cumplen los criterios de Clase A o B pero están diseñados para transportar 16 o más pasajeros incluido el conductor, o que transportan materiales peligrosos que requieren cartel (placard) (Idaho CDL Manual, ITD)."},"23":{"q":"¿Qué letra de endoso asigna Idaho a la autorización para conducir vehículos cisterna (tanque) que transportan líquidos o gases a granel?","options":["T","N","X","H"],"explanation":"El endoso N es para vehículos cisterna. (T = dobles/triples, H = hazmat, X = combinación de cisterna y hazmat). Fuente: Idaho CDL Manual, ITD; 49 CFR 383.93."},"24":{"q":"En Idaho, el endoso 'T' autoriza al titular a operar qué tipo de vehículo?","options":["Vehículos cisterna","Vehículos que transportan materiales peligrosos","Remolques dobles y triples","Vehículos que transportan 16 o más pasajeros"],"explanation":"El endoso T cubre los remolques dobles y triples y requiere aprobar únicamente un examen de conocimientos (Idaho CDL Manual, ITD; 49 CFR 383.93)."},"25":{"q":"Para obtener un endoso HazMat (H) de Idaho, el solicitante debe aprobar un examen de conocimientos y además completar qué requisito federal adicional?","options":["Un examen de habilidades al volante","Una evaluación de amenaza de seguridad de la TSA (verificación de antecedentes)","Una solicitud de exención de visión","Un segundo examen médico"],"explanation":"Idaho exige que el solicitante del endoso H apruebe un examen de conocimientos y supere una Evaluación de Amenaza de Seguridad de la TSA (verificación de antecedentes basada en huellas dactilares) bajo la USA PATRIOT Act (Idaho CDL Manual, ITD; 49 CFR 1572)."},"26":{"q":"En Idaho, antes de emitir un endoso de autobús escolar (S), ¿qué otro endoso debe también poseer u obtener el solicitante?","options":["N (Cisterna)","T (Dobles/Triples)","P (Pasajeros)","H (HazMat)"],"explanation":"El endoso S (autobús escolar) requiere el endoso P (pasajeros), además de un examen de conocimientos y un examen de habilidades en un autobús escolar (Idaho CDL Manual, ITD; 49 CFR 383.123)."},"27":{"q":"¿Qué endoso de CDL de Idaho requiere tanto un examen de conocimientos como un examen de habilidades al volante en un vehículo representativo?","options":["N (Cisterna)","P (Pasajeros)","T (Dobles/Triples)","H (HazMat)"],"explanation":"El endoso P (pasajeros) requiere aprobar un examen de conocimientos y un examen de habilidades en un vehículo de pasajeros; N, T y H son endosos que requieren únicamente examen de conocimientos (Idaho CDL Manual, ITD; 49 CFR 383.93)."},"28":{"q":"¿Cuál es la edad mínima para obtener una CDL de Idaho para conducir un vehículo comercial únicamente dentro de Idaho (intraestatal)?","options":["16 años","18 años","19 años","21 años"],"explanation":"Idaho permite una CDL intraestatal a los 18 años; el solicitante también debe poseer una licencia válida de Clase D de Idaho y tener un año de experiencia de conducción con licencia (Idaho CDL Manual, ITD; Idaho Code 49-305)."},"29":{"q":"¿Qué edad mínima exige Idaho (siguiendo la ley federal) para conducir un vehículo comercial a través de las fronteras estatales (interestatal)?","options":["18 años","19 años","20 años","21 años"],"explanation":"La conducción comercial interestatal requiere una edad mínima de 21 años; un titular de CDL de Idaho de 18 años está restringido a la operación intraestatal (Idaho CDL Manual, ITD; 49 CFR 391.11)."},"30":{"q":"Un endoso HazMat (H) en Idaho no puede emitirse a un solicitante que sea menor de qué edad?","options":["18","19","21","25"],"explanation":"Debido a que el transporte de hazmat con fines comerciales generalmente implica comercio interestatal y una evaluación de la TSA, el endoso H requiere que el solicitante tenga al menos 21 años (Idaho CDL Manual, ITD; 49 CFR 383/1572)."},"31":{"q":"Según las reglas federales adoptadas en Idaho, ¿cuánto tiempo debe poseer un conductor un Permiso de Aprendiz Comercial (CLP) antes de ser elegible para presentar el examen de habilidades de la CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"El CLP debe poseerse durante un mínimo de 14 días antes de poder presentar el examen de habilidades (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"32":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Idaho antes de que deba renovarse?","options":["90 días","180 días","1 año","2 años"],"explanation":"Un CLP de Idaho es válido por 180 días y puede renovarse una vez por 180 días adicionales sin volver a presentar el examen de conocimientos generales (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"33":{"q":"Mientras conduce con un Permiso de Aprendiz Comercial (CLP) de Idaho, el titular siempre debe estar acompañado por qué?","options":["Cualquier adulto con licencia de 25 años o más","Un titular de CDL de la clase/endoso apropiados sentado junto al conductor","Un examinador del DMV","Nadie; se permite conducir solo"],"explanation":"Un titular de CLP puede operar un CMV solo cuando está acompañado por una persona que posee una CDL válida para el tipo de vehículo y está sentada junto al conductor (Idaho CDL Manual, ITD; 49 CFR 383.25)."},"34":{"q":"¿Cuál de los siguientes documentos NO está entre los que un Idaho DMV exige para solicitar una CDL?","options":["Comprobante de identidad","Comprobante de número de Seguro Social","Comprobante de residencia en Idaho y presencia legal","Una carta firmada de un empleador actual"],"explanation":"Idaho exige comprobante de identidad, número de Seguro Social, residencia en Idaho y presencia legal/ciudadanía; no se requiere una carta del empleador (Idaho CDL Manual / requisitos del DMV del ITD)."},"35":{"q":"Desde el 7 de febrero de 2022, un solicitante de CDL de Idaho por primera vez debe completar la Capacitación para Conductores de Nivel Inicial (ELDT) proporcionada por una entidad listada dónde?","options":["El registro de la academia de la Idaho State Police","El FMCSA Training Provider Registry (TPR)","La lista de escuelas del Idaho Transportation Department","Cualquier colegio comunitario acreditado"],"explanation":"La ELDT debe completarse a través de un proveedor listado en el FMCSA Training Provider Registry antes de presentar el examen de habilidades, en vigor desde el 7 de febrero de 2022 (Idaho CDL Manual, ITD; 49 CFR 380 Subpart F)."},"36":{"q":"¿Para cuál de los siguientes la regla de ELDT adoptada por Idaho NO requiere capacitación antes del examen?","options":["Obtener una CDL Clase A por primera vez","Mejorar una CDL Clase B a una CDL Clase A","Renovar una CDL existente sin nuevos endosos","Obtener un endoso HazMat (H) por primera vez"],"explanation":"La ELDT se aplica a las CDL por primera vez, las mejoras de Clase B a A, y los endosos P, S o H por primera vez; una renovación simple sin nuevos privilegios no requiere ELDT (Idaho CDL Manual, ITD; 49 CFR 380)."},"37":{"q":"Al autocertificar el estado médico en Idaho, un conductor que opera únicamente dentro de Idaho pero está exento de los requisitos de tarjeta médica estatal selecciona qué categoría?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Las cuatro categorías de autocertificación son NI, EI, NA y EA; un conductor que opera exclusivamente de forma intraestatal y está exento de la certificación médica estatal selecciona Excepted Intrastate (EA) (Idaho CDL Manual, ITD; 49 CFR 383.71)."},"38":{"q":"Un solicitante de CDL de Idaho que conducirá a través de las fronteras estatales y está sujeto al requisito del examen físico DOT debe autocertificarse en qué categoría?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Un conductor en comercio interestatal sujeto al 49 CFR Part 391 selecciona Non-Excepted Interstate (NI) y debe mantener un certificado válido de examinador médico en archivo (Idaho CDL Manual, ITD; 49 CFR 383.71)."},"39":{"q":"Idaho ofrece una CDL restringida especial válida solo dos veces en la vida para trabajos de servicio relacionados con la agricultura dentro de 150 millas. ¿Cómo se llama?","options":["Una CDL Provisional","Una CDL Estacional (restringida)","Una CDL de Aprendiz","Una CDL de Dificultad Limitada"],"explanation":"La CDL Estacional restringida de Idaho sirve a las industrias de servicio relacionadas con la agricultura, es válida hasta 180 días en un período de 12 meses dentro de 150 millas, y puede obtenerse solo dos veces en la vida (requisitos de CDL del DMV del ITD; Idaho Code Title 49)."},"40":{"q":"Mientras opera un vehículo motorizado comercial en Idaho, se considera que un conductor con CDL está legalmente por encima del límite y sujeto a descalificación con qué concentración de alcohol en sangre (BAC)?","options":["0.04 o más","0.08 o más","0.02 o más","0.10 o más"],"explanation":"Idaho establece el límite de BAC para operar un vehículo motorizado comercial en 0.04 o más (la mitad del límite de 0.08 para conductores no comerciales). Fuente: Idaho Code 49-335; Idaho CDL Manual (ITD)."},"41":{"q":"En Idaho, un titular de CDL condenado por una primera infracción mayor como DUI mientras conduce un CMV sin carteles (placards) es descalificado por al menos cuánto tiempo?","options":["1 año","60 días","6 meses","3 años"],"explanation":"Una primera infracción mayor (DUI, negativa, abandono de la escena, uso de un CMV en un delito grave, etc.) conlleva una descalificación de CDL mínima de 1 año en Idaho. Fuente: Idaho Code 49-335; Idaho CDL Manual."},"42":{"q":"Si un conductor con CDL de Idaho comete una primera infracción mayor (como DUI) mientras el CMV transporta materiales peligrosos que requieren cartel (placard), la descalificación mínima aumenta a:","options":["3 años","1 año","2 años","5 años"],"explanation":"Idaho extiende la descalificación por primera infracción mayor de 1 año a un mínimo de 3 años cuando la infracción ocurre mientras se transportan materiales peligrosos con cartel (placard). Fuente: Idaho Code 49-335; 49 CFR 383.51."},"43":{"q":"Según la ley de Idaho, ¿cuál es el período de descalificación para un titular de CDL condenado por una SEGUNDA infracción mayor (p. ej., un segundo DUI) en un incidente separado?","options":["Descalificación de por vida","10 años","5 años","3 años"],"explanation":"Dos infracciones mayores que surgen de incidentes separados resultan en una descalificación de CDL de por vida en Idaho (reflejando el 49 CFR 383.51), aunque puede estar disponible un programa de reinstalación a los 10 años. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"44":{"q":"Un conductor con CDL de Idaho que se niega a someterse a una prueba probatoria de alcohol o drogas bajo la ley de consentimiento implícito enfrenta una descalificación de CDL de al menos:","options":["1 año","90 días","6 meses","30 días"],"explanation":"Negarse a la prueba requerida de BAC/drogas se trata como una infracción mayor en Idaho, conllevando la misma descalificación de CDL mínima de 1 año que una condena por DUI (3 años si hay hazmat con cartel). Fuente: Idaho Code 49-335 y 18-8002 (consentimiento implícito)."},"45":{"q":"Al conducir por las carreteras de Idaho, se considera que una persona que opera un vehículo motorizado ha dado su consentimiento para las pruebas probatorias de alcohol/drogas. Este principio se conoce como:","options":["Consentimiento implícito","Causa probable","Debido proceso","Revisión administrativa"],"explanation":"La ley de consentimiento implícito de Idaho (Idaho Code 18-8002) considera que todo conductor ha consentido a las pruebas probatorias; la negativa desencadena la descalificación de la CDL y la suspensión de la licencia. Fuente: Idaho Code 18-8002; Idaho CDL Manual."},"46":{"q":"En Idaho, ser condenado por DOS infracciones de tránsito graves en incidentes separados dentro de un período de 3 años mientras se conduce un CMV resulta en una descalificación de CDL de:","options":["60 días","30 días","120 días","90 días"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años descalifican al conductor por al menos 60 días en Idaho. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"47":{"q":"Un conductor con CDL de Idaho condenado por TRES infracciones de tránsito graves en incidentes separados dentro de un período de 3 años es descalificado por:","options":["120 días","60 días","1 año","180 días"],"explanation":"Una tercera infracción de tránsito grave dentro de 3 años eleva la descalificación a al menos 120 días en Idaho. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"48":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE para un titular de CDL de Idaho?","options":["Exceso de velocidad de 15 o más mph por encima del límite señalizado","Exceso de velocidad de 5 mph por encima del límite señalizado","Una infracción de estacionamiento","Una calcomanía de registro vencida"],"explanation":"El exceso de velocidad, definido como 15 mph o más por encima del límite señalizado, es una infracción de tránsito grave en Idaho. Dos o tres dentro de 3 años desencadenan descalificaciones de 60/120 días. Fuente: Idaho Code 49-335; Idaho CDL Manual."},"49":{"q":"¿Cuál de las infracciones a continuación también se cuenta como una infracción de tránsito GRAVE que puede conducir a la descalificación de la CDL en Idaho?","options":["Seguir demasiado de cerca (manejar pegado)","Conducir 3 mph por debajo del límite","No señalizar un giro en una intersección vacía","Una luz trasera rota"],"explanation":"Seguir demasiado de cerca está en la lista de infracciones de tránsito graves de Idaho, junto con la conducción imprudente, los cambios de carril indebidos o erráticos y el exceso de velocidad. Fuente: Idaho Code 49-335; Idaho CDL Manual."},"50":{"q":"Enviar mensajes de texto mientras se conduce un CMV y conducir un CMV sin obtener la CDL adecuada están ambos categorizados por las reglas de Idaho/FMCSA como:","options":["Infracciones de tránsito graves","Infracciones mayores","Infracciones de fuera de servicio (out-of-service)","Infracciones de cruce ferroviario"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV y operar un CMV sin la CDL/clase adecuada son infracciones de tránsito graves (no infracciones mayores), que cuentan para los umbrales de descalificación de 60/120 días. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"51":{"q":"Por una PRIMERA infracción de cruce a nivel entre ferrocarril y carretera cometida mientras se conduce un CMV, un conductor con CDL de Idaho es descalificado por:","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera infracción de cruce a nivel ferroviario conlleva una descalificación de CDL mínima de 60 días en Idaho. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"52":{"q":"Un conductor con CDL de Idaho condenado por una SEGUNDA infracción de cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años es descalificado por:","options":["120 días","60 días","1 año","90 días"],"explanation":"Una segunda infracción de cruce a nivel ferroviario dentro de 3 años resulta en una descalificación mínima de 120 días en Idaho. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"53":{"q":"¿Cuál es el período de descalificación para una TERCERA o posterior infracción de cruce a nivel entre ferrocarril y carretera dentro de un período de 3 años en Idaho?","options":["1 año","120 días","180 días","60 días"],"explanation":"Una tercera o posterior infracción de cruce a nivel ferroviario dentro de 3 años descalifica al conductor con CDL de Idaho por al menos 1 año. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"54":{"q":"Un conductor con CDL de Idaho condenado por una PRIMERA infracción de una orden de fuera de servicio (OOS) mientras conduce un CMV sin hazmat y sin pasajeros es descalificado por al menos:","options":["180 días","60 días","90 días","30 días"],"explanation":"Una primera infracción de una orden de fuera de servicio conlleva una descalificación mínima de 180 días (hasta 1 año) en Idaho. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"55":{"q":"En Idaho, una SEGUNDA infracción de una orden de fuera de servicio en incidentes separados dentro de un período de 10 años resulta en una descalificación de:","options":["2 a 5 años","180 días a 1 año","1 año","3 a 5 años"],"explanation":"Una segunda infracción de una orden OOS dentro de 10 años descalifica al conductor por no menos de 2 años y no más de 5 años en Idaho. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"56":{"q":"Si la PRIMERA infracción de una orden de fuera de servicio de un conductor con CDL de Idaho ocurre mientras transporta materiales peligrosos con cartel (placard) o lleva 16 o más pasajeros, la descalificación mínima es:","options":["180 días, hasta 2 años","60 días, hasta 1 año","30 días, hasta 6 meses","1 año, hasta 3 años"],"explanation":"Cuando una primera infracción OOS involucra hazmat con cartel o 16 o más pasajeros, la descalificación es de no menos de 180 días y no más de 2 años. Fuente: Idaho Code 49-335; 49 CFR 383.51."},"57":{"q":"Además de la descalificación del conductor, un conductor con CDL de Idaho que infringe una orden de fuera de servicio está sujeto a una multa civil federal de al menos:","options":["$2,500 por una primera condena","$1,000 por una primera condena","$500 por una primera condena","$5,000 por una primera condena"],"explanation":"Una infracción de una orden de fuera de servicio conlleva una multa civil de no menos de $2,500 por una primera condena (y no menos de $5,000 por condenas posteriores), además de la descalificación. Fuente: Idaho Code 49-335; 49 CFR 383.53."},"58":{"q":"Según las reglas que se aplican a los conductores de CMV de Idaho, la multa civil máxima que puede enfrentar un CONDUCTOR por enviar mensajes de texto mientras opera un vehículo motorizado comercial es de aproximadamente:","options":["$2,750","$500","$11,000","$1,000"],"explanation":"Un conductor de CMV que envía mensajes de texto mientras conduce puede enfrentar una multa civil de hasta aproximadamente $2,750, mientras que un empleador que lo permite o lo exige puede ser multado con hasta aproximadamente $11,000. Dos condenas en 3 años también conllevan una descalificación de 60 días. Fuente: FMCSA No-Texting Rule (49 CFR 392.80); Idaho CDL Manual."},"59":{"q":"Un conductor con CDL en Idaho que usa un teléfono móvil de mano mientras conduce un CMV y acumula dos de tales condenas en incidentes separados dentro de 3 años enfrenta una descalificación de:","options":["60 días","30 días","120 días","1 año"],"explanation":"Usar un teléfono de mano mientras se conduce un CMV es una infracción de tránsito grave; dos condenas dentro de 3 años conllevan una descalificación de 60 días (120 días por tres). Fuente: FMCSA mobile phone rule (49 CFR 392.82); Idaho Code 49-335; 49 CFR 383.51."},"60":{"q":"Según las reglas de cruces ferroviarios del manual de CDL de Idaho, el conductor de un vehículo con materiales peligrosos (HazMat) que lleva carteles o de un autobús que transporta pasajeros debe detenerse a qué distancia del riel más cercano?","options":["A menos de 50 pies, pero no a menos de 15 pies","A menos de 100 pies, pero no a menos de 50 pies","A menos de 25 pies, pero no a menos de 5 pies","A menos de 75 pies, pero no a menos de 25 pies"],"explanation":"Idaho sigue la norma federal (49 CFR 392.10) adoptada en el Manual de CDL de Idaho: los autobuses que transportan pasajeros y los vehículos con HazMat con carteles deben detenerse a menos de 50 pies, pero no a menos de 15 pies del riel más cercano. Los códigos de Idaho 49-648/49-650 usan la misma franja de detención de 15 a 50 pies. Fuente: Manual de CDL de Idaho (ITD); Idaho Code 49-648."},"61":{"q":"Cuando un autobús de Idaho o un vehículo con carteles debe detenerse en un cruce ferroviario, ¿qué acción debe realizar el conductor mientras cualquier parte del vehículo esté sobre las vías?","options":["No cambiar de marcha mientras cruza","Tocar la bocina de forma continua","Poner la marcha más baja a mitad del cruce","Apagar las luces intermitentes de emergencia"],"explanation":"El manual de CDL de Idaho (que refleja el 49 CFR 392.10) indica que el conductor elija una marcha que permita pasar la unidad completamente al otro lado sin cambiar de marcha, y que no cambie de marcha mientras cualquier parte del vehículo esté sobre el cruce. Fuente: Manual de CDL de Idaho (ITD); Idaho Code 49-649."},"62":{"q":"Antes de cruzar las vías en una detención obligatoria, el manual de CDL de Idaho indica que el conductor de un autobús o de un vehículo con HazMat con carteles debe usar qué equipo de advertencia a medida que el vehículo se acerca al cruce?","options":["Encender las luces intermitentes (de emergencia) de cuatro direcciones","Colocar tres triángulos reflectantes","Tocar un toque largo con la bocina de aire","Encender las luces altas de los faros"],"explanation":"El manual de CDL de Idaho indica a los conductores que deben detenerse en los cruces ferroviarios que enciendan las luces intermitentes de emergencia de cuatro direcciones al acercarse y al detenerse, para advertir al tránsito que viene detrás. Fuente: Manual de CDL de Idaho (ITD), sección de cruces ferroviarios."},"63":{"q":"Según la ley 'Cámbiese de Carril' (Move Over) de Idaho (Idaho Code 49-624), cuando se acerca a un vehículo detenido de la policía, de emergencia, de remolque (grúa) o de respuesta a incidentes en la carretera que tiene luces intermitentes encendidas en una vía con dos o más carriles en su dirección, usted debe:","options":["Reducir la velocidad por debajo del límite indicado y, si está en el carril contiguo, cambiarse a un carril no contiguo cuando sea posible","Mantener la velocidad indicada pero tocar la bocina","Detenerse por completo hasta que el vehículo de emergencia se mueva","Cambiarse de carril solo si lo indica un oficial"],"explanation":"El Idaho Code 49-624 exige que los conductores reduzcan la velocidad por debajo del límite indicado y, en una carretera de varios carriles, desocupen el carril contiguo al vehículo de emergencia/grúa/respuesta a incidentes detenido (con luces intermitentes) cambiándose a un carril no contiguo tan pronto como sea razonablemente posible. Fuente: Idaho Code 49-624."},"64":{"q":"La ley Move Over de Idaho (49-624) se aplica a vehículos detenidos que tienen luces intermitentes encendidas. ¿Cuál de los siguientes NO es un tipo de vehículo específicamente protegido por la ley?","options":["Un automóvil particular de pasajeros detenido por una llanta pinchada","Una grúa de remolque","Un vehículo de respuesta a incidentes en la carretera","Un vehículo de emergencia autorizado"],"explanation":"El Idaho Code 49-624 protege a los vehículos policiales detenidos, los vehículos de emergencia autorizados, las grúas de remolque y los vehículos de respuesta a incidentes en la carretera que tienen luces intermitentes encendidas. Un automóvil particular de pasajeros común no está mencionado en la ley Move Over. Fuente: Idaho Code 49-624."},"65":{"q":"En una carretera de dos carriles con un solo carril en cada dirección, la ley Move Over de Idaho exige que un conductor que pasa junto a un vehículo de emergencia detenido con luces intermitentes:","options":["Reduzca la velocidad por debajo del límite indicado y mantenga una velocidad segura hasta haber pasado por completo el vehículo","Se detenga por completo y espere","Cruce la línea central hacia los carriles en sentido contrario para dar espacio","Continúe a la velocidad indicada sin reducir"],"explanation":"Cuando cambiarse de carril es imposible (un carril en cada dirección), el Idaho Code 49-624 exige que el conductor reduzca la velocidad por debajo del límite indicado y avance con precaución a una velocidad segura hasta haber pasado por completo el vehículo detenido. Fuente: Idaho Code 49-624."},"66":{"q":"Según el Idaho Code 49-1422, el conductor de un vehículo que se cruza con un autobús escolar detenido en sentido contrario con sus señales visuales rojas activadas NO está obligado a detenerse únicamente cuando la carretera tiene:","options":["Más de tres carriles","Más de dos carriles","Un carril central de giro pintado","Cualquier mediana divisoria de cualquier ancho"],"explanation":"El Idaho Code 49-1422 establece que el tránsito en sentido contrario en una carretera de más de tres (3) carriles no está obligado a detenerse al cruzarse con un autobús escolar con las señales activadas. Idaho vincula la excepción a la cantidad de carriles (>3 carriles), no simplemente a una mediana. Fuente: Idaho Code 49-1422."},"67":{"q":"En una carretera estándar de dos carriles en Idaho, el conductor de un vehículo que se cruza con O alcanza por detrás a un autobús escolar detenido con sus señales visuales rojas intermitentes debe:","options":["Detenerse antes de llegar al autobús y no continuar hasta que las señales se apaguen o el autobús se mueva","Reducir la velocidad a 20 mph y pasar con precaución","Detenerse solo si hay niños a la vista","Detenerse solo si lo alcanza por detrás, no si se cruza con él"],"explanation":"El Idaho Code 49-1422 exige que un conductor que se cruza con un autobús escolar o que lo alcanza desde cualquier dirección se detenga antes de llegar al autobús que muestra las señales visuales del 49-915, y que no continúe hasta que el autobús reanude el movimiento o las señales ya no estén activadas (excepto la excepción del tránsito en sentido contrario en vías de más de 3 carriles). Fuente: Idaho Code 49-1422."},"68":{"q":"Hasta el 1 de julio de 2026, según el Idaho Code 49-654, un camión de cinco o más ejes de más de 26,000 lbs está limitado en las carreteras interestatales en zonas NO URBANAS a una velocidad máxima de:","options":["10 mph menos que el límite para vehículos más livianos","Exactamente 65 mph en todas partes","5 mph menos que el límite para vehículos más livianos","La misma velocidad que los automóviles de pasajeros"],"explanation":"Según la versión del Idaho Code 49-654 vigente hasta el 30 de junio de 2026, los camiones pesados (5+ ejes, más de 26,000 lbs) no pueden exceder los 10 mph menos que los vehículos más livianos en las interestatales no urbanas. El proyecto de ley House Bill 664 iguala estos límites a partir del 1 de julio de 2026. Fuente: Idaho Code 49-654; HB664 (2026)."},"69":{"q":"A partir del 1 de julio de 2026, el House Bill 664 de Idaho cambia la regla de velocidad para camiones pesados (5+ ejes, más de 26,000 lbs) de modo que, en las interestatales, las carreteras estatales y otros lugares, su velocidad máxima legal será:","options":["La misma que para los vehículos de menos de cinco ejes y de 26,000 lbs o menos","Aún 10 mph menos que los automóviles de pasajeros en las interestatales no urbanas","Limitada a 70 mph en todo el estado sin importar el límite indicado","Limitada a 65 mph únicamente en todas las zonas urbanas"],"explanation":"El HB664 modifica el Idaho Code 49-654 de modo que, a partir del 1 de julio de 2026, los camiones pesados estén sujetos a los mismos límites máximos de velocidad indicados que los vehículos más livianos, eliminando los anteriores topes para camiones de 10 mph menos y de 65 mph en zonas urbanas. Fuente: Idaho HB664 (2026); Idaho Code 49-654."},"70":{"q":"Según el Idaho Code 49-654, el límite máximo de velocidad que puede indicarse en las carreteras interestatales de Idaho (para vehículos más livianos, tras un estudio de ingeniería) es:","options":["80 mph","75 mph","70 mph","85 mph"],"explanation":"El Idaho Code 49-654 establece una base de 75 mph en las interestatales, pero autoriza al ITD a elevar el límite hasta 80 mph en las carreteras interestatales tras un estudio de ingeniería y de tránsito; los 80 mph están indicados en muchos tramos interestatales rurales de Idaho. Fuente: Idaho Code 49-654; ITD."},"71":{"q":"Según el Idaho Code 49-654, en ausencia de un límite indicado, la velocidad máxima predeterminada en cualquier distrito residencial, comercial o urbano es:","options":["35 mph","25 mph","30 mph","20 mph"],"explanation":"El Idaho Code 49-654 establece un máximo predeterminado de 35 mph en cualquier distrito residencial, comercial o urbano, salvo que se indique lo contrario. Fuente: Idaho Code 49-654."},"72":{"q":"El Idaho Code 49-630 regula el uso de los carriles en las carreteras de Idaho. Un vehículo que circula más lento que el flujo normal del tránsito, como un camión cargado subiendo una pendiente, debe:","options":["Circular por el carril derecho o lo más cerca posible del borde derecho","Usar el carril central para equilibrar el tránsito","Permanecer en el carril izquierdo para mantener libre el carril derecho para las incorporaciones","Elegir cualquier carril siempre que señalice"],"explanation":"El Idaho Code 49-630 exige que todo vehículo que circule a menos de la velocidad normal del tránsito sea conducido por el carril derecho disponible, o lo más cerca posible del cordón/borde derecho, excepto al rebasar o al prepararse para girar a la izquierda. Fuente: Idaho Code 49-630."},"73":{"q":"En una carretera dividida o de un solo sentido, el manual de CDL de Idaho indica que un vehículo comercial detenido coloque sus tres dispositivos de advertencia de emergencia a qué distancias hacia el tránsito que se aproxima?","options":["10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima","10 pies, 50 pies y 100 pies hacia el tránsito que se aproxima","15 pies, 100 pies y 300 pies hacia el tránsito que se aproxima","25 pies, 100 pies y 500 pies hacia el tránsito que se aproxima"],"explanation":"En una carretera de un solo sentido o dividida, el manual de CDL de Idaho (según el 49 CFR 392.22) exige los dispositivos de advertencia a 10 pies, 100 pies y 200 pies del vehículo hacia el tránsito que se aproxima. Fuente: Manual de CDL de Idaho (ITD)."},"74":{"q":"En una carretera de dos carriles y doble sentido en Idaho, ¿dónde indica el manual de CDL de Idaho que se coloquen los tres dispositivos de advertencia requeridos para un CMV detenido?","options":["A menos de 10 pies del vehículo, y a 100 pies detrás y 100 pies adelante de este","Los tres a menos de 10 pies de la parte trasera del vehículo","A 50 pies, 200 pies y 500 pies únicamente por detrás","A 100 pies, 200 pies y 300 pies por detrás del vehículo"],"explanation":"En una carretera de dos carriles y doble sentido, el manual de CDL de Idaho (según el 49 CFR 392.22) exige un dispositivo a menos de 10 pies del vehículo del lado del tránsito, uno a unos 100 pies por detrás y uno a unos 100 pies por delante, en el acotamiento o en el carril donde se detuvo. Fuente: Manual de CDL de Idaho (ITD)."},"75":{"q":"Si un CMV se detiene en una carretera de dos carriles de Idaho a menos de 500 pies de una colina, curva u otra obstrucción, el manual de CDL de Idaho indica:","options":["Mover el dispositivo de advertencia trasero hacia atrás a una distancia de entre 100 y 500 pies para dar más advertencia a los conductores","Dejar los tres triángulos en los puntos estándar de 10/100/100 pies","Apilar los tres dispositivos directamente detrás del vehículo","Retirar los triángulos y depender solo de las luces intermitentes"],"explanation":"Cuando está detenido a menos de 500 pies de una colina, curva u obstrucción que limita la distancia de visibilidad, el manual de CDL de Idaho (según el 49 CFR 392.22) indica mover el dispositivo de advertencia trasero más alejado hacia atrás por la carretera a un punto entre 100 y 500 pies del vehículo, de modo que los conductores que se aproximan reciban una advertencia adecuada. Fuente: Manual de CDL de Idaho (ITD)."},"76":{"q":"El manual de CDL de Idaho exige que un CMV detenido coloque sus dispositivos de advertencia (bengalas o triángulos) dentro de qué tiempo después de detenerse en una carretera?","options":["10 minutos","5 minutos","15 minutos","30 minutos"],"explanation":"El manual de CDL de Idaho (según el 49 CFR 392.22) exige que los dispositivos de advertencia de emergencia se coloquen dentro de los 10 minutos posteriores a detenerse en la parte transitada o en el acotamiento de una carretera. Fuente: Manual de CDL de Idaho (ITD)."},"77":{"q":"Las pendientes de la US-95, como la Lewiston Grade y la White Bird Grade, son conocidas en Idaho por sus pronunciados descensos de montaña. ¿Qué característica de seguridad ofrecen estas pendientes para los camiones que pierden la capacidad de frenado?","options":["Rampas de escape de emergencia (para camiones sin frenos)","Casetas de peaje obligatorias para camiones pesados","Una prohibición estatal de rutas de camiones que los desvía alrededor de ellas","Reguladores electrónicos de velocidad integrados en la carretera"],"explanation":"Las pronunciadas pendientes de montaña de la US-95 de Idaho (Lewiston Grade, White Bird Grade) están equipadas con rampas de escape de emergencia para camiones sin frenos que usan largos lechos de grava para detener un vehículo que ha perdido los frenos. El ITD coloca señalización anticipada para estos descensos. Fuente: Idaho Transportation Department (ITD), proyectos de rampas de escape de la US-95."},"78":{"q":"Idaho no tiene carreteras de peaje ni puentes interestatales financiados con peaje en su sistema de carreteras estatales. Para un conductor de CDL que planifica una ruta a través de Idaho, esto significa:","options":["No se cobran peajes en las interestatales ni en las carreteras estatales de Idaho","Se cobran peajes solo en los puentes interestatales sobre el río Snake","Los camiones pesados pagan un peaje por milla en la I-84","Los peajes se aplican solo en el bypass metropolitano de Boise"],"explanation":"Idaho no opera carreteras de peaje ni puentes de peaje en su sistema de carreteras públicas; las interestatales y las carreteras estatales son libres de peaje. En cambio, los conductores de CDL deben planificar en torno a los requisitos de permisos para cargas de gran tamaño/sobrepeso y de rutas restringidas administrados por el ITD, no en torno a peajes. Fuente: Idaho Transportation Department (ITD)."},"79":{"q":"¿Cuál agencia es la Agencia Estatal de Licencias de Conducir responsable de emitir las Licencias de Conducir Comerciales en Idaho?","options":["El Idaho Transportation Department (ITD)","El Servicio de Vehículos Comerciales de la Policía Estatal de Idaho","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Seguridad de Vehículos Motorizados de Idaho"],"explanation":"El DMV del Idaho Transportation Department (ITD) es la Agencia Estatal de Licencias de Conducir de Idaho y emite las CDL. Fuente: página de Licencia de Conducir Comercial (CDL) del DMV del ITD; 'Ten Steps to Getting an Idaho CDL' del ITD."},"80":{"q":"En Idaho, ¿a dónde acude realmente un solicitante de CDL para postularse, presentar los exámenes escritos y obtener la licencia?","options":["Una franquicia de exámenes del ITD administrada de forma privada","Una oficina de licencias de conducir (DMV) del sheriff del condado","Una oficina de campo de la FMCSA","Únicamente la sede del ITD en Boise"],"explanation":"La emisión de licencias de conducir en Idaho es administrada por los condados: los solicitantes acuden a una oficina de licencias de conducir del sheriff del condado, que gestiona la solicitud de CDL, los exámenes de conocimientos y la emisión, mientras el ITD procesa los registros. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 4."},"81":{"q":"Antes de obtener la licencia, todo nuevo solicitante de CDL en Idaho debe obtener primero qué credencial para practicar y para presentar el examen de habilidades?","options":["Un Permiso de Aprendiz Comercial (CLP)","Un permiso de instrucción de Clase D","Una tarjeta federal de autoridad interestatal","Un endoso comercial provisional"],"explanation":"Idaho exige que los solicitantes obtengan un Permiso de Aprendiz Comercial (CLP) para obtener o mejorar una licencia comercial y para practicar en las vías públicas antes del examen de habilidades. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 5."},"82":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Idaho una vez emitido?","options":["180 días","90 días","Dos años","Un año"],"explanation":"El CLP de Idaho es válido por un año (el plazo de Idaho difiere del mínimo de 180 días que usan algunos estados). Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 5."},"83":{"q":"Según las reglas federales aplicadas en Idaho, ¿por cuánto tiempo debe un solicitante tener el CLP antes de que se le permita presentar el examen de habilidades de CDL?","options":["Al menos 30 días","Al menos 10 días","Al menos 14 días","Al menos 60 días"],"explanation":"Las reglas de la FMCSA adoptadas por Idaho exigen tener el CLP durante un mínimo de 14 días antes de presentar un examen de habilidades, incluso cuando solo se está mejorando una CDL existente. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Pasos 5 y 9."},"84":{"q":"¿De qué tres partes se compone el examen de habilidades de CDL de Idaho?","options":["Examen escrito, examen de la vista y examen de manejo","Examen de frenos de aire, examen de retroceso y examen de estación de pesaje","Inspección previaje, examen en simulador y manejo nocturno","Inspección previaje, control básico del vehículo y manejo en la vía"],"explanation":"Idaho sigue el examen de habilidades de tres partes de la FMCSA: inspección previaje (del vehículo), control básico del vehículo (maniobras en pista cerrada) y el examen de manejo en la vía. Fuente: manual de CDL del ITD; 'Ten Easy Steps to a C.D.L.' del ITD, Pasos 6 a 9."},"85":{"q":"El día del examen en Idaho, ¿cuánto tiempo se le da a un solicitante para completar la inspección previaje del vehículo?","options":["45 minutos","15 minutos","60 minutos","30 minutos"],"explanation":"Idaho otorga 45 minutos para completar la parte de la inspección previaje el día del examen; una verificación de frenos incorrecta es una causa común de reprobación. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 6."},"86":{"q":"En la parte de control básico (retroceso) de Idaho, ¿cuáles dos maniobras se exigen a todos los solicitantes?","options":["Estacionamiento en callejón (alley dock) y estacionamiento en paralelo","Retroceso en línea recta y estacionamiento en callejón (alley dock)","Retroceso en línea recta y retroceso con desplazamiento lateral (offset back)","Estacionamiento en paralelo y serpentina"],"explanation":"Idaho exige el retroceso en línea recta y el retroceso con desplazamiento lateral (offset back) a todos los solicitantes; el examinador luego selecciona ya sea el estacionamiento en callejón (alley dock) o el estacionamiento en paralelo. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 7 (maniobras del Capítulo 12)."},"87":{"q":"¿Cuál capacitación debe completar un solicitante de CDL de Idaho con un proveedor registrado antes de ser elegible para presentar el examen de habilidades?","options":["Un curso de manejo defensivo aprobado por el estado","Un seminario de orientación de seguridad del ITD","Un curso de vehículos comerciales de OSHA","Capacitación para Conductores Principiantes (ELDT)"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes deben completar la Capacitación para Conductores Principiantes (ELDT) con un proveedor que figure en el Registro de Proveedores de Capacitación de la FMCSA antes de presentar los exámenes de habilidades requeridos. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 5; regla de ELDT de la FMCSA."},"88":{"q":"En la autocertificación de CDL de Idaho, ¿entre cuántas categorías de manejo debe elegir un solicitante?","options":["Dos","Tres","Cinco","Cuatro"],"explanation":"Los titulares de CDL de Idaho deben autocertificarse en una de cuatro categorías: interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada o intraestatal exceptuada. Fuente: cuadro 'Medical Cards & Self Certification Categories' del ITD; FMCSA 49 CFR 383.71."},"89":{"q":"¿Cuál categoría de autocertificación describe Idaho como el 'estándar de oro' que requiere tarjeta médica para la mayoría de los conductores de CDL, y que permite manejar a través de las fronteras estatales?","options":["Interestatal exceptuada","Intraestatal no exceptuada","Interestatal no exceptuada","Intraestatal exceptuada"],"explanation":"Idaho califica a la interestatal no exceptuada como el 'estándar de oro': el conductor está certificado médicamente y puede cruzar las fronteras estatales y transportar cualquier cosa. Fuente: cuadro 'Medical Cards & Self Certification Categories' del ITD."},"90":{"q":"¿Cuál categoría de autocertificación de Idaho requiere un certificado médico DOT válido aunque todo el manejo se mantenga dentro de Idaho?","options":["Intraestatal exceptuada","Intraestatal no exceptuada","Interestatal exceptuada","No-CDL exceptuada"],"explanation":"Los conductores intraestatales no exceptuados se mantienen dentro de Idaho pero aún están certificados médicamente (p. ej., transportando productos no exentos), y esto agrega una restricción 'K' (solo intraestatal). Fuente: cuadro 'Medical Cards & Self Certification Categories' del ITD."},"91":{"q":"¿Cuál restricción agrega Idaho a una CDL cuando un conductor se autocertifica en una categoría intraestatal?","options":["Una restricción 'L' (sin frenos de aire)","Una restricción 'K' (solo operación intraestatal)","Una restricción 'E' (solo transmisión automática)","Una restricción 'O' (sin quinta rueda)"],"explanation":"Autocertificarse en cualquiera de las categorías intraestatales (exceptuada o no exceptuada) agrega una restricción 'K' que limita al conductor a la operación intraestatal. Fuente: cuadro 'Medical Cards & Self Certification Categories' del ITD; 49 CFR 383.95."},"92":{"q":"Un titular de CDL no exceptuada de Idaho obtiene un nuevo certificado de examinador médico DOT. ¿Qué debe hacer con él?","options":["Presentar una copia al DMV del condado/ITD para que se agregue al registro de conducir","Guardarlo únicamente en el camión para las inspecciones en carretera","Enviar por correo el original a la FMCSA en Washington, D.C.","Presentarlo ante su empleador en lugar del estado"],"explanation":"Los titulares de CDL no exceptuada deben presentar (entregar) una copia del certificado del examinador médico (ME) al DMV del condado/ITD cuando lo obtengan y en cada renovación, para que se registre en el registro de conducir. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 4."},"93":{"q":"Un certificado de examinador médico DOT usado para una CDL de Idaho puede emitirse por un máximo de cuánto tiempo?","options":["Hasta 12 meses","Hasta 36 meses","Hasta 24 meses","Hasta 48 meses"],"explanation":"Un certificado de examen físico/examinador médico DOT es válido por hasta 24 meses; un examinador puede emitirlo por menos tiempo para monitorear una condición médica. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 2."},"94":{"q":"El proveedor médico que realiza el examen físico DOT para un solicitante de CDL de Idaho debe figurar dónde?","options":["En el panel de CDL de la Junta de Medicina de Idaho","En el Registro Nacional de Examinadores Médicos Certificados (National Registry of Certified Medical Examiners)","En la lista de médicos aprobados del ITD","En el listado de seguridad de transportistas de la FMCSA"],"explanation":"El proveedor que realiza el examen debe figurar en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA; usar un proveedor no registrado puede llevar a una degradación de la CDL. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 2; aviso sobre certificado médico del ITD."},"95":{"q":"¿Por cuánto tiempo permanecen válidos los resultados aprobados del examen de conocimientos (escrito) de CDL de un solicitante de Idaho antes de que deban repetirse todos los exámenes escritos?","options":["Un año a partir de la fecha en que se aprobó","Seis meses a partir de la fecha en que se aprobó","Dos años a partir de la fecha en que se aprobó","90 días a partir de la fecha en que se aprobó"],"explanation":"Los resultados del examen de conocimientos permanecen válidos por un año a partir de la fecha en que se aprobó; si no se obtiene la CDL dentro de ese año, deben repetirse todos los exámenes escritos. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 4."},"96":{"q":"Si un solicitante de Idaho reprueba un examen de conocimientos (escrito) de CDL, ¿qué tan pronto puede volver a presentarlo?","options":["El mismo día","Después de tres días","Después de siete días","Después de catorce días"],"explanation":"Un solicitante que reprueba un examen escrito puede volver a presentarlo después de tres días (y pagar de nuevo la tarifa por examen). Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 4."},"97":{"q":"Después de aprobar el examen de habilidades, ¿cuál es el periodo de validez de una CDL de Idaho estándar recién emitida?","options":["Solo dos años","Solo un año","Cuatro años (con una opción de ocho años también disponible)","Seis años fijos"],"explanation":"Idaho emite la CDL por cuatro años; el ITD también ofrece una opción de ocho años. El conductor debe regresar al DMV del condado para que se le emita la licencia después de aprobar. Fuente: 'Ten Steps to Getting an Idaho CDL' del ITD, Paso 10."},"98":{"q":"¿Cómo se rige según el Idaho Code la tarifa del examen de habilidades de CDL de Idaho que cobra el examinador?","options":["Es un monto fijo establecido a nivel federal en cada estado","Se exime para todos los solicitantes por primera vez","La establece únicamente la escuela de capacitación del solicitante","Tiene un tope y no puede exceder un máximo establecido por el Idaho Code por examen"],"explanation":"La tarifa del examen de habilidades fijada por el examinador tiene un tope establecido por el Idaho Code (sin exceder el máximo legal por examen), aparte de la pequeña porción del condado. Los montos exactos en dólares pueden cambiar. Fuente: 'Ten Easy Steps to a C.D.L.' del ITD, Paso 9."}},"hi":{"0":{"q":"इडाहो के राजमार्गों पर, किसी वाहन की अधिकतम कानूनी चौड़ाई कितनी होती है, जिसमें उसका भार भी शामिल है?","options":["8 फीट 6 इंच","8 फीट 0 इंच","9 फीट 0 इंच","10 फीट 0 इंच"],"explanation":"Idaho Code 49-1010 किसी भी वाहन की कुल चौड़ाई को, जिसमें उसका भार भी शामिल है, 8 फीट 6 इंच (102 इंच) तक सीमित करता है। इससे चौड़े भार के लिए ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: Idaho Code 49-1010 (वाहनों और भार का आकार)।"},"1":{"q":"इडाहो के राजमार्गों पर किसी वाहन और उसके भार की अधिकतम कानूनी ऊंचाई कितनी होती है?","options":["13 फीट 6 इंच","14 फीट","15 फीट","13 फीट"],"explanation":"Idaho Code 49-1010 किसी वाहन की अधिकतम ऊंचाई, जिसमें भार भी शामिल है, 14 फीट निर्धारित करता है। 14 फीट से ऊंचे भार के लिए ओवरहाइट परमिट की आवश्यकता होती है। स्रोत: Idaho Code 49-1010।"},"2":{"q":"इडाहो में किसी एकल एक्सल पर अधिकतम सकल भार कितना होता है?","options":["18,000 पाउंड","22,400 पाउंड","20,000 पाउंड","21,500 पाउंड"],"explanation":"Idaho Code 49-1001 अधिकतम एकल एक्सल सकल भार को 20,000 पाउंड निर्धारित करता है। स्रोत: Idaho Code 49-1001 (अनुमेय सकल भार)।"},"3":{"q":"इडाहो में किसी टैंडम एक्सल पर अधिकतम कितना सकल भार अनुमत है?","options":["34,000 पाउंड","36,000 पाउंड","32,000 पाउंड","40,000 पाउंड"],"explanation":"Idaho Code 49-1001 के तहत, टैंडम एक्सल का एक सेट 34,000 पाउंड तक भार ले जा सकता है, जो संघीय मानक के अनुरूप है। स्रोत: Idaho Code 49-1001।"},"4":{"q":"अमेरिकी संघीय इंटरस्टेट और रक्षा राजमार्ग प्रणाली के इडाहो वाले हिस्से पर, बिना परमिट के अधिकतम सकल वाहन या संयोजन भार कितना अनुमत है?","options":["80,000 पाउंड","105,500 पाउंड","90,000 पाउंड","129,000 पाउंड"],"explanation":"Idaho Code 49-1001 संघीय इंटरस्टेट और रक्षा राजमार्गों पर सकल वाहन या संयोजन भार को 80,000 पाउंड तक सीमित करता है, जो संघीय कानून के अनुरूप है। स्रोत: Idaho Code 49-1001।"},"5":{"q":"इडाहो के सामान्य (गैर-इंटरस्टेट) राज्य राजमार्गों पर, विशेष अतिरिक्त-भार परमिट का सहारा लेने से पहले मूल कानून के तहत अधिकतम सकल वाहन या संयोजन भार कितना अनुमत है?","options":["80,000 पाउंड","129,000 पाउंड","100,000 पाउंड","105,500 पाउंड"],"explanation":"Idaho Code 49-1001 अधिकतम सकल वाहन या संयोजन भार 105,500 पाउंड की अनुमति देता है, सिवाय इसके कि संघीय इंटरस्टेट और रक्षा राजमार्गों पर यह सीमा घटकर 80,000 पाउंड हो जाती है। स्रोत: Idaho Code 49-1001।"},"6":{"q":"इडाहो में किसी एकल पहिये पर अधिकतम कितना सकल भार अनुमत है?","options":["8,000 पाउंड","12,000 पाउंड","10,000 पाउंड","6,000 पाउंड"],"explanation":"Idaho Code 49-1001 अधिकतम एकल पहिया सकल भार को 10,000 पाउंड निर्धारित करता है। स्रोत: Idaho Code 49-1001।"},"7":{"q":"इडाहो लगातार एक्सलों के समूह पर अनुमत अधिकतम भार निर्धारित करने के लिए संघीय ब्रिज वज़न सूत्र का उपयोग करता है। इडाहो कोड कौन-सा सूत्र अपनाता है?","options":["W = 500((LN/N-1) + 12N + 36)","W = 1000(L + N + 20)","W = 34,000 + (N x 12)","W = 250(LN + 12 + 36N)"],"explanation":"Idaho Code 49-1001(1) संघीय ब्रिज सूत्र W = 500((LN/N-1) + 12N + 36) अपनाता है, जहां W अधिकतम भार है, L एक्सल समूह के दोनों छोरों के बीच फीट में दूरी है, और N एक्सलों की संख्या है। स्रोत: Idaho Code 49-1001(1)।"},"8":{"q":"इडाहो के ब्रिज सूत्र में, चर 'L' किसका प्रतिनिधित्व करता है?","options":["ट्रेलर की कानूनी भार रेटिंग","दो या अधिक लगातार एक्सलों के समूह के दोनों छोरों के बीच फीट में दूरी","केवल सबसे लंबे एकल एक्सल समूह की लंबाई","वाहन का लाइसेंसकृत सकल भार"],"explanation":"सूत्र W = 500((LN/N-1) + 12N + 36) में, 'L' किन्हीं दो या अधिक लगातार एक्सलों के समूह के दोनों छोरों के बीच फीट में दूरी है, 'N' एक्सलों की संख्या है, और 'W' अधिकतम भार है। स्रोत: Idaho Code 49-1001(1)।"},"9":{"q":"इडाहो में टैंडम एक्सलों के दो लगातार सेट प्रत्येक 34,000 पाउंड तभी ले जा सकते हैं जब उन टैंडम सेटों के पहले और अंतिम एक्सलों के बीच कुल दूरी कम से कम कितने फीट हो?","options":["30 फीट","36 फीट","40 फीट","34 फीट"],"explanation":"Idaho Code 49-1001(1)(b) दो लगातार टैंडम सेटों को प्रत्येक 34,000 पाउंड ले जाने की अनुमति देता है, बशर्ते उन सेटों के पहले और अंतिम एक्सलों के बीच की दूरी 36 फीट या अधिक हो। स्रोत: Idaho Code 49-1001(1)(b)।"},"10":{"q":"इडाहो में राष्ट्रीय नेटवर्क का हिस्सा बनने वाले मार्गों पर चलने वाला एक सेमीट्रेलर किस लंबाई से अधिक नहीं हो सकता?","options":["48 फीट","53 फीट","57 फीट","45 फीट"],"explanation":"Idaho Code 49-1010 राष्ट्रीय नेटवर्क (और संबंधित पहुंच मार्गों) पर चलने वाले सेमीट्रेलर की लंबाई को 53 फीट तक सीमित करता है। स्रोत: Idaho Code 49-1010।"},"11":{"q":"इडाहो कोड के तहत, किसी वाहन पर लदा भार आमतौर पर वाहन के अगले हिस्से से कितने फीट से अधिक आगे नहीं निकल सकता?","options":["3 फीट","4 फीट","6 फीट","2 फीट"],"explanation":"Idaho Code 49-1010 किसी भार को वाहन के अगले हिस्से से 4 फीट से अधिक आगे निकलने से रोकता है। स्रोत: Idaho Code 49-1010।"},"12":{"q":"इडाहो में किसी कम किए जा सकने वाले (रिड्यूसिबल) भार को ढोने वाला वाहन संयोजन 105,500 पाउंड से अधिक सकल भार पर चल सकता है, लेकिन किस भार से अधिक नहीं, और केवल उचित पंजीकरण और परमिट के साथ निर्दिष्ट गैर-इंटरस्टेट मार्गों पर?","options":["129,000 पाउंड","117,000 पाउंड","140,000 पाउंड","125,500 पाउंड"],"explanation":"Idaho Code 49-1001(1)(c) 105,500 पाउंड से अधिक के रिड्यूसिबल भार की अनुमति देता है, लेकिन गैर-इंटरस्टेट राजमार्गों पर 129,000 पाउंड से अधिक नहीं, जब वाहन पंजीकृत हो, भार सूत्र और लंबाई प्रतिबंधों का पालन करता हो, और Idaho Code 49-1004 के अनुसार निर्दिष्ट मार्गों पर चलता हो। स्रोत: Idaho Code 49-1001(1)(c) और 49-1004।"},"13":{"q":"इडाहो में किसी पंजीकृत संयोजन को 105,501 और 129,000 पाउंड के बीच रिड्यूसिबल भार ढोने के लिए अधिकृत करने वाला विशेष-मार्ग वार्षिक परमिट कौन जारी करता है?","options":["मार्ग के प्रत्येक काउंटी का काउंटी शेरिफ","Federal Highway Administration","Idaho Transportation Department या, अपने विवेक से, एक स्थानीय सार्वजनिक राजमार्ग एजेंसी","कोई भी वाणिज्यिक ट्रक स्टॉप वेट स्टेशन"],"explanation":"Idaho Code 49-1004 प्रावधान करता है कि 105,501 से 129,000 पाउंड तक के भार के लिए विशेष-मार्ग परमिट Idaho Transportation Department द्वारा, या अपने विवेक से किसी स्थानीय सार्वजनिक राजमार्ग एजेंसी द्वारा, विभाग या स्थानीय प्राधिकरणों द्वारा निर्दिष्ट मार्गों पर जारी किए जाते हैं। स्रोत: Idaho Code 49-1004।"},"14":{"q":"इडाहो की कानूनी आकार या भार सीमा से अधिक वाले वाहन के राजमार्ग पर चलने से पहले आमतौर पर किसकी आवश्यकता होती है?","options":["चलने से पहले प्राप्त किया गया वैध ओवरसाइज़/ओवरवेट परमिट","Class A CDL में परिवर्तन","FMCSA से संघीय छूट","केवल पोर्ट-ऑफ-एंट्री अधिकारी से मौखिक स्वीकृति"],"explanation":"Idaho Code 49-1004 और ITD परमिटिंग नियमों के अनुसार कानूनी आकार या भार सीमा से अधिक वाहन चलाने के लिए ओवरसाइज़ और/या ओवरवेट परमिट की आवश्यकता होती है, जो आवाजाही से पहले प्राप्त किया गया हो; परमिट को वाहन में रखना होता है। स्रोत: Idaho Code 49-1004; ITD परमिट नियम (IDAPA 39.03.03)।"},"15":{"q":"इडाहो कानून कुछ निश्चित वस्तुएं ढोने वाले वाहनों को गैर-इंटरस्टेट राजमार्गों पर एक भार छूट (एक अलग, अधिक उदार एक्सल-स्पेसिंग तालिका) देता है। वस्तुओं का कौन-सा समूह इसमें शामिल है?","options":["लट्ठे, पल्प वुड, खुरदुरी लकड़ी, खंभे, अयस्क, रेत और बजरी, और पशुधन सहित कृषि वस्तुएं","प्रशीतित किराना और बोतलबंद पेय पदार्थ","नई ऑटोमोबाइल और मनोरंजन वाहन","केवल खतरनाक सामग्री और थोक ईंधन"],"explanation":"Idaho Code 49-1001(2) उन वाहनों के लिए एक विशेष अनुमत-भार तालिका प्रदान करता है जो लट्ठे, पल्प वुड, स्टल, खुरदुरी लकड़ी, खंभे या पाइलिंग; अयस्क, सांद्रण, रेत और बजरी और थोक में समुच्चय; या पशुधन सहित कृषि वस्तुएं ढोते हैं। स्रोत: Idaho Code 49-1001(2)।"},"16":{"q":"Idaho Code 49-1001(2) में लट्ठों, अयस्कों, रेत/बजरी और कृषि वस्तुओं के लिए विशेष भार भत्ते तब लागू नहीं होते जब कुल सकल भार, जैसा कि ऑपरेटर द्वारा घोषित किया गया है, किस आंकड़े से अधिक होने का इरादा हो?","options":["80,000 पाउंड","79,000 पाउंड","105,500 पाउंड","84,000 पाउंड"],"explanation":"Idaho Code 49-1001(2) बताता है कि वस्तु भार भत्ते लागू नहीं होते यदि कुल सकल भार, जैसा कि ऑपरेटर द्वारा घोषित किया गया है, 79,000 पाउंड से अधिक होने का इरादा हो। स्रोत: Idaho Code 49-1001(2)।"},"17":{"q":"इडाहो के किसी पोर्ट ऑफ एंट्री पर, जब किसी एकल एक्सल का भार अधिकतम सीमा से कितना अधिक हो जाए तो एक लदा हुआ वाहन स्केल से आगे नहीं बढ़ सकता?","options":["500 पाउंड या अधिक","1,000 पाउंड या अधिक","2,000 पाउंड या अधिक","5,000 पाउंड या अधिक"],"explanation":"Idaho Code 49-1001(8) प्रावधान करता है कि कोई वाहन पोर्ट ऑफ एंट्री से आगे नहीं बढ़ सकता जब कोई एकल एक्सल अधिकतम से 2,000 पाउंड या अधिक से अधिक हो, या जब सकल/एक्सल-समूह भार अधिकतम से 7% या अधिक से अधिक हो। स्रोत: Idaho Code 49-1001(8)।"},"18":{"q":"इडाहो के किसी पोर्ट ऑफ एंट्री पर, अधिकतम अनुमेय सकल या एक्सल-समूह भार से कितने प्रतिशत अधिक होने पर वाहन को रोका जाएगा और आगे बढ़ने से पहले अनुपालन में लाने की आवश्यकता होगी?","options":["7 प्रतिशत या अधिक","5 प्रतिशत या अधिक","10 प्रतिशत या अधिक","15 प्रतिशत या अधिक"],"explanation":"Idaho Code 49-1001(8) के अनुसार किसी वाहन को स्केल पर अनुपालन में लाना आवश्यक है जब उसका सकल वाहन भार या एक्सलों का संयोजन अधिकतम अनुमेय भार से 7 प्रतिशत या अधिक से अधिक हो (एकल एक्सल की सीमा 2,000 पाउंड है)। स्रोत: Idaho Code 49-1001(8)।"},"19":{"q":"इडाहो को अति-चौड़ाई वाले परमिट किए गए भार के लिए एस्कॉर्ट (पायलट/फ्लैग कारें) की आवश्यकता होती है। किस भार चौड़ाई पर इडाहो आमतौर पर कम से कम एक पायलट/एस्कॉर्ट वाहन की आवश्यकता रखता है?","options":["8 फीट 6 इंच से अधिक चौड़ा","10 फीट से अधिक चौड़ा","12 फीट से अधिक चौड़ा","16 फीट से अधिक चौड़ा"],"explanation":"ITD के ओवरसाइज़ मूवमेंट नियमों के तहत, 12 फीट से अधिक चौड़े भार के लिए आमतौर पर एक पायलट/एस्कॉर्ट वाहन की आवश्यकता होती है, और 14 फीट से अधिक चौड़े भार के लिए दो की। अति-चौड़े भार के कोनों पर फ्लैग आवश्यक होते हैं, और एस्कॉर्ट पर एक OVERSIZE LOAD साइन और एम्बर लाइट आवश्यक होती हैं। स्रोत: ITD परमिट नियम (IDAPA 39.03.05 / पायलट-एस्कॉर्ट आवश्यकताएं)।"},"20":{"q":"इडाहो में, किसी एकल वाहन को चलाने के लिए CDL की आवश्यकता होती है जिसका सकल वाहन भार रेटिंग (GVWR) कितने पाउंड या अधिक हो (10,000 lbs से अधिक कुछ भी न खींचते हुए)?","options":["16,001 पाउंड","26,001 पाउंड","33,001 पाउंड","10,001 पाउंड"],"explanation":"इडाहो संघीय सीमा अपनाता है: किसी भी एकल वाहन के लिए जिसका GVWR 26,001 lbs या अधिक हो, एक Class B CDL की आवश्यकता होती है (Idaho CDL Manual, ITD; 49 CFR 383.91)।"},"21":{"q":"26,001 lbs या अधिक GCWR वाले संयोजन वाहन को चलाने के लिए किस इडाहो CDL क्लास की आवश्यकता होती है जहां खींची गई इकाई/इकाइयां 10,000 lbs GVWR से अधिक हों?","options":["Class C","Class B","Class A","Class D"],"explanation":"एक Class A CDL 26,001 lbs या अधिक GCWR वाले संयोजन वाहनों को कवर करता है, बशर्ते खींचे गए वाहन/वाहनों का GVWR 10,000 lbs से अधिक हो (Idaho CDL Manual, ITD)।"},"22":{"q":"इडाहो नियमों के तहत, 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए वाहन, लेकिन Class A/B भार सीमा से कम वाले, को किस CDL क्लास की आवश्यकता होती है?","options":["Class C","Class A","Class B","किसी CDL की आवश्यकता नहीं"],"explanation":"एक Class C CDL उन वाहनों के लिए आवश्यक है जो Class A या B मानदंडों को पूरा नहीं करते लेकिन चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए हैं, या प्लेकार्ड लगाने योग्य खतरनाक सामग्री ले जाते हैं (Idaho CDL Manual, ITD)।"},"23":{"q":"इडाहो थोक में तरल पदार्थ या गैसें ले जाने वाले टैंक (टैंकर) वाहनों को चलाने के अधिकार को कौन-सा एंडोर्समेंट अक्षर सौंपता है?","options":["T","N","X","H"],"explanation":"N एंडोर्समेंट टैंक वाहनों के लिए है। (T = डबल/ट्रिपल, H = हैज़मैट, X = संयुक्त टैंक और हैज़मैट।) स्रोत: Idaho CDL Manual, ITD; 49 CFR 383.93।"},"24":{"q":"इडाहो में, 'T' एंडोर्समेंट धारक को किस प्रकार के वाहन को चलाने के लिए अधिकृत करता है?","options":["टैंक वाहन","खतरनाक सामग्री ले जाने वाले वाहन","डबल और ट्रिपल ट्रेलर","16+ यात्रियों को ले जाने वाले वाहन"],"explanation":"T एंडोर्समेंट डबल और ट्रिपल ट्रेलरों को कवर करता है और केवल एक ज्ञान परीक्षा पास करने की आवश्यकता होती है (Idaho CDL Manual, ITD; 49 CFR 383.93)।"},"25":{"q":"इडाहो HazMat (H) एंडोर्समेंट प्राप्त करने के लिए, आवेदक को एक ज्ञान परीक्षा पास करनी होगी और साथ ही कौन-सी अतिरिक्त संघीय आवश्यकता पूरी करनी होगी?","options":["एक बिहाइंड-द-व्हील कौशल परीक्षा","एक TSA सुरक्षा खतरा मूल्यांकन (पृष्ठभूमि जांच)","एक दृष्टि छूट आवेदन","एक दूसरी चिकित्सा परीक्षा"],"explanation":"इडाहो H एंडोर्समेंट आवेदक से एक ज्ञान परीक्षा पास करने और USA PATRIOT Act के तहत एक TSA सुरक्षा खतरा मूल्यांकन (फिंगरप्रिंट-आधारित पृष्ठभूमि जांच) पास करने की आवश्यकता रखता है (Idaho CDL Manual, ITD; 49 CFR 1572)।"},"26":{"q":"इडाहो में, स्कूल बस (S) एंडोर्समेंट जारी करने से पहले, आवेदक के पास कौन-सा अन्य एंडोर्समेंट भी होना या प्राप्त करना आवश्यक है?","options":["N (टैंक)","T (डबल/ट्रिपल)","P (यात्री)","H (हैज़मैट)"],"explanation":"S (स्कूल बस) एंडोर्समेंट के लिए P (यात्री) एंडोर्समेंट आवश्यक है, साथ ही एक ज्ञान परीक्षा और एक स्कूल बस में कौशल परीक्षा भी (Idaho CDL Manual, ITD; 49 CFR 383.123)।"},"27":{"q":"किस इडाहो CDL एंडोर्समेंट के लिए एक प्रतिनिधि वाहन में एक ज्ञान परीक्षा और एक बिहाइंड-द-व्हील कौशल परीक्षा दोनों की आवश्यकता होती है?","options":["N (टैंक)","P (यात्री)","T (डबल/ट्रिपल)","H (हैज़मैट)"],"explanation":"P (यात्री) एंडोर्समेंट के लिए एक ज्ञान परीक्षा और एक यात्री वाहन में कौशल परीक्षा पास करना आवश्यक है; N, T, और H केवल-ज्ञान-परीक्षा वाले एंडोर्समेंट हैं (Idaho CDL Manual, ITD; 49 CFR 383.93)।"},"28":{"q":"केवल इडाहो के भीतर (इंट्रास्टेट) वाणिज्यिक वाहन चलाने के लिए इडाहो CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 वर्ष","18 वर्ष","19 वर्ष","21 वर्ष"],"explanation":"इडाहो 18 वर्ष की आयु में इंट्रास्टेट CDL की अनुमति देता है; आवेदक के पास एक वैध Idaho Class D लाइसेंस भी होना चाहिए और एक वर्ष का लाइसेंसकृत ड्राइविंग अनुभव होना चाहिए (Idaho CDL Manual, ITD; Idaho Code 49-305)।"},"29":{"q":"राज्य की सीमाओं के पार (इंटरस्टेट) वाणिज्यिक वाहन चलाने के लिए इडाहो (संघीय कानून का पालन करते हुए) कितनी न्यूनतम आयु की आवश्यकता रखता है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"इंटरस्टेट वाणिज्यिक ड्राइविंग के लिए न्यूनतम आयु 21 वर्ष आवश्यक है; एक 18 वर्षीय इडाहो CDL धारक केवल इंट्रास्टेट संचालन तक सीमित है (Idaho CDL Manual, ITD; 49 CFR 391.11)।"},"30":{"q":"इडाहो में HazMat (H) एंडोर्समेंट किसी ऐसे आवेदक को जारी नहीं किया जा सकता जो किस आयु से कम का हो?","options":["18","19","21","25"],"explanation":"चूंकि किराए के लिए हैज़मैट परिवहन में आमतौर पर इंटरस्टेट वाणिज्य और एक TSA मूल्यांकन शामिल होता है, H एंडोर्समेंट के लिए आवेदक का कम से कम 21 वर्ष का होना आवश्यक है (Idaho CDL Manual, ITD; 49 CFR 383/1572)।"},"31":{"q":"इडाहो में अपनाए गए संघीय नियमों के तहत, CDL कौशल परीक्षा देने के योग्य होने से पहले एक चालक को कितने समय तक Commercial Learner's Permit (CLP) धारण करना होगा?","options":["कम से कम 7 दिन","कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 60 दिन"],"explanation":"कौशल परीक्षा देने से पहले CLP को कम से कम 14 दिन तक धारण करना होगा (Idaho CDL Manual, ITD; 49 CFR 383.25)।"},"32":{"q":"इडाहो Commercial Learner's Permit (CLP) को नवीनीकृत करने से पहले कितने समय तक वैध रहता है?","options":["90 दिन","180 दिन","1 वर्ष","2 वर्ष"],"explanation":"एक इडाहो CLP 180 दिनों के लिए वैध होता है और सामान्य ज्ञान परीक्षा दोबारा दिए बिना अतिरिक्त 180 दिनों के लिए एक बार नवीनीकृत किया जा सकता है (Idaho CDL Manual, ITD; 49 CFR 383.25)।"},"33":{"q":"इडाहो Commercial Learner's Permit (CLP) पर वाहन चलाते समय, धारक के साथ हमेशा क्या होना आवश्यक है?","options":["कोई भी 25 वर्ष या उससे अधिक आयु का लाइसेंसकृत वयस्क","वाहन के उचित क्लास/एंडोर्समेंट वाला एक CDL धारक जो चालक के बगल में बैठा हो","एक DMV परीक्षक","कोई नहीं; अकेले वाहन चलाने की अनुमति है"],"explanation":"एक CLP धारक केवल तभी CMV चला सकता है जब उसके साथ कोई ऐसा व्यक्ति हो जिसके पास वाहन प्रकार के लिए वैध CDL हो और जो चालक के बगल में बैठा हो (Idaho CDL Manual, ITD; 49 CFR 383.25)।"},"34":{"q":"CDL के लिए आवेदन करने के लिए Idaho DMV द्वारा आवश्यक दस्तावेज़ों में से कौन-सा दस्तावेज़ शामिल नहीं है?","options":["पहचान का प्रमाण","Social Security number का प्रमाण","इडाहो निवास और वैध उपस्थिति का प्रमाण","किसी वर्तमान नियोक्ता से एक हस्ताक्षरित पत्र"],"explanation":"इडाहो को पहचान, Social Security number, इडाहो निवास, और वैध उपस्थिति/नागरिकता का प्रमाण आवश्यक है; नियोक्ता का पत्र आवश्यक नहीं है (Idaho CDL Manual / ITD DMV आवश्यकताएं)।"},"35":{"q":"7 फरवरी 2022 से, पहली बार इडाहो CDL के आवेदक को Entry-Level Driver Training (ELDT) पूरा करना होगा जो कहां सूचीबद्ध इकाई द्वारा प्रदान किया गया हो?","options":["Idaho State Police अकादमी रोस्टर","FMCSA Training Provider Registry (TPR)","Idaho Transportation Department स्कूल सूची","कोई भी मान्यता प्राप्त सामुदायिक कॉलेज"],"explanation":"कौशल परीक्षा देने से पहले ELDT को FMCSA Training Provider Registry पर सूचीबद्ध एक प्रदाता के माध्यम से पूरा करना होगा, जो 7 फरवरी 2022 से प्रभावी है (Idaho CDL Manual, ITD; 49 CFR 380 Subpart F)।"},"36":{"q":"निम्नलिखित में से किसके लिए इडाहो के अपनाए गए ELDT नियम के अनुसार परीक्षा से पहले प्रशिक्षण आवश्यक नहीं है?","options":["पहली बार Class A CDL प्राप्त करना","Class B CDL को Class A CDL में अपग्रेड करना","बिना किसी नए एंडोर्समेंट के मौजूदा CDL का नवीनीकरण","पहली बार HazMat (H) एंडोर्समेंट प्राप्त करना"],"explanation":"ELDT पहली बार के CDL, Class B-से-A अपग्रेड, और पहली बार के P, S, या H एंडोर्समेंट पर लागू होता है; बिना किसी नए विशेषाधिकार के सीधे नवीनीकरण के लिए ELDT आवश्यक नहीं है (Idaho CDL Manual, ITD; 49 CFR 380)।"},"37":{"q":"इडाहो में चिकित्सा स्थिति का स्व-प्रमाणन करते समय, एक चालक जो केवल इडाहो के भीतर संचालन करता है लेकिन राज्य के मेडिकल-कार्ड आवश्यकताओं से छूट प्राप्त है, कौन-सी श्रेणी चुनता है?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"चार स्व-प्रमाणन श्रेणियां NI, EI, NA, और EA हैं; एक चालक जो विशेष रूप से इंट्रास्टेट संचालन करता है और राज्य चिकित्सा प्रमाणन से छूट प्राप्त है, वह Excepted Intrastate (EA) चुनता है (Idaho CDL Manual, ITD; 49 CFR 383.71)।"},"38":{"q":"एक इडाहो CDL आवेदक जो राज्य की सीमाओं के पार वाहन चलाएगा और DOT शारीरिक परीक्षा आवश्यकता के अधीन है, उसे किस श्रेणी में स्व-प्रमाणन करना होगा?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"49 CFR Part 391 के अधीन इंटरस्टेट वाणिज्य में एक चालक Non-Excepted Interstate (NI) चुनता है और उसे एक वैध मेडिकल परीक्षक का प्रमाणपत्र फाइल पर रखना होगा (Idaho CDL Manual, ITD; 49 CFR 383.71)।"},"39":{"q":"इडाहो एक विशेष प्रतिबंधित CDL प्रदान करता है जो 150 मील के भीतर कृषि-संबंधी सेवा कार्य के लिए जीवन में केवल दो बार वैध होता है। इसे क्या कहा जाता है?","options":["एक Provisional CDL","एक Seasonal (प्रतिबंधित) CDL","एक Apprentice CDL","एक Limited Hardship CDL"],"explanation":"इडाहो का Seasonal प्रतिबंधित CDL कृषि-संबंधी सेवा उद्योगों के लिए है, 12 महीने की अवधि में 150 मील के भीतर 180 दिनों तक वैध होता है, और जीवन में केवल दो बार ही प्राप्त किया जा सकता है (ITD DMV CDL आवश्यकताएं; Idaho Code Title 49)।"},"40":{"q":"इडाहो में किसी वाणिज्यिक मोटर वाहन को चलाते समय, एक CDL चालक को किस रक्त अल्कोहल सांद्रता (BAC) पर कानूनी रूप से सीमा से अधिक माना जाता है और अयोग्यता के अधीन माना जाता है?","options":["0.04 या अधिक","0.08 या अधिक","0.02 या अधिक","0.10 या अधिक"],"explanation":"इडाहो किसी वाणिज्यिक मोटर वाहन को चलाने के लिए BAC सीमा 0.04 या अधिक निर्धारित करता है (गैर-वाणिज्यिक चालकों के लिए 0.08 सीमा का आधा)। स्रोत: Idaho Code 49-335; Idaho CDL Manual (ITD)।"},"41":{"q":"इडाहो में, किसी गैर-प्लेकार्ड CMV को चलाते समय DUI जैसे पहले प्रमुख अपराध के लिए दोषी ठहराया गया CDL धारक कम से कम कितने समय के लिए अयोग्य ठहराया जाता है?","options":["1 वर्ष","60 दिन","6 महीने","3 वर्ष"],"explanation":"एक पहला प्रमुख अपराध (DUI, इनकार, घटनास्थल छोड़ना, किसी अपराध में CMV का उपयोग, आदि) इडाहो में न्यूनतम 1-वर्ष की CDL अयोग्यता लाता है। स्रोत: Idaho Code 49-335; Idaho CDL Manual।"},"42":{"q":"यदि कोई इडाहो CDL चालक पहला प्रमुख अपराध (जैसे DUI) तब करता है जब CMV प्लेकार्ड लगाने के लिए आवश्यक खतरनाक सामग्री का परिवहन कर रहा हो, तो न्यूनतम अयोग्यता बढ़कर कितनी हो जाती है:","options":["3 वर्ष","1 वर्ष","2 वर्ष","5 वर्ष"],"explanation":"इडाहो पहले-प्रमुख-अपराध की अयोग्यता को 1 वर्ष से बढ़ाकर न्यूनतम 3 वर्ष कर देता है जब उल्लंघन प्लेकार्ड लगी खतरनाक सामग्री का परिवहन करते समय होता है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"43":{"q":"इडाहो कानून के तहत, किसी अलग घटना में दूसरे प्रमुख अपराध (जैसे दूसरा DUI) के लिए दोषी ठहराए गए CDL धारक के लिए अयोग्यता अवधि क्या है?","options":["आजीवन अयोग्यता","10 वर्ष","5 वर्ष","3 वर्ष"],"explanation":"अलग-अलग घटनाओं से उत्पन्न दो प्रमुख अपराध इडाहो में आजीवन CDL अयोग्यता का परिणाम होते हैं (49 CFR 383.51 के अनुरूप), हालांकि 10-वर्ष का पुनर्बहाली कार्यक्रम उपलब्ध हो सकता है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"44":{"q":"एक इडाहो CDL चालक जो इम्प्लाइड-कंसेंट कानून के तहत अल्कोहल या नशीली दवाओं के लिए एक साक्ष्य परीक्षण से इनकार करता है, उसे कम से कम कितने समय की CDL अयोग्यता का सामना करना पड़ता है:","options":["1 वर्ष","90 दिन","6 महीने","30 दिन"],"explanation":"आवश्यक BAC/नशीली दवा परीक्षण से इनकार को इडाहो में एक प्रमुख अपराध माना जाता है, जो DUI दोषसिद्धि के समान ही न्यूनतम 1-वर्ष की CDL अयोग्यता लाता है (प्लेकार्ड हैज़मैट होने पर 3 वर्ष)। स्रोत: Idaho Code 49-335 और 18-8002 (इम्प्लाइड कंसेंट)।"},"45":{"q":"इडाहो की सड़कों पर वाहन चलाकर, एक मोटर वाहन संचालित करने वाले व्यक्ति को साक्ष्य अल्कोहल/नशीली दवा परीक्षण के लिए सहमति दी हुई माना जाता है। इस सिद्धांत को कहा जाता है:","options":["इम्प्लाइड कंसेंट","प्रोबेबल कॉज़","ड्यू प्रोसेस","प्रशासनिक समीक्षा"],"explanation":"इडाहो का इम्प्लाइड-कंसेंट कानून (Idaho Code 18-8002) किसी भी चालक को साक्ष्य परीक्षण के लिए सहमति दी हुई मानता है; इनकार करने पर CDL अयोग्यता और लाइसेंस निलंबन हो जाता है। स्रोत: Idaho Code 18-8002; Idaho CDL Manual।"},"46":{"q":"इडाहो में, CMV चलाते समय 3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं में दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराए जाने पर CDL अयोग्यता होती है:","options":["60 दिन","30 दिन","120 दिन","90 दिन"],"explanation":"3 वर्षों के भीतर दो गंभीर यातायात उल्लंघन इडाहो में चालक को कम से कम 60 दिनों के लिए अयोग्य ठहराते हैं। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"47":{"q":"एक इडाहो CDL चालक जिसे 3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं में तीन गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया गया है, उसे कितने समय के लिए अयोग्य ठहराया जाता है:","options":["120 दिन","60 दिन","1 वर्ष","180 दिन"],"explanation":"3 वर्षों के भीतर तीसरा गंभीर यातायात उल्लंघन इडाहो में अयोग्यता को कम से कम 120 दिनों तक बढ़ा देता है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"48":{"q":"निम्नलिखित में से किसे इडाहो CDL धारक के लिए एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["निर्धारित सीमा से 15 या अधिक mph तेज़ गति","निर्धारित सीमा से 5 mph तेज़ गति","एक पार्किंग उल्लंघन","एक समाप्त पंजीकरण स्टिकर"],"explanation":"अत्यधिक तेज़ गति, जिसे निर्धारित सीमा से 15 mph या अधिक के रूप में परिभाषित किया गया है, इडाहो में एक गंभीर यातायात उल्लंघन है। 3 वर्षों के भीतर दो या तीन उल्लंघन 60/120-दिन की अयोग्यता को ट्रिगर करते हैं। स्रोत: Idaho Code 49-335; Idaho CDL Manual।"},"49":{"q":"नीचे दिए गए कौन-से उल्लंघन को भी एक गंभीर यातायात उल्लंघन के रूप में गिना जाता है जो इडाहो में CDL अयोग्यता का कारण बन सकता है?","options":["बहुत पास से वाहन चलाना (टेलगेटिंग)","सीमा से 3 mph धीमी गति से वाहन चलाना","एक खाली चौराहे पर मुड़ने का संकेत देने में विफल रहना","एक टूटी हुई टेललाइट"],"explanation":"बहुत पास से वाहन चलाना इडाहो की गंभीर-यातायात-उल्लंघन सूची में है, साथ ही लापरवाही से वाहन चलाना, अनुचित या अनियमित लेन परिवर्तन, और अत्यधिक तेज़ गति भी। स्रोत: Idaho Code 49-335; Idaho CDL Manual।"},"50":{"q":"CMV चलाते समय टेक्स्टिंग करना और बिना उचित CDL प्राप्त किए CMV चलाना, दोनों को इडाहो/FMCSA नियमों द्वारा किस रूप में वर्गीकृत किया गया है:","options":["गंभीर यातायात उल्लंघन","प्रमुख अपराध","आउट-ऑफ-सर्विस उल्लंघन","रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग करना और उचित CDL/क्लास के बिना CMV संचालित करना गंभीर यातायात उल्लंघन हैं (प्रमुख अपराध नहीं), जो 60/120-दिन की अयोग्यता सीमाओं की ओर गिने जाते हैं। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"51":{"q":"CMV चलाते समय किए गए पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए, एक इडाहो CDL चालक को कितने समय के लिए अयोग्य ठहराया जाता है:","options":["60 दिन","30 दिन","120 दिन","1 वर्ष"],"explanation":"एक पहला रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन इडाहो में न्यूनतम 60-दिन की CDL अयोग्यता लाता है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"52":{"q":"एक इडाहो CDL चालक जिसे 3-वर्ष की अवधि के भीतर दूसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए दोषी ठहराया गया है, उसे कितने समय के लिए अयोग्य ठहराया जाता है:","options":["120 दिन","60 दिन","1 वर्ष","90 दिन"],"explanation":"3 वर्षों के भीतर दूसरा रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन इडाहो में न्यूनतम 120-दिन की अयोग्यता का परिणाम होता है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"53":{"q":"इडाहो में 3-वर्ष की अवधि के भीतर तीसरे या बाद के रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["1 वर्ष","120 दिन","180 दिन","60 दिन"],"explanation":"3 वर्षों के भीतर तीसरा या बाद का रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन इडाहो CDL चालक को कम से कम 1 वर्ष के लिए अयोग्य ठहराता है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"54":{"q":"एक इडाहो CDL चालक जिसे किसी गैर-हैज़मैट, गैर-यात्री CMV को चलाते समय आउट-ऑफ-सर्विस (OOS) आदेश के पहले उल्लंघन के लिए दोषी ठहराया गया है, उसे कम से कम कितने समय के लिए अयोग्य ठहराया जाता है:","options":["180 दिन","60 दिन","90 दिन","30 दिन"],"explanation":"एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन इडाहो में न्यूनतम 180-दिन की अयोग्यता (1 वर्ष तक) लाता है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"55":{"q":"इडाहो में, 10-वर्ष की अवधि के भीतर अलग-अलग घटनाओं में दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन कितनी अयोग्यता का परिणाम होता है:","options":["2 से 5 वर्ष","180 दिन से 1 वर्ष","1 वर्ष","3 से 5 वर्ष"],"explanation":"10 वर्षों के भीतर दूसरा OOS-आदेश उल्लंघन इडाहो में चालक को 2 वर्ष से कम नहीं और 5 वर्ष से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"56":{"q":"यदि किसी इडाहो CDL चालक का पहला आउट-ऑफ-सर्विस आदेश उल्लंघन प्लेकार्ड लगी खतरनाक सामग्री का परिवहन करते समय या 16 या अधिक यात्रियों को ले जाते समय होता है, तो न्यूनतम अयोग्यता है:","options":["180 दिन, 2 वर्ष तक","60 दिन, 1 वर्ष तक","30 दिन, 6 महीने तक","1 वर्ष, 3 वर्ष तक"],"explanation":"जब किसी पहले OOS उल्लंघन में प्लेकार्ड हैज़मैट या 16+ यात्री शामिल हों, तो अयोग्यता 180 दिन से कम नहीं और 2 वर्ष से अधिक नहीं होती है। स्रोत: Idaho Code 49-335; 49 CFR 383.51।"},"57":{"q":"चालक अयोग्यता के अलावा, एक इडाहो CDL चालक जो किसी आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है, उस पर कम से कम कितने का संघीय नागरिक दंड लगाया जा सकता है:","options":["पहली दोषसिद्धि के लिए $2,500","पहली दोषसिद्धि के लिए $1,000","पहली दोषसिद्धि के लिए $500","पहली दोषसिद्धि के लिए $5,000"],"explanation":"एक आउट-ऑफ-सर्विस आदेश उल्लंघन पर अयोग्यता के अतिरिक्त पहली दोषसिद्धि के लिए $2,500 से कम नहीं (और बाद की दोषसिद्धियों के लिए $5,000 से कम नहीं) का नागरिक दंड लगता है। स्रोत: Idaho Code 49-335; 49 CFR 383.53।"},"58":{"q":"इडाहो CMV चालकों पर लागू नियमों के तहत, एक वाणिज्यिक मोटर वाहन संचालित करते समय टेक्स्टिंग करने पर एक चालक को अधिकतम कितने नागरिक दंड का सामना करना पड़ सकता है, लगभग:","options":["$2,750","$500","$11,000","$1,000"],"explanation":"एक CMV चालक जो वाहन चलाते समय टेक्स्ट करता है, उसे लगभग $2,750 तक के नागरिक दंड का सामना करना पड़ सकता है, जबकि एक नियोक्ता जो इसकी अनुमति देता है/आवश्यकता रखता है, उस पर लगभग $11,000 तक का जुर्माना लगाया जा सकता है। 3 वर्षों में दो दोषसिद्धियां भी 60-दिन की अयोग्यता लाती हैं। स्रोत: FMCSA No-Texting Rule (49 CFR 392.80); Idaho CDL Manual।"},"59":{"q":"इडाहो में एक CDL चालक जो CMV चलाते समय हैंड-हेल्ड मोबाइल टेलीफोन का उपयोग करता है और 3 वर्षों के भीतर अलग-अलग घटनाओं में ऐसी दो दोषसिद्धियां जमा करता है, उसे कितनी अयोग्यता का सामना करना पड़ता है:","options":["60 दिन","30 दिन","120 दिन","1 वर्ष"],"explanation":"CMV चलाते समय हैंड-हेल्ड फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है; 3 वर्षों के भीतर दो दोषसिद्धियां 60-दिन की अयोग्यता लाती हैं (तीन के लिए 120 दिन)। स्रोत: FMCSA mobile phone rule (49 CFR 392.82); Idaho Code 49-335; 49 CFR 383.51।"},"60":{"q":"Idaho CDL मैनुअल के रेलरोड-क्रॉसिंग नियमों के अनुसार, प्लेकार्ड लगे HazMat वाहन या यात्रियों को ले जा रही बस के चालक को निकटतम रेल से कितनी दूरी पर रुकना चाहिए?","options":["50 फीट के भीतर परंतु 15 फीट से कम नहीं","100 फीट के भीतर परंतु 50 फीट से कम नहीं","25 फीट के भीतर परंतु 5 फीट से कम नहीं","75 फीट के भीतर परंतु 25 फीट से कम नहीं"],"explanation":"Idaho CDL मैनुअल में अपनाए गए संघीय मानक (49 CFR 392.10) का इडाहो पालन करता है: यात्रियों को ले जा रही बसों और प्लेकार्ड लगे HazMat वाहनों को निकटतम रेल से 50 फीट के भीतर परंतु 15 फीट से कम नहीं की दूरी पर रुकना चाहिए। Idaho Code 49-648/49-650 समान 15-से-50-फीट रुकने वाली सीमा का उपयोग करते हैं। स्रोत: Idaho CDL Manual (ITD); Idaho Code 49-648।"},"61":{"q":"जब किसी इडाहो बस या प्लेकार्ड लगे वाहन को रेलरोड क्रॉसिंग पर रुकना आवश्यक हो, तो वाहन का कोई भी हिस्सा पटरियों पर होने के दौरान चालक को कौन-सी क्रिया करनी चाहिए?","options":["क्रॉसिंग करते समय गियर न बदलें","लगातार हॉर्न बजाएं","बीच रास्ते में सबसे निचले गियर में शिफ्ट करें","चारों ओर के फ्लैशर बंद कर दें"],"explanation":"इडाहो का CDL मैनुअल (49 CFR 392.10 के अनुरूप) निर्देश देता है कि चालक ऐसा गियर चुने जो यूनिट को बिना शिफ्ट किए पूरी तरह पार करा दे, और जब वाहन का कोई भी हिस्सा क्रॉसिंग पर हो तब गियर न बदले। स्रोत: Idaho CDL Manual (ITD); Idaho Code 49-649।"},"62":{"q":"किसी आवश्यक स्टॉप पर पटरियों को पार करने से पहले, Idaho CDL मैनुअल कहता है कि बस या प्लेकार्ड-HazMat चालक को क्रॉसिंग के पास पहुंचते समय कौन-सा चेतावनी उपकरण उपयोग करना चाहिए?","options":["चारों ओर के (हैज़र्ड) फ्लैशर चालू करें","तीन परावर्तक त्रिकोण रखें","एयर हॉर्न पर एक लंबा झोंका बजाएं","हाई-बीम हेडलाइट चालू करें"],"explanation":"इडाहो का CDL मैनुअल रेलरोड क्रॉसिंग पर रुकने के लिए आवश्यक चालकों को निर्देश देता है कि पीछे आ रहे ट्रैफ़िक को चेतावनी देने के लिए पास पहुंचते और रुकते समय चारों ओर के आपातकालीन फ्लैशर चालू करें। स्रोत: Idaho CDL Manual (ITD), रेलरोड-क्रॉसिंग अनुभाग।"},"63":{"q":"इडाहो के 'Move Over' कानून (Idaho Code 49-624) के अनुसार, जब आप किसी ऐसे रुके हुए पुलिस, आपातकालीन, टो, या हाईवे घटना-प्रतिक्रिया वाहन के पास पहुंचते हैं जो आपकी दिशा में दो या अधिक लेन वाले हाईवे पर चमकती लाइटें प्रदर्शित कर रहा है, तो आपको:","options":["गति को पोस्टेड सीमा से कम करें और, यदि आसन्न लेन में हों, तो संभव होने पर गैर-आसन्न लेन में बदल जाएं","पोस्टेड गति बनाए रखें परंतु अपना हॉर्न बजाएं","आपातकालीन वाहन के हटने तक पूरी तरह रुक जाएं","लेन तभी बदलें जब किसी अधिकारी द्वारा निर्देशित किया जाए"],"explanation":"Idaho Code 49-624 के अनुसार चालकों को पोस्टेड गति सीमा से कम गति करनी होगी और, बहु-लेन हाईवे पर, स्थिर आपातकालीन/टो/घटना-प्रतिक्रिया वाहन (चमकती लाइटों के साथ) से सटी लेन को जितनी जल्दी उचित रूप से संभव हो गैर-आसन्न लेन में जाकर खाली करना होगा। स्रोत: Idaho Code 49-624।"},"64":{"q":"इडाहो का Move Over कानून (49-624) चमकती लाइटें प्रदर्शित कर रहे स्थिर वाहनों पर लागू होता है। निम्नलिखित में से कौन-सा वाहन प्रकार इस कानून द्वारा विशेष रूप से संरक्षित नहीं है?","options":["पंक्चर टायर के लिए रुकी एक निजी यात्री कार","एक टो ट्रक","एक हाईवे घटना-प्रतिक्रिया वाहन","एक अधिकृत आपातकालीन वाहन"],"explanation":"Idaho Code 49-624 स्थिर पुलिस वाहनों, अधिकृत आपातकालीन वाहनों, टो ट्रकों, और चमकती लाइटें प्रदर्शित कर रहे हाईवे घटना-प्रतिक्रिया वाहनों की रक्षा करता है। एक सामान्य निजी यात्री कार का Move Over कानून में नाम नहीं है। स्रोत: Idaho Code 49-624।"},"65":{"q":"प्रत्येक दिशा में केवल एक लेन वाले दो-लेन हाईवे पर, इडाहो का Move Over कानून चमकती लाइटों वाले स्थिर आपातकालीन वाहन से गुजरने वाले चालक से क्या अपेक्षा करता है:","options":["गति को पोस्टेड सीमा से कम करें और वाहन को पूरी तरह पार करने तक सुरक्षित गति बनाए रखें","पूरी तरह रुक जाएं और प्रतीक्षा करें","जगह देने के लिए सेंटरलाइन पार कर आने वाली लेन में चले जाएं","बिना धीमे हुए पोस्टेड गति पर चलते रहें"],"explanation":"जहां लेन बदलना असंभव हो (प्रत्येक दिशा में एक लेन), Idaho Code 49-624 के अनुसार चालक को गति पोस्टेड सीमा से कम करनी होगी और स्थिर वाहन को पूरी तरह पार करने तक सावधानी से सुरक्षित गति पर आगे बढ़ना होगा। स्रोत: Idaho Code 49-624।"},"66":{"q":"Idaho Code 49-1422 के अनुसार, अपने लाल दृश्य संकेत सक्रिय किए हुए रुकी हुई सामने से आ रही स्कूल बस से मिलने वाले वाहन के चालक को रुकना आवश्यक नहीं केवल तब होता है जब हाईवे में हो:","options":["तीन से अधिक लेन","दो से अधिक लेन","एक चित्रित सेंटर टर्न लेन","किसी भी चौड़ाई का कोई भी विभाजित मध्य-भाग"],"explanation":"Idaho Code 49-1422 कहता है कि तीन (3) से अधिक लेन वाले हाईवे पर सामने से आ रहे ट्रैफ़िक को संकेत सक्रिय किए हुए स्कूल बस से मिलते समय रुकना आवश्यक नहीं है। इडाहो इस अपवाद को लेन संख्या (>3 लेन) से जोड़ता है, केवल मध्य-भाग से नहीं। स्रोत: Idaho Code 49-1422।"},"67":{"q":"एक मानक दो-लेन इडाहो सड़क पर, अपने लाल दृश्य संकेत चमकाते हुए रुकी हुई स्कूल बस से मिलने वाले या उससे आगे निकलने वाले वाहन के चालक को क्या करना चाहिए:","options":["बस तक पहुंचने से पहले रुकें और संकेत बंद होने या बस के चलने तक आगे न बढ़ें","20 mph तक धीमा करें और सावधानी से गुजरें","केवल तभी रुकें जब बच्चे दिखाई दें","केवल तभी रुकें जब पीछे से आगे निकल रहे हों, मिलते समय नहीं"],"explanation":"Idaho Code 49-1422 के अनुसार किसी भी दिशा से मिलने वाले या आगे निकलने वाले चालक को 49-915 के दृश्य संकेत प्रदर्शित कर रही स्कूल बस तक पहुंचने से पहले रुकना होगा, और बस के फिर से चलने या संकेत बंद होने तक आगे नहीं बढ़ना होगा (>3-लेन वाले सामने से आने वाले अपवाद को छोड़कर)। स्रोत: Idaho Code 49-1422।"},"68":{"q":"1 जुलाई 2026 तक, Idaho Code 49-654 के अनुसार, 26,000 lbs से अधिक वाले पांच-या-अधिक-एक्सल ट्रक को गैर-शहरी (NONURBAN) क्षेत्रों में इंटरस्टेट हाईवे पर अधिकतम गति की सीमा है:","options":["हल्के वाहनों की सीमा से 10 mph कम","हर जगह बिल्कुल 65 mph","हल्के वाहनों की सीमा से 5 mph कम","यात्री कारों के समान गति"],"explanation":"30 जून 2026 तक प्रभावी Idaho Code 49-654 के संस्करण के अनुसार, भारी ट्रक (5+ एक्सल, 26,000 lbs से अधिक) गैर-शहरी इंटरस्टेट पर हल्के वाहनों से 10 mph कम से अधिक नहीं चल सकते। House Bill 664 इन सीमाओं को 1 जुलाई 2026 से प्रभावी रूप से समान कर देता है। स्रोत: Idaho Code 49-654; HB664 (2026)।"},"69":{"q":"1 जुलाई 2026 से प्रभावी, Idaho House Bill 664 भारी ट्रकों (5+ एक्सल, 26,000 lbs से अधिक) के लिए गति नियम को बदलता है ताकि इंटरस्टेट, राज्य हाईवे, और अन्य स्थानों पर उनकी अधिकतम वैध गति होगी:","options":["पांच एक्सल से कम और 26,000 lbs या उससे कम वाले वाहनों के समान","गैर-शहरी इंटरस्टेट पर यात्री कारों से अब भी 10 mph कम","पोस्टेड सीमा की परवाह किए बिना पूरे राज्य में 70 mph पर सीमित","केवल सभी शहरी क्षेत्रों में 65 mph पर सीमित"],"explanation":"HB664 Idaho Code 49-654 में संशोधन करता है ताकि, 1 जुलाई 2026 से प्रभावी, भारी ट्रक हल्के वाहनों के समान पोस्टेड अधिकतम गति सीमाओं के अधीन हों, पूर्व 10-mph-कम और 65-mph-शहरी ट्रक सीमाओं को समाप्त करते हुए। स्रोत: Idaho HB664 (2026); Idaho Code 49-654।"},"70":{"q":"Idaho Code 49-654 के अनुसार, इडाहो इंटरस्टेट हाईवे पर (एक इंजीनियरिंग अध्ययन के बाद, हल्के वाहनों के लिए) पोस्ट की जा सकने वाली अधिकतम गति सीमा है:","options":["80 mph","75 mph","70 mph","85 mph"],"explanation":"Idaho Code 49-654 इंटरस्टेट पर 75 mph का आधार निर्धारित करता है परंतु ITD को एक इंजीनियरिंग और ट्रैफ़िक अध्ययन के बाद इंटरस्टेट हाईवे पर सीमा को 80 mph तक बढ़ाने का अधिकार देता है; इडाहो के कई ग्रामीण इंटरस्टेट खंडों पर 80 mph पोस्ट किया गया है। स्रोत: Idaho Code 49-654; ITD।"},"71":{"q":"Idaho Code 49-654 के अनुसार, पोस्टेड सीमा के अभाव में, किसी भी आवासीय, व्यावसायिक, या शहरी जिले में डिफ़ॉल्ट अधिकतम गति है:","options":["35 mph","25 mph","30 mph","20 mph"],"explanation":"Idaho Code 49-654 किसी भी आवासीय, व्यावसायिक, या शहरी जिले में डिफ़ॉल्ट अधिकतम 35 mph निर्धारित करता है जब तक अन्यथा पोस्ट न किया गया हो। स्रोत: Idaho Code 49-654।"},"72":{"q":"Idaho Code 49-630 इडाहो हाईवे पर लेन उपयोग को नियंत्रित करता है। ट्रैफ़िक के सामान्य प्रवाह से धीमी गति से चल रहा वाहन, जैसे चढ़ाई चढ़ रहा एक लदा हुआ ट्रक, को क्या करना चाहिए:","options":["दाहिनी लेन में या जितना व्यावहारिक हो दाहिने किनारे के निकट चलें","ट्रैफ़िक को संतुलित करने के लिए मध्य लेन का उपयोग करें","मर्जिंग के लिए दाहिनी लेन खाली रखने हेतु बाईं लेन में रहें","जब तक संकेत दे रहे हों तब तक कोई भी लेन चुनें"],"explanation":"Idaho Code 49-630 के अनुसार ट्रैफ़िक की सामान्य गति से कम पर चल रहे किसी भी वाहन को उपलब्ध दाहिनी लेन में, या जितना व्यावहारिक हो दाहिने कर्ब/किनारे के निकट चलाया जाना चाहिए, सिवाय जब आगे निकल रहे हों या बाएं मुड़ने की तैयारी कर रहे हों। स्रोत: Idaho Code 49-630।"},"73":{"q":"एक विभाजित या एकतरफ़ा सड़क पर, Idaho CDL मैनुअल एक रुके हुए वाणिज्यिक वाहन को आ रहे ट्रैफ़िक की ओर अपने तीन आपातकालीन चेतावनी उपकरण किन दूरियों पर रखने का निर्देश देता है?","options":["आ रहे ट्रैफ़िक की ओर 10 फीट, 100 फीट, और 200 फीट","आ रहे ट्रैफ़िक की ओर 10 फीट, 50 फीट, और 100 फीट","आ रहे ट्रैफ़िक की ओर 15 फीट, 100 फीट, और 300 फीट","आ रहे ट्रैफ़िक की ओर 25 फीट, 100 फीट, और 500 फीट"],"explanation":"एकतरफ़ा या विभाजित हाईवे पर, Idaho CDL मैनुअल (49 CFR 392.22 के अनुसार) वाहन से आ रहे ट्रैफ़िक की ओर 10 फीट, 100 फीट, और 200 फीट पर चेतावनी उपकरण आवश्यक करता है। स्रोत: Idaho CDL Manual (ITD)।"},"74":{"q":"एक दो-लेन, दोतरफ़ा इडाहो सड़क पर, Idaho CDL मैनुअल एक रुके हुए CMV के लिए तीन आवश्यक चेतावनी उपकरण कहां रखने को कहता है?","options":["वाहन के 10 फीट के भीतर, और उसके 100 फीट पीछे तथा 100 फीट आगे","तीनों वाहन के पिछले हिस्से के 10 फीट के भीतर","केवल पीछे 50 फीट, 200 फीट, और 500 फीट पर","वाहन के पीछे 100 फीट, 200 फीट, और 300 फीट"],"explanation":"एक दो-लेन, दोतरफ़ा सड़क पर Idaho CDL मैनुअल (49 CFR 392.22 के अनुसार) ट्रैफ़िक की ओर वाले हिस्से पर वाहन के 10 फीट के भीतर एक उपकरण, लगभग 100 फीट पीछे एक, और लगभग 100 फीट आगे एक, शोल्डर पर या रुकने वाली लेन में आवश्यक करता है। स्रोत: Idaho CDL Manual (ITD)।"},"75":{"q":"यदि कोई CMV किसी इडाहो दो-लेन सड़क पर किसी पहाड़ी, मोड़, या अन्य अवरोध के 500 फीट के भीतर रुका हो, तो Idaho CDL मैनुअल क्या कहता है:","options":["चालकों को अधिक चेतावनी देने के लिए पिछले चेतावनी उपकरण को 100 से 500 फीट के बीच पीछे हटाएं","तीनों त्रिकोणों को मानक 10/100/100-फीट स्थानों पर छोड़ दें","तीनों उपकरणों को सीधे वाहन के पीछे ढेर कर दें","त्रिकोण हटा दें और केवल फ्लैशर पर निर्भर रहें"],"explanation":"जब किसी पहाड़ी, मोड़, या दृष्टि दूरी सीमित करने वाले अवरोध के 500 फीट के भीतर रुका हो, तो Idaho CDL मैनुअल (49 CFR 392.22 के अनुसार) निर्देश देता है कि सबसे पिछले चेतावनी उपकरण को सड़क पर पीछे की ओर वाहन से 100 से 500 फीट के बिंदु तक हटाया जाए ताकि आ रहे चालकों को पर्याप्त चेतावनी मिले। स्रोत: Idaho CDL Manual (ITD)।"},"76":{"q":"Idaho CDL मैनुअल एक रुके हुए CMV को किसी हाईवे पर रुकने के कितने समय के भीतर अपने चेतावनी उपकरण (फ्लेयर या त्रिकोण) प्रदर्शित करना आवश्यक करता है?","options":["10 मिनट","5 मिनट","15 मिनट","30 मिनट"],"explanation":"Idaho CDL मैनुअल (49 CFR 392.22 के अनुसार) किसी हाईवे के यात्रा वाले हिस्से या शोल्डर पर रुकने के 10 मिनट के भीतर आपातकालीन चेतावनी उपकरण रखना आवश्यक करता है। स्रोत: Idaho CDL Manual (ITD)।"},"77":{"q":"Lewiston Grade और White Bird Grade जैसी US-95 ढलानें इडाहो में खड़ी पहाड़ी उतराई के लिए उल्लेखनीय हैं। ये ढलानें ब्रेकिंग क्षमता खो देने वाले ट्रकों के लिए कौन-सी सुरक्षा सुविधा प्रदान करती हैं?","options":["आपातकालीन निकास (रनअवे-ट्रक) रैंप","भारी ट्रकों के लिए अनिवार्य टोल बूथ","इनके चारों ओर मोड़ने वाला राज्यव्यापी ट्रक-मार्ग प्रतिबंध","सड़क में निर्मित इलेक्ट्रॉनिक स्पीड गवर्नर"],"explanation":"इडाहो की खड़ी US-95 पहाड़ी ढलानें (Lewiston Grade, White Bird Grade) आपातकालीन निकास/रनअवे-ट्रक रैंप से सुसज्जित हैं जो ब्रेक खो चुके वाहन को रोकने के लिए लंबे बजरी के बेड का उपयोग करती हैं। ITD इन उतराइयों के लिए अग्रिम साइनेज लगाता है। स्रोत: Idaho Transportation Department (ITD), US-95 escape-ramp परियोजनाएं।"},"78":{"q":"इडाहो के राज्य हाईवे प्रणाली पर कोई टोल रोड या टोल-वित्तपोषित इंटरस्टेट पुल नहीं हैं। इडाहो के पार मार्ग की योजना बना रहे एक CDL चालक के लिए, इसका अर्थ है:","options":["इडाहो के इंटरस्टेट या राज्य हाईवे पर कोई टोल नहीं लिया जाता","टोल केवल Snake River पर इंटरस्टेट पुलों पर लिया जाता है","भारी ट्रक I-84 पर प्रति-मील टोल देते हैं","टोल केवल Boise मेट्रो बायपास में लागू होता है"],"explanation":"इडाहो अपनी सार्वजनिक हाईवे प्रणाली पर कोई टोल रोड या टोल पुल नहीं चलाता; इंटरस्टेट और राज्य हाईवे टोल-मुक्त हैं। CDL चालकों को इसके बजाय ITD द्वारा प्रशासित ओवरसाइज़/ओवरवेट परमिट और प्रतिबंधित-मार्ग आवश्यकताओं के आसपास योजना बनानी चाहिए, टोल के नहीं। स्रोत: Idaho Transportation Department (ITD)।"},"79":{"q":"इडाहो में वाणिज्यिक चालक लाइसेंस (Commercial Driver's Licenses) जारी करने के लिए ज़िम्मेदार राज्य चालक लाइसेंसिंग एजेंसी कौन-सी एजेंसी है?","options":["Idaho Transportation Department (ITD)","Idaho State Police Commercial Vehicle Services","Federal Motor Carrier Safety Administration","Idaho Department of Motor Vehicle Safety"],"explanation":"Idaho Transportation Department (ITD) DMV इडाहो की राज्य चालक लाइसेंसिंग एजेंसी है और CDL जारी करती है। स्रोत: ITD DMV Commercial Driver's License (CDL) पृष्ठ; ITD 'Ten Steps to Getting an Idaho CDL'।"},"80":{"q":"इडाहो में, एक CDL आवेदक वास्तव में आवेदन करने, लिखित परीक्षाएं देने, और लाइसेंस जारी करवाने के लिए कहां जाता है?","options":["एक निजी रूप से संचालित ITD परीक्षण फ्रेंचाइज़ी","एक काउंटी शेरिफ़ का चालक लाइसेंसिंग (DMV) कार्यालय","एक FMCSA फील्ड कार्यालय","केवल Boise में ITD मुख्यालय"],"explanation":"इडाहो चालक लाइसेंसिंग काउंटी-प्रशासित है: आवेदक एक काउंटी शेरिफ़ के चालक लाइसेंसिंग कार्यालय में जाते हैं, जो CDL आवेदन, ज्ञान परीक्षाओं, और जारी करने को संभालता है जबकि ITD रिकॉर्ड संसाधित करता है। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 4।"},"81":{"q":"लाइसेंस मिलने से पहले, प्रत्येक नए इडाहो CDL आवेदक को अभ्यास करने और कौशल परीक्षा देने के लिए सबसे पहले कौन-सा क्रेडेंशियल प्राप्त करना होगा?","options":["एक Commercial Learner's Permit (CLP)","एक Class D अनुदेश परमिट","एक संघीय इंटरस्टेट प्राधिकार कार्ड","एक अनंतिम वाणिज्यिक एंडोर्समेंट"],"explanation":"इडाहो के अनुसार आवेदकों को वाणिज्यिक लाइसेंस प्राप्त करने या उन्नत करने और कौशल परीक्षा से पहले सार्वजनिक सड़कों पर अभ्यास करने के लिए एक Commercial Learner's Permit (CLP) प्राप्त करना होगा। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 5।"},"82":{"q":"एक इडाहो Commercial Learner's Permit (CLP) जारी होने के बाद कितने समय तक वैध रहता है?","options":["180 दिन","90 दिन","दो वर्ष","एक वर्ष"],"explanation":"इडाहो का CLP एक वर्ष के लिए वैध है (इडाहो की अवधि कुछ राज्यों द्वारा उपयोग की जाने वाली 180-दिन की न्यूनतम से भिन्न है)। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 5।"},"83":{"q":"इडाहो में लागू संघीय नियमों के अनुसार, CDL कौशल परीक्षा देने की अनुमति मिलने से पहले एक आवेदक को कितने समय तक CLP धारण करना होगा?","options":["कम से कम 30 दिन","कम से कम 10 दिन","कम से कम 14 दिन","कम से कम 60 दिन"],"explanation":"इडाहो द्वारा अपनाए गए FMCSA नियमों के अनुसार कौशल परीक्षा देने से पहले CLP को कम से कम 14 दिन धारण करना आवश्यक है, भले ही केवल मौजूदा CDL को उन्नत किया जा रहा हो। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Steps 5 और 9।"},"84":{"q":"इडाहो CDL कौशल परीक्षा किन तीन भागों से बनी है?","options":["लिखित परीक्षा, नेत्र परीक्षण, और रोड टेस्ट","एयर ब्रेक टेस्ट, बैकिंग टेस्ट, और वेट-स्टेशन टेस्ट","प्री-ट्रिप निरीक्षण, सिम्युलेटर टेस्ट, और रात्रि ड्राइविंग","प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग"],"explanation":"इडाहो FMCSA तीन-भाग कौशल परीक्षा का पालन करता है: प्री-ट्रिप (वाहन) निरीक्षण, बुनियादी वाहन नियंत्रण (बंद-कोर्स मैन्यूवर), और ऑन-रोड ड्राइविंग टेस्ट। स्रोत: ITD CDL मैनुअल; ITD 'Ten Easy Steps to a C.D.L.' Steps 6-9।"},"85":{"q":"इडाहो में परीक्षा के दिन, एक आवेदक को प्री-ट्रिप वाहन निरीक्षण पूरा करने के लिए कितना समय दिया जाता है?","options":["45 मिनट","15 मिनट","60 मिनट","30 मिनट"],"explanation":"इडाहो परीक्षा के दिन प्री-ट्रिप निरीक्षण भाग पूरा करने के लिए 45 मिनट देता है; एक अनुचित ब्रेक जांच असफलता का एक सामान्य कारण है। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 6।"},"86":{"q":"इडाहो के बुनियादी-नियंत्रण (बैकिंग) भाग में, सभी आवेदकों से कौन-से दो मैन्यूवर आवश्यक हैं?","options":["ऐली डॉक और पैरेलल पार्क","सीधी रेखा में बैक और ऐली डॉक","सीधी रेखा में बैक और ऑफसेट बैक","पैरेलल पार्क और सर्पेंटाइन"],"explanation":"इडाहो प्रत्येक आवेदक से सीधी रेखा में बैक और ऑफसेट बैक आवश्यक करता है; फिर परीक्षक या तो ऐली डॉक या पैरेलल पार्क का चयन करता है। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 7 (Chapter 12 मैन्यूवर)।"},"87":{"q":"कौशल परीक्षा देने के योग्य होने से पहले एक इडाहो CDL आवेदक को एक पंजीकृत प्रदाता से कौन-सा प्रशिक्षण पूरा करना होगा?","options":["एक राज्य-अनुमोदित रक्षात्मक ड्राइविंग पाठ्यक्रम","एक ITD सुरक्षा अभिविन्यास सेमिनार","एक OSHA वाणिज्यिक वाहन पाठ्यक्रम","Entry-Level Driver Training (ELDT)"],"explanation":"7 फरवरी 2022 से, आवेदकों को आवश्यक कौशल परीक्षाएं देने से पहले FMCSA के Training Provider Registry पर मौजूद किसी प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना होगा। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 5; FMCSA ELDT नियम।"},"88":{"q":"इडाहो के CDL स्व-प्रमाणन में, एक आवेदक को कितनी ड्राइविंग श्रेणियों में से चुनना होगा?","options":["दो","तीन","पांच","चार"],"explanation":"इडाहो CDL धारकों को चार श्रेणियों में से एक के लिए स्व-प्रमाणित करना होगा: interstate non-excepted, interstate excepted, intrastate non-excepted, या intrastate excepted। स्रोत: ITD 'Medical Cards & Self Certification Categories' चार्ट; FMCSA 49 CFR 383.71।"},"89":{"q":"अधिकांश CDL चालकों के लिए इडाहो द्वारा किस स्व-प्रमाणन श्रेणी को मेडिकल-कार्ड-आवश्यक 'गोल्ड स्टैंडर्ड' के रूप में वर्णित किया गया है, जो राज्य की सीमाओं के पार ड्राइविंग की अनुमति देती है?","options":["Interstate excepted","Intrastate non-excepted","Interstate non-excepted","Intrastate excepted"],"explanation":"इडाहो interstate non-excepted को 'गोल्ड स्टैंडर्ड' कहता है: चालक चिकित्सकीय रूप से प्रमाणित है और राज्य की सीमाओं को पार कर सकता है तथा कुछ भी ढो सकता है। स्रोत: ITD 'Medical Cards & Self Certification Categories' चार्ट।"},"90":{"q":"कौन-सी इडाहो स्व-प्रमाणन श्रेणी के लिए एक वैध DOT मेडिकल प्रमाणपत्र आवश्यक है भले ही सारी ड्राइविंग इडाहो के भीतर ही रहती हो?","options":["Intrastate excepted","Intrastate non-excepted","Interstate excepted","Non-CDL excepted"],"explanation":"Intrastate non-excepted चालक इडाहो के भीतर रहते हैं परंतु फिर भी चिकित्सकीय रूप से प्रमाणित होते हैं (जैसे, गैर-छूट वाली वस्तुएं ढोना), और इससे एक 'K' (केवल-इंट्रास्टेट) प्रतिबंध जुड़ता है। स्रोत: ITD 'Medical Cards & Self Certification Categories' चार्ट।"},"91":{"q":"जब कोई चालक किसी इंट्रास्टेट श्रेणी के लिए स्व-प्रमाणन करता है तो इडाहो CDL में कौन-सा प्रतिबंध जोड़ता है?","options":["एक 'L' प्रतिबंध (कोई एयर ब्रेक नहीं)","एक 'K' प्रतिबंध (केवल इंट्रास्टेट संचालन)","एक 'E' प्रतिबंध (केवल स्वचालित ट्रांसमिशन)","एक 'O' प्रतिबंध (कोई फिफ्थ-व्हील नहीं)"],"explanation":"किसी भी इंट्रास्टेट श्रेणी (excepted या non-excepted) के लिए स्व-प्रमाणन एक 'K' प्रतिबंध जोड़ता है जो चालक को केवल इंट्रास्टेट संचालन तक सीमित करता है। स्रोत: ITD 'Medical Cards & Self Certification Categories' चार्ट; 49 CFR 383.95।"},"92":{"q":"एक non-excepted इडाहो CDL धारक एक नया DOT मेडिकल परीक्षक प्रमाणपत्र प्राप्त करता है। उन्हें इसके साथ क्या करना होगा?","options":["काउंटी DMV/ITD को एक प्रति जमा करें ताकि इसे ड्राइविंग रिकॉर्ड में जोड़ा जाए","इसे केवल रोडसाइड निरीक्षणों के लिए ट्रक में रखें","मूल को FMCSA को Washington, D.C. में डाक से भेजें","इसे राज्य के बजाय अपने नियोक्ता के पास दाखिल करें"],"explanation":"Non-excepted CDL धारकों को ME प्रमाणपत्र प्राप्त करने पर और प्रत्येक नवीनीकरण पर काउंटी DMV/ITD को एक प्रति जमा (प्रदान) करनी होगी ताकि इसे ड्राइविंग रिकॉर्ड में पोस्ट किया जाए। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 4।"},"93":{"q":"एक इडाहो CDL के लिए उपयोग किया जाने वाला DOT मेडिकल परीक्षक प्रमाणपत्र अधिकतम कितने समय के लिए जारी किया जा सकता है?","options":["12 महीने तक","36 महीने तक","24 महीने तक","48 महीने तक"],"explanation":"एक DOT फिजिकल/मेडिकल परीक्षक प्रमाणपत्र 24 महीने तक के लिए वैध है; एक परीक्षक किसी चिकित्सा स्थिति की निगरानी के लिए इसे कम समय के लिए जारी कर सकता है। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 2।"},"94":{"q":"एक इडाहो CDL आवेदक के लिए DOT फिजिकल करने वाला चिकित्सा प्रदाता कहां सूचीबद्ध होना चाहिए?","options":["Idaho Board of Medicine CDL पैनल पर","National Registry of Certified Medical Examiners पर","अनुमोदित चिकित्सकों की ITD सूची पर","FMCSA carrier safety रोस्टर पर"],"explanation":"परीक्षण करने वाला प्रदाता FMCSA के National Registry of Certified Medical Examiners पर सूचीबद्ध होना चाहिए; एक अपंजीकृत प्रदाता का उपयोग CDL डाउनग्रेड का कारण बन सकता है। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 2; ITD मेडिकल प्रमाणपत्र सूचना।"},"95":{"q":"एक इडाहो आवेदक के पास किए गए CDL ज्ञान (लिखित) परीक्षा परिणाम सभी लिखित परीक्षाएं दोबारा देनी पड़ने से पहले कितने समय तक वैध रहते हैं?","options":["पास होने की तारीख से एक वर्ष","पास होने की तारीख से छह महीने","पास होने की तारीख से दो वर्ष","पास होने की तारीख से 90 दिन"],"explanation":"ज्ञान परीक्षा परिणाम पास होने की तारीख से एक वर्ष तक वैध रहते हैं; यदि उस वर्ष के भीतर CDL प्राप्त नहीं किया जाता, तो सभी लिखित परीक्षाएं दोबारा देनी होंगी। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 4।"},"96":{"q":"यदि कोई इडाहो आवेदक CDL ज्ञान (लिखित) परीक्षा में असफल हो जाता है, तो वे कितनी जल्दी इसे दोबारा दे सकते हैं?","options":["उसी दिन","तीन दिन के बाद","सात दिन के बाद","चौदह दिन के बाद"],"explanation":"एक आवेदक जो लिखित परीक्षा में असफल होता है वह तीन दिन के बाद दोबारा परीक्षा दे सकता है (और प्रति-परीक्षा शुल्क फिर से चुकाना होगा)। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 4।"},"97":{"q":"कौशल परीक्षा पास करने के बाद, एक मानक नए जारी किए गए इडाहो CDL की वैधता अवधि क्या है?","options":["केवल दो वर्ष","केवल एक वर्ष","चार वर्ष (आठ-वर्ष का विकल्प भी उपलब्ध)","निश्चित छह वर्ष"],"explanation":"इडाहो CDL को चार वर्ष के लिए जारी करता है; ITD एक आठ-वर्ष का विकल्प भी प्रदान करता है। पास होने के बाद लाइसेंस जारी करवाने के लिए चालक को काउंटी DMV वापस जाना होगा। स्रोत: ITD 'Ten Steps to Getting an Idaho CDL' Step 10।"},"98":{"q":"परीक्षक द्वारा लिया जाने वाला इडाहो का CDL कौशल परीक्षा शुल्क Idaho Code के तहत कैसे नियंत्रित होता है?","options":["यह हर राज्य में एक समान संघीय रूप से निर्धारित राशि है","यह सभी पहली-बार के आवेदकों के लिए माफ़ किया जाता है","यह केवल आवेदक के प्रशिक्षण स्कूल द्वारा निर्धारित किया जाता है","यह सीमित है और प्रति परीक्षा Idaho Code द्वारा निर्धारित अधिकतम से अधिक नहीं हो सकता"],"explanation":"परीक्षक-निर्धारित कौशल परीक्षा शुल्क Idaho Code द्वारा सीमित है (प्रति परीक्षा वैधानिक अधिकतम से अधिक नहीं), जो छोटे काउंटी हिस्से से अलग है। सटीक डॉलर राशियां बदल सकती हैं। स्रोत: ITD 'Ten Easy Steps to a C.D.L.' Step 9।"}},"ar":{"0":{"q":"على الطرق السريعة في ولاية أيداهو، ما هو الحد الأقصى القانوني لعرض المركبة، بما في ذلك حمولتها؟","options":["8 أقدام و6 بوصات","8 أقدام و0 بوصة","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"تحدّ مدونة أيداهو 49-1010 من العرض الإجمالي لأي مركبة، بما في ذلك حمولتها، إلى 8 أقدام و6 بوصات (102 بوصة). وتتطلب الحمولات الأعرض من ذلك تصريح حمولة كبيرة الحجم. المصدر: Idaho Code 49-1010 (حجم المركبات والحمولات)."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة وحمولتها على الطرق السريعة في ولاية أيداهو؟","options":["13 قدمًا و6 بوصات","14 قدمًا","15 قدمًا","13 قدمًا"],"explanation":"تحدد مدونة أيداهو 49-1010 الحد الأقصى لارتفاع المركبة، بما في ذلك الحمولة، عند 14 قدمًا. وتحتاج الحمولات التي يزيد ارتفاعها عن 14 قدمًا إلى تصريح ارتفاع زائد. المصدر: Idaho Code 49-1010."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي على محور واحد في ولاية أيداهو؟","options":["18,000 رطل","22,400 رطل","20,000 رطل","21,500 رطل"],"explanation":"تحدد مدونة أيداهو 49-1001 الحد الأقصى للوزن الإجمالي للمحور الواحد عند 20,000 رطل. المصدر: Idaho Code 49-1001 (الأحمال الإجمالية المسموح بها)."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على محور مزدوج (تاندم) في ولاية أيداهو؟","options":["34,000 رطل","36,000 رطل","32,000 رطل","40,000 رطل"],"explanation":"بموجب مدونة أيداهو 49-1001، يجوز أن تحمل مجموعة من المحاور المزدوجة (التاندم) ما يصل إلى 34,000 رطل، بما يتوافق مع المعيار الفيدرالي. المصدر: Idaho Code 49-1001."},"4":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة أو التركيبة المسموح به على الجزء التابع لأيداهو من نظام الطرق السريعة الفيدرالية بين الولايات وطرق الدفاع الأمريكية دون تصريح؟","options":["80,000 رطل","105,500 رطل","90,000 رطل","129,000 رطل"],"explanation":"تحدد مدونة أيداهو 49-1001 سقف الوزن الإجمالي للمركبة أو التركيبة على الطرق السريعة الفيدرالية بين الولايات وطرق الدفاع عند 80,000 رطل، بما يتسق مع القانون الفيدرالي. المصدر: Idaho Code 49-1001."},"5":{"q":"على الطرق السريعة العامة (غير الطرق بين الولايات) للولاية في أيداهو، ما هو الحد الأقصى للوزن الإجمالي للمركبة أو التركيبة المسموح به بموجب القانون الأساسي قبل اللجوء إلى تصريح خاص للوزن الزائد؟","options":["80,000 رطل","129,000 رطل","100,000 رطل","105,500 رطل"],"explanation":"تسمح مدونة أيداهو 49-1001 بحد أقصى للوزن الإجمالي للمركبة أو التركيبة يبلغ 105,500 رطل، باستثناء أن الحد ينخفض إلى 80,000 رطل على الطرق السريعة الفيدرالية بين الولايات وطرق الدفاع. المصدر: Idaho Code 49-1001."},"6":{"q":"ما هو الحد الأقصى للوزن الإجمالي المسموح به على عجلة واحدة في ولاية أيداهو؟","options":["8,000 رطل","12,000 رطل","10,000 رطل","6,000 رطل"],"explanation":"تحدد مدونة أيداهو 49-1001 الحد الأقصى للوزن الإجمالي للعجلة الواحدة عند 10,000 رطل. المصدر: Idaho Code 49-1001."},"7":{"q":"تستخدم ولاية أيداهو صيغة وزن الجسر الفيدرالية لتحديد الحد الأقصى للوزن المسموح به على مجموعة من المحاور المتتالية. أي صيغة تعتمدها مدونة أيداهو؟","options":["W = 500((LN/N-1) + 12N + 36)","W = 1000(L + N + 20)","W = 34,000 + (N x 12)","W = 250(LN + 12 + 36N)"],"explanation":"تعتمد مدونة أيداهو 49-1001(1) صيغة الجسر الفيدرالية W = 500((LN/N-1) + 12N + 36)، حيث W هو الوزن الأقصى، وL هو المسافة بالأقدام بين طرفي مجموعة المحاور، وN هو عدد المحاور. المصدر: Idaho Code 49-1001(1)."},"8":{"q":"في صيغة الجسر الخاصة بأيداهو، ماذا يمثل المتغير 'L'؟","options":["التصنيف القانوني لحمولة المقطورة","المسافة بالأقدام بين طرفي مجموعة من محورين متتاليين أو أكثر","طول أطول مجموعة محاور مفردة فقط","الوزن الإجمالي المرخّص للمركبة"],"explanation":"في الصيغة W = 500((LN/N-1) + 12N + 36)، يمثل 'L' المسافة بالأقدام بين طرفي أي مجموعة من محورين متتاليين أو أكثر، و'N' هو عدد المحاور، و'W' هو الوزن الأقصى. المصدر: Idaho Code 49-1001(1)."},"9":{"q":"لا يجوز أن تحمل مجموعتان متتاليتان من المحاور المزدوجة (التاندم) 34,000 رطل لكل منهما في ولاية أيداهو إلا إذا كانت المسافة الكلية بين المحور الأول والمحور الأخير من تلك المجموعات المزدوجة لا تقل عن كم قدمًا؟","options":["30 قدمًا","36 قدمًا","40 قدمًا","34 قدمًا"],"explanation":"تسمح مدونة أيداهو 49-1001(1)(b) لمجموعتين متتاليتين من المحاور المزدوجة بحمل 34,000 رطل لكل منهما شريطة أن تكون المسافة بين المحور الأول والمحور الأخير من تلك المجموعات 36 قدمًا أو أكثر. المصدر: Idaho Code 49-1001(1)(b)."},"10":{"q":"لا يجوز أن يتجاوز طول نصف المقطورة العاملة على الطرق التي تشكل جزءًا من الشبكة الوطنية في أيداهو كم؟","options":["48 قدمًا","53 قدمًا","57 قدمًا","45 قدمًا"],"explanation":"تحدّ مدونة أيداهو 49-1010 من طول نصف المقطورة العاملة على الشبكة الوطنية (وطرق الوصول المرتبطة بها) إلى 53 قدمًا. المصدر: Idaho Code 49-1010."},"11":{"q":"بموجب مدونة أيداهو، لا يجوز عمومًا أن تمتد الحمولة على المركبة إلى أبعد من مقدمة المركبة بأكثر من كم قدمًا؟","options":["3 أقدام","4 أقدام","6 أقدام","قدمان"],"explanation":"تحظر مدونة أيداهو 49-1010 امتداد الحمولة إلى أبعد من مقدمة المركبة بأكثر من 4 أقدام. المصدر: Idaho Code 49-1010."},"12":{"q":"يجوز لتركيبة مركبات تنقل حمولة قابلة للتقليل أن تعمل بوزن إجمالي يتجاوز 105,500 رطل في ولاية أيداهو، لكن دون تجاوز أي وزن، وفقط على الطرق غير الواقعة بين الولايات المحددة لذلك مع التسجيل والتصريح المناسبين؟","options":["129,000 رطل","117,000 رطل","140,000 رطل","125,500 رطل"],"explanation":"تسمح مدونة أيداهو 49-1001(1)(c) بالحمولات القابلة للتقليل التي تتجاوز 105,500 رطل لكن دون تجاوز 129,000 رطل على الطرق السريعة غير الواقعة بين الولايات عندما تكون المركبة مسجّلة وتمتثل لصيغة الوزن وقيود الطول وتعمل على الطرق المحددة وفقًا لمدونة أيداهو 49-1004. المصدر: Idaho Code 49-1001(1)(c) و49-1004."},"13":{"q":"من الذي يصدر التصريح السنوي للطريق الخاص الذي يخوّل تركيبة مسجّلة بنقل حمولات قابلة للتقليل تتراوح بين 105,501 و129,000 رطل في ولاية أيداهو؟","options":["مأمور المقاطعة في كل مقاطعة على الطريق","إدارة الطرق السريعة الفيدرالية","إدارة النقل في أيداهو (Idaho Transportation Department) أو، وفقًا لتقديرها، وكالة طرق سريعة عامة محلية","أي محطة وزن في استراحة شاحنات تجارية"],"explanation":"تنص مدونة أيداهو 49-1004 على أن تصاريح الطرق الخاصة للحمولات من 105,501 وحتى 129,000 رطل تصدرها إدارة النقل في أيداهو، أو وفقًا لتقديرها وكالة طرق سريعة عامة محلية، على الطرق التي تحددها الإدارة أو السلطات المحلية. المصدر: Idaho Code 49-1004."},"14":{"q":"أي مما يلي يُطلب عمومًا قبل أن تتمكن مركبة تتجاوز حدود الحجم أو الوزن القانونية في أيداهو من التحرك على الطريق السريع؟","options":["تصريح ساري المفعول للحجم الكبير/الوزن الزائد يتم الحصول عليه قبل التحرك","تغيير إلى رخصة CDL من الفئة A","إعفاء فيدرالي من FMCSA","مجرد موافقة شفهية من ضابط نقطة الدخول"],"explanation":"تتطلب مدونة أيداهو 49-1004 وقواعد التصاريح الخاصة بإدارة النقل (ITD) تصريحًا للحجم الكبير و/أو الوزن الزائد، يتم الحصول عليه قبل التحرك، لتشغيل مركبة تتجاوز حدود الحجم أو الوزن القانونية؛ ويجب حمل التصريح في المركبة. المصدر: Idaho Code 49-1004؛ قواعد تصاريح ITD (IDAPA 39.03.03)."},"15":{"q":"يمنح قانون أيداهو استثناءً في الوزن (جدول منفصل وأكثر سماحًا للمسافات بين المحاور) على الطرق السريعة غير الواقعة بين الولايات للمركبات التي تنقل سلعًا معينة. أي مجموعة من السلع مشمولة؟","options":["جذوع الأشجار ولب الخشب والأخشاب الخام والأعمدة والخامات والرمل والحصى والسلع الزراعية بما في ذلك الماشية","البقالة المبردة والمشروبات المعبأة","السيارات الجديدة والمركبات الترفيهية","المواد الخطرة والوقود السائب فقط"],"explanation":"توفر مدونة أيداهو 49-1001(2) جدول حمولة مسموحًا بها خاصًا للمركبات التي تنقل جذوع الأشجار ولب الخشب والأخشاب القصيرة (stull) والأخشاب الخام والأعمدة أو الركائز؛ والخامات والمركّزات والرمل والحصى والركام السائب؛ أو السلع الزراعية بما في ذلك الماشية. المصدر: Idaho Code 49-1001(2)."},"16":{"q":"لا تنطبق علاوات الوزن الخاصة بجذوع الأشجار والخامات والرمل/الحصى والسلع الزراعية في مدونة أيداهو 49-1001(2) بمجرد أن يكون المقصود أن يتجاوز إجمالي الوزن الإجمالي أي رقم، وفقًا لما يعلنه المشغّل؟","options":["80,000 رطل","79,000 رطل","105,500 رطل","84,000 رطل"],"explanation":"تنص مدونة أيداهو 49-1001(2) على أن علاوات وزن السلع لا تنطبق إذا كان المقصود أن يتجاوز إجمالي الوزن الإجمالي 79,000 رطل وفقًا لما يعلنه المشغّل. المصدر: Idaho Code 49-1001(2)."},"17":{"q":"عند نقطة دخول في أيداهو، لا يجوز لمركبة محمّلة أن تتجاوز الميزان عندما يتجاوز وزن محور واحد الحد الأقصى بمقدار كم؟","options":["500 رطل أو أكثر","1,000 رطل أو أكثر","2,000 رطل أو أكثر","5,000 رطل أو أكثر"],"explanation":"تنص مدونة أيداهو 49-1001(8) على أنه لا يجوز للمركبة أن تتجاوز نقطة الدخول عندما يتجاوز محور واحد الحد الأقصى بمقدار 2,000 رطل أو أكثر، أو عندما يتجاوز الوزن الإجمالي/وزن مجموعة المحاور الحد الأقصى بنسبة 7% أو أكثر. المصدر: Idaho Code 49-1001(8)."},"18":{"q":"عند نقطة دخول في أيداهو، بأي نسبة مئوية تجاوزًا للحد الأقصى المسموح به للوزن الإجمالي أو وزن مجموعة المحاور سيتم إيقاف المركبة ومطالبتها بالامتثال قبل الاستمرار؟","options":["7 بالمئة أو أكثر","5 بالمئة أو أكثر","10 بالمئة أو أكثر","15 بالمئة أو أكثر"],"explanation":"تتطلب مدونة أيداهو 49-1001(8) إعادة المركبة إلى الامتثال عند الميزان عندما يتجاوز وزنها الإجمالي أو وزن مجموعة من المحاور الحد الأقصى المسموح به بنسبة 7 بالمئة أو أكثر (وحد المحور الواحد هو 2,000 رطل). المصدر: Idaho Code 49-1001(8)."},"19":{"q":"تتطلب ولاية أيداهو مرافقات (سيارات إرشاد/إعلام) للحمولات المرخّصة الزائدة العرض. عند أي عرض للحمولة تتطلب أيداهو عمومًا سيارة إرشاد/مرافقة واحدة على الأقل؟","options":["أكثر من 8 أقدام و6 بوصات عرضًا","أكثر من 10 أقدام عرضًا","أكثر من 12 قدمًا عرضًا","أكثر من 16 قدمًا عرضًا"],"explanation":"بموجب قواعد حركة الأحمال كبيرة الحجم الخاصة بإدارة النقل (ITD)، تتطلب الحمولة التي يزيد عرضها عن 12 قدمًا عمومًا سيارة إرشاد/مرافقة واحدة، وتتطلب الحمولات التي يزيد عرضها عن 14 قدمًا سيارتين. ويُطلب وضع أعلام على زوايا الحمولات الزائدة العرض، وتُطلب لافتة OVERSIZE LOAD وأضواء كهرمانية على سيارات المرافقة. المصدر: قواعد تصاريح ITD (IDAPA 39.03.05 / متطلبات سيارات الإرشاد والمرافقة)."},"20":{"q":"في ولاية أيداهو، تُطلب رخصة CDL لتشغيل أي مركبة مفردة بتصنيف وزن إجمالي للمركبة (GVWR) يبلغ كم رطلًا أو أكثر (دون قطر أي شيء يزيد عن 10,000 رطل)؟","options":["16,001 رطل","26,001 رطل","33,001 رطل","10,001 رطل"],"explanation":"تعتمد أيداهو الحد الفيدرالي: تُطلب رخصة CDL من الفئة B لأي مركبة مفردة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر (دليل CDL في أيداهو، ITD؛ 49 CFR 383.91)."},"21":{"q":"أي فئة من رخصة CDL في أيداهو تُطلب لقيادة مركبة تركيبية بتصنيف وزن إجمالي للتركيبة (GCWR) يبلغ 26,001 رطل أو أكثر حيث تتجاوز الوحدة (الوحدات) المقطورة 10,000 رطل من تصنيف GVWR؟","options":["الفئة C","الفئة B","الفئة A","الفئة D"],"explanation":"تغطي رخصة CDL من الفئة A المركبات التركيبية بتصنيف GCWR يبلغ 26,001 رطل أو أكثر شريطة أن يتجاوز تصنيف GVWR للمركبة (المركبات) المقطورة 10,000 رطل (دليل CDL في أيداهو، ITD)."},"22":{"q":"بموجب قواعد أيداهو، تتطلب المركبة المصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) لكن أقل من حدود وزن الفئة A/B أي فئة من رخصة CDL؟","options":["الفئة C","الفئة A","الفئة B","لا تُطلب رخصة CDL"],"explanation":"تُطلب رخصة CDL من الفئة C للمركبات التي لا تستوفي معايير الفئة A أو B لكنها مصممة لنقل 16 راكبًا أو أكثر بما في ذلك السائق، أو تنقل مواد خطرة تتطلب لافتات (placards) (دليل CDL في أيداهو، ITD)."},"23":{"q":"أي حرف تصديق تخصصه أيداهو لصلاحية قيادة مركبات الصهاريج (الناقلات) التي تنقل السوائل أو الغازات سائبة؟","options":["T","N","X","H"],"explanation":"تصديق N مخصص لمركبات الصهاريج. (T = مقطورات مزدوجة/ثلاثية، H = مواد خطرة، X = صهاريج ومواد خطرة معًا.) المصدر: دليل CDL في أيداهو، ITD؛ 49 CFR 383.93."},"24":{"q":"في أيداهو، يخوّل تصديق 'T' حامله بتشغيل أي نوع من المركبات؟","options":["مركبات الصهاريج","المركبات التي تنقل مواد خطرة","المقطورات المزدوجة والثلاثية","المركبات التي تنقل 16 راكبًا أو أكثر"],"explanation":"يغطي تصديق T المقطورات المزدوجة والثلاثية ويتطلب اجتياز اختبار معرفي فقط (دليل CDL في أيداهو، ITD؛ 49 CFR 383.93)."},"25":{"q":"للحصول على تصديق المواد الخطرة (HazMat) (H) في أيداهو، يجب على مقدم الطلب اجتياز اختبار معرفي وكذلك استيفاء أي متطلب فيدرالي إضافي؟","options":["اختبار مهارات خلف عجلة القيادة","تقييم تهديد أمني من إدارة أمن النقل TSA (فحص الخلفية)","طلب إعفاء بصري","فحص طبي ثانٍ"],"explanation":"تتطلب أيداهو من مقدم طلب تصديق H اجتياز اختبار معرفي واجتياز تقييم تهديد أمني من إدارة أمن النقل TSA (فحص خلفية قائم على البصمات) بموجب قانون USA PATRIOT (دليل CDL في أيداهو، ITD؛ 49 CFR 1572)."},"26":{"q":"في أيداهو، قبل إصدار تصديق حافلة المدرسة (S)، أي تصديق آخر يجب على مقدم الطلب أيضًا أن يحمله أو يحصل عليه؟","options":["N (صهريج)","T (مزدوج/ثلاثي)","P (ركاب)","H (مواد خطرة)"],"explanation":"يتطلب تصديق S (حافلة المدرسة) تصديق P (الركاب)، بالإضافة إلى اختبار معرفي واختبار مهارات في حافلة مدرسة (دليل CDL في أيداهو، ITD؛ 49 CFR 383.123)."},"27":{"q":"أي تصديق CDL في أيداهو يتطلب اختبارًا معرفيًا واختبار مهارات خلف عجلة القيادة معًا في مركبة تمثيلية؟","options":["N (صهريج)","P (ركاب)","T (مزدوج/ثلاثي)","H (مواد خطرة)"],"explanation":"يتطلب تصديق P (الركاب) اجتياز اختبار معرفي واختبار مهارات في مركبة ركاب؛ أما N وT وH فهي تصديقات تتطلب اختبارًا معرفيًا فقط (دليل CDL في أيداهو، ITD؛ 49 CFR 383.93)."},"28":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في أيداهو لقيادة مركبة تجارية داخل أيداهو فقط (داخل الولاية)؟","options":["16 عامًا","18 عامًا","19 عامًا","21 عامًا"],"explanation":"تسمح أيداهو برخصة CDL داخل الولاية عند سن 18 عامًا؛ ويجب على مقدم الطلب أيضًا أن يحمل رخصة أيداهو سارية من الفئة D ولديه سنة واحدة من خبرة القيادة المرخّصة (دليل CDL في أيداهو، ITD؛ Idaho Code 49-305)."},"29":{"q":"ما هو الحد الأدنى للعمر الذي تتطلبه أيداهو (تبعًا للقانون الفيدرالي) لقيادة مركبة تجارية عبر حدود الولايات (بين الولايات)؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"تتطلب القيادة التجارية بين الولايات حدًا أدنى للعمر يبلغ 21 عامًا؛ ويقتصر حامل رخصة CDL في أيداهو البالغ 18 عامًا على التشغيل داخل الولاية (دليل CDL في أيداهو، ITD؛ 49 CFR 391.11)."},"30":{"q":"لا يجوز إصدار تصديق المواد الخطرة (HazMat) (H) في أيداهو لمقدم طلب يقل عمره عن أي سن؟","options":["18","19","21","25"],"explanation":"نظرًا لأن نقل المواد الخطرة بمقابل ينطوي عمومًا على تجارة بين الولايات وتقييم من TSA، يتطلب تصديق H أن يكون مقدم الطلب 21 عامًا على الأقل (دليل CDL في أيداهو، ITD؛ 49 CFR 383/1572)."},"31":{"q":"بموجب القواعد الفيدرالية المعتمدة في أيداهو، كم من الوقت يجب أن يحمل السائق رخصة المتعلّم التجارية (CLP) قبل أن يكون مؤهلاً لأداء اختبار مهارات CDL؟","options":["7 أيام على الأقل","14 يومًا على الأقل","30 يومًا على الأقل","60 يومًا على الأقل"],"explanation":"يجب حمل رخصة CLP لمدة 14 يومًا كحد أدنى قبل إمكان أداء اختبار المهارات (دليل CDL في أيداهو، ITD؛ 49 CFR 383.25)."},"32":{"q":"كم من الوقت تكون رخصة المتعلّم التجارية (CLP) في أيداهو سارية المفعول قبل أن يلزم تجديدها؟","options":["90 يومًا","180 يومًا","سنة واحدة","سنتان"],"explanation":"تكون رخصة CLP في أيداهو سارية لمدة 180 يومًا ويجوز تجديدها مرة واحدة لمدة 180 يومًا إضافية دون إعادة أداء اختبار المعرفة العام (دليل CDL في أيداهو، ITD؛ 49 CFR 383.25)."},"33":{"q":"أثناء القيادة برخصة المتعلّم التجارية (CLP) في أيداهو، يجب أن يكون حاملها مصحوبًا دائمًا بماذا؟","options":["أي شخص بالغ مرخّص له عمره 25 عامًا أو أكثر","حامل رخصة CDL من الفئة/التصديق المناسب جالس بجوار السائق","فاحص من DMV","لا أحد؛ القيادة المنفردة مسموح بها"],"explanation":"يجوز لحامل رخصة CLP تشغيل مركبة تجارية (CMV) فقط عندما يكون مصحوبًا بشخص يحمل رخصة CDL سارية لنوع المركبة ويجلس بجوار السائق (دليل CDL في أيداهو، ITD؛ 49 CFR 383.25)."},"34":{"q":"أي مستند ليس من بين المستندات التي يطلبها قسم المركبات الآلية (DMV) في أيداهو للتقدم بطلب للحصول على رخصة CDL؟","options":["إثبات الهوية","إثبات رقم الضمان الاجتماعي","إثبات الإقامة في أيداهو والوجود القانوني","خطاب موقّع من صاحب عمل حالي"],"explanation":"تتطلب أيداهو إثبات الهوية ورقم الضمان الاجتماعي والإقامة في أيداهو والوجود/المواطنة القانونية؛ ولا يُطلب خطاب من صاحب العمل (دليل CDL في أيداهو / متطلبات DMV في ITD)."},"35":{"q":"منذ 7 فبراير 2022، يجب على مقدم طلب رخصة CDL لأول مرة في أيداهو إكمال تدريب السائقين المبتدئين (ELDT) المقدم من جهة مدرجة أين؟","options":["قائمة أكاديمية شرطة ولاية أيداهو","سجل مزوّدي التدريب (TPR) التابع لـ FMCSA","قائمة مدارس إدارة النقل في أيداهو","أي كلية مجتمع معتمدة"],"explanation":"يجب إكمال تدريب ELDT من خلال مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل أداء اختبار المهارات، اعتبارًا من 7 فبراير 2022 (دليل CDL في أيداهو، ITD؛ 49 CFR 380 Subpart F)."},"36":{"q":"أي مما يلي لا تتطلب قاعدة ELDT المعتمدة في أيداهو تدريبًا عليه قبل الاختبار؟","options":["الحصول على رخصة CDL من الفئة A لأول مرة","ترقية رخصة CDL من الفئة B إلى الفئة A","تجديد رخصة CDL قائمة دون تصديقات جديدة","الحصول على تصديق المواد الخطرة (HazMat) (H) لأول مرة"],"explanation":"ينطبق تدريب ELDT على رخص CDL لأول مرة، وترقيات الفئة B إلى A، وتصديقات P أو S أو H لأول مرة؛ أما التجديد المباشر دون امتيازات جديدة فلا يتطلب ELDT (دليل CDL في أيداهو، ITD؛ 49 CFR 380)."},"37":{"q":"عند المصادقة الذاتية على الحالة الطبية في أيداهو، فإن السائق الذي يعمل داخل أيداهو فقط لكنه معفى من متطلبات البطاقة الطبية للولاية يختار أي فئة؟","options":["غير معفى بين الولايات (NI)","معفى بين الولايات (EI)","غير معفى داخل الولاية (NA)","معفى داخل الولاية (EA)"],"explanation":"فئات المصادقة الذاتية الأربع هي NI وEI وNA وEA؛ ويختار السائق الذي يعمل حصريًا داخل الولاية ومعفى من المصادقة الطبية للولاية فئة معفى داخل الولاية (EA) (دليل CDL في أيداهو، ITD؛ 49 CFR 383.71)."},"38":{"q":"يجب على مقدم طلب رخصة CDL في أيداهو الذي سيقود عبر حدود الولايات ويخضع لمتطلب الفحص البدني من DOT أن يصادق ذاتيًا على أي فئة؟","options":["غير معفى بين الولايات (NI)","معفى بين الولايات (EI)","غير معفى داخل الولاية (NA)","معفى داخل الولاية (EA)"],"explanation":"يختار السائق العامل في التجارة بين الولايات والخاضع لـ 49 CFR Part 391 فئة غير معفى بين الولايات (NI) ويجب أن يحتفظ بشهادة فاحص طبي سارية في ملفه (دليل CDL في أيداهو، ITD؛ 49 CFR 383.71)."},"39":{"q":"تقدّم أيداهو رخصة CDL مقيّدة خاصة سارية مرتين فقط مدى الحياة لأعمال الخدمة المتعلقة بالمزارع ضمن 150 ميلاً. ماذا تُسمى؟","options":["رخصة CDL مؤقتة","رخصة CDL موسمية (مقيّدة)","رخصة CDL متدرب","رخصة CDL محدودة لحالات المشقّة"],"explanation":"تخدم رخصة CDL الموسمية المقيّدة في أيداهو صناعات الخدمات المتعلقة بالمزارع، وهي سارية لمدة تصل إلى 180 يومًا في فترة 12 شهرًا ضمن 150 ميلاً، ولا يجوز الحصول عليها إلا مرتين مدى الحياة (متطلبات CDL في DMV التابعة لـ ITD؛ Idaho Code Title 49)."},"40":{"q":"أثناء تشغيل مركبة تجارية آلية في أيداهو، يُعتبر سائق رخصة CDL متجاوزًا للحد قانونيًا ويخضع لإلغاء الأهلية عند أي تركيز للكحول في الدم (BAC)؟","options":["0.04 أو أكثر","0.08 أو أكثر","0.02 أو أكثر","0.10 أو أكثر"],"explanation":"تحدد أيداهو حد تركيز الكحول في الدم BAC لتشغيل مركبة تجارية آلية عند 0.04 أو أكثر (نصف حد 0.08 للسائقين غير التجاريين). المصدر: Idaho Code 49-335؛ دليل CDL في أيداهو (ITD)."},"41":{"q":"في أيداهو، يُلغى تأهيل حامل رخصة CDL المُدان بأول مخالفة كبرى مثل القيادة تحت تأثير الكحول (DUI) أثناء قيادة مركبة تجارية آلية غير حاملة للافتات لمدة لا تقل عن كم؟","options":["سنة واحدة","60 يومًا","6 أشهر","3 سنوات"],"explanation":"تحمل أول مخالفة كبرى (القيادة تحت التأثير، الرفض، مغادرة مكان الحادث، استخدام مركبة تجارية في جناية، إلخ) حدًا أدنى لإلغاء أهلية رخصة CDL مدته سنة واحدة في أيداهو. المصدر: Idaho Code 49-335؛ دليل CDL في أيداهو."},"42":{"q":"إذا ارتكب سائق رخصة CDL في أيداهو أول مخالفة كبرى (مثل القيادة تحت التأثير) أثناء نقل المركبة التجارية الآلية لمواد خطرة يُطلب وضع لافتات عليها، فإن الحد الأدنى لإلغاء الأهلية يرتفع إلى:","options":["3 سنوات","سنة واحدة","سنتان","5 سنوات"],"explanation":"تمدد أيداهو إلغاء أهلية أول مخالفة كبرى من سنة واحدة إلى ما لا يقل عن 3 سنوات عندما تقع المخالفة أثناء نقل مواد خطرة تحمل لافتات. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"43":{"q":"بموجب قانون أيداهو، ما هي مدة إلغاء الأهلية لحامل رخصة CDL المُدان بمخالفة كبرى ثانية (مثل قيادة ثانية تحت التأثير) في حادثة منفصلة؟","options":["إلغاء الأهلية مدى الحياة","10 سنوات","5 سنوات","3 سنوات"],"explanation":"ينتج عن مخالفتين كبريين ناشئتين عن حادثتين منفصلتين إلغاء أهلية رخصة CDL مدى الحياة في أيداهو (محاكاةً لـ 49 CFR 383.51)، رغم احتمال توفر برنامج إعادة تأهيل بعد 10 سنوات. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"44":{"q":"سائق رخصة CDL في أيداهو الذي يرفض الخضوع لاختبار إثباتي للكحول أو المخدرات بموجب قانون الموافقة الضمنية يواجه إلغاء أهلية رخصة CDL لمدة لا تقل عن:","options":["سنة واحدة","90 يومًا","6 أشهر","30 يومًا"],"explanation":"يُعامل رفض اختبار BAC/المخدرات المطلوب كمخالفة كبرى في أيداهو، ويحمل نفس الحد الأدنى لإلغاء أهلية رخصة CDL مدته سنة واحدة مثل الإدانة بالقيادة تحت التأثير (3 سنوات في حال المواد الخطرة الحاملة للافتات). المصدر: Idaho Code 49-335 و18-8002 (الموافقة الضمنية)."},"45":{"q":"بقيادة الطرق في أيداهو، يُعتبر الشخص الذي يشغّل مركبة آلية أنه قد أعطى موافقته على الاختبار الإثباتي للكحول/المخدرات. يُعرف هذا المبدأ باسم:","options":["الموافقة الضمنية","السبب المحتمل","الإجراءات القانونية الواجبة","المراجعة الإدارية"],"explanation":"يعتبر قانون الموافقة الضمنية في أيداهو (Idaho Code 18-8002) أن أي سائق قد وافق على الاختبار الإثباتي؛ ويؤدي الرفض إلى إلغاء أهلية رخصة CDL وتعليق الرخصة. المصدر: Idaho Code 18-8002؛ دليل CDL في أيداهو."},"46":{"q":"في أيداهو، تؤدي الإدانة بمخالفتين مروريتين خطيرتين في حادثتين منفصلتين خلال فترة 3 سنوات أثناء قيادة مركبة تجارية آلية إلى إلغاء أهلية رخصة CDL لمدة:","options":["60 يومًا","30 يومًا","120 يومًا","90 يومًا"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات إلى إلغاء أهلية السائق لمدة لا تقل عن 60 يومًا في أيداهو. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"47":{"q":"سائق رخصة CDL في أيداهو المُدان بثلاث مخالفات مرورية خطيرة في حوادث منفصلة خلال فترة 3 سنوات تُلغى أهليته لمدة:","options":["120 يومًا","60 يومًا","سنة واحدة","180 يومًا"],"explanation":"ترفع المخالفة المرورية الخطيرة الثالثة خلال 3 سنوات إلغاء الأهلية إلى ما لا يقل عن 120 يومًا في أيداهو. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"48":{"q":"أي مما يلي يُصنّف كمخالفة مرورية خطيرة لحامل رخصة CDL في أيداهو؟","options":["تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد المعلن","تجاوز السرعة بمقدار 5 أميال في الساعة فوق الحد المعلن","مخالفة وقوف","ملصق تسجيل منتهي الصلاحية"],"explanation":"تجاوز السرعة المفرط، المعرّف بأنه 15 ميلاً في الساعة أو أكثر فوق الحد المعلن، هو مخالفة مرورية خطيرة في أيداهو. وتؤدي مخالفتان أو ثلاث خلال 3 سنوات إلى إلغاء أهلية لمدة 60/120 يومًا. المصدر: Idaho Code 49-335؛ دليل CDL في أيداهو."},"49":{"q":"أي مخالفة أدناه تُحتسب أيضًا كمخالفة مرورية خطيرة يمكن أن تؤدي إلى إلغاء أهلية رخصة CDL في أيداهو؟","options":["القيادة بمسافة قريبة جدًا (الالتصاق بالمركبة الأمامية)","القيادة بسرعة أقل من الحد بمقدار 3 أميال في الساعة","عدم الإشارة عند الانعطاف عند تقاطع خالٍ","ضوء خلفي مكسور"],"explanation":"القيادة بمسافة قريبة جدًا مدرجة على قائمة المخالفات المرورية الخطيرة في أيداهو، إلى جانب القيادة المتهورة وتغييرات المسار غير السليمة أو غير المنتظمة وتجاوز السرعة المفرط. المصدر: Idaho Code 49-335؛ دليل CDL في أيداهو."},"50":{"q":"الكتابة على الهاتف أثناء قيادة مركبة تجارية آلية وقيادة مركبة تجارية آلية دون الحصول على رخصة CDL المناسبة، كلاهما مصنّف بموجب قواعد أيداهو/FMCSA على أنه:","options":["مخالفات مرورية خطيرة","مخالفات كبرى","مخالفات خارج الخدمة","مخالفات معابر السكك الحديدية"],"explanation":"الكتابة على الهاتف أثناء قيادة مركبة تجارية آلية وتشغيل مركبة تجارية آلية دون رخصة/فئة CDL المناسبة هما مخالفتان مروريتان خطيرتان (وليستا مخالفتين كبريين)، وتُحتسبان ضمن عتبات إلغاء الأهلية لمدة 60/120 يومًا. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"51":{"q":"بالنسبة لأول مخالفة عند معبر السكك الحديدية مع الطريق السريع تُرتكب أثناء قيادة مركبة تجارية آلية، تُلغى أهلية سائق رخصة CDL في أيداهو لمدة:","options":["60 يومًا","30 يومًا","120 يومًا","سنة واحدة"],"explanation":"تحمل أول مخالفة عند معبر السكك الحديدية حدًا أدنى لإلغاء أهلية رخصة CDL مدته 60 يومًا في أيداهو. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"52":{"q":"سائق رخصة CDL في أيداهو المُدان بمخالفة ثانية عند معبر السكك الحديدية مع الطريق السريع خلال فترة 3 سنوات تُلغى أهليته لمدة:","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"تؤدي المخالفة الثانية عند معبر السكك الحديدية خلال 3 سنوات إلى حد أدنى لإلغاء الأهلية مدته 120 يومًا في أيداهو. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"53":{"q":"ما هي مدة إلغاء الأهلية لمخالفة ثالثة أو لاحقة عند معبر السكك الحديدية مع الطريق السريع خلال فترة 3 سنوات في أيداهو؟","options":["سنة واحدة","120 يومًا","180 يومًا","60 يومًا"],"explanation":"تؤدي المخالفة الثالثة أو اللاحقة عند معبر السكك الحديدية خلال 3 سنوات إلى إلغاء أهلية سائق رخصة CDL في أيداهو لمدة لا تقل عن سنة واحدة. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"54":{"q":"سائق رخصة CDL في أيداهو المُدان بأول مخالفة لأمر خارج الخدمة (OOS) أثناء قيادة مركبة تجارية آلية غير حاملة لمواد خطرة وغير ناقلة للركاب تُلغى أهليته لمدة لا تقل عن:","options":["180 يومًا","60 يومًا","90 يومًا","30 يومًا"],"explanation":"تحمل أول مخالفة لأمر خارج الخدمة حدًا أدنى لإلغاء الأهلية مدته 180 يومًا (حتى سنة واحدة) في أيداهو. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"55":{"q":"في أيداهو، تؤدي مخالفة ثانية لأمر خارج الخدمة في حوادث منفصلة خلال فترة 10 سنوات إلى إلغاء أهلية لمدة:","options":["2 إلى 5 سنوات","180 يومًا إلى سنة واحدة","سنة واحدة","3 إلى 5 سنوات"],"explanation":"تؤدي مخالفة ثانية لأمر خارج الخدمة خلال 10 سنوات إلى إلغاء أهلية السائق لمدة لا تقل عن سنتين ولا تزيد عن 5 سنوات في أيداهو. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"56":{"q":"إذا وقعت أول مخالفة لأمر خارج الخدمة لسائق رخصة CDL في أيداهو أثناء نقل مواد خطرة تحمل لافتات أو نقل 16 راكبًا أو أكثر، فإن الحد الأدنى لإلغاء الأهلية هو:","options":["180 يومًا، حتى سنتين","60 يومًا، حتى سنة واحدة","30 يومًا، حتى 6 أشهر","سنة واحدة، حتى 3 سنوات"],"explanation":"عندما تنطوي أول مخالفة لأمر خارج الخدمة على مواد خطرة تحمل لافتات أو 16 راكبًا أو أكثر، يكون إلغاء الأهلية لمدة لا تقل عن 180 يومًا ولا تزيد عن سنتين. المصدر: Idaho Code 49-335؛ 49 CFR 383.51."},"57":{"q":"إلى جانب إلغاء أهلية السائق، يخضع سائق رخصة CDL في أيداهو الذي يخالف أمرًا خارج الخدمة لعقوبة مدنية فيدرالية لا تقل عن:","options":["$2,500 لأول إدانة","$1,000 لأول إدانة","$500 لأول إدانة","$5,000 لأول إدانة"],"explanation":"تحمل مخالفة أمر خارج الخدمة عقوبة مدنية لا تقل عن $2,500 لأول إدانة (ولا تقل عن $5,000 للإدانات اللاحقة)، بالإضافة إلى إلغاء الأهلية. المصدر: Idaho Code 49-335؛ 49 CFR 383.53."},"58":{"q":"بموجب القواعد التي تنطبق على سائقي المركبات التجارية الآلية في أيداهو، فإن الحد الأقصى للعقوبة المدنية التي يمكن أن يواجهها السائق للكتابة على الهاتف أثناء تشغيل مركبة تجارية آلية يبلغ تقريبًا:","options":["$2,750","$500","$11,000","$1,000"],"explanation":"يمكن أن يواجه سائق المركبة التجارية الآلية الذي يكتب على الهاتف أثناء القيادة عقوبة مدنية تصل إلى نحو $2,750، بينما يمكن تغريم صاحب العمل الذي يسمح بذلك/يطلبه بما يصل إلى نحو $11,000. وتؤدي إدانتان خلال 3 سنوات أيضًا إلى إلغاء أهلية لمدة 60 يومًا. المصدر: قاعدة منع الكتابة على الهاتف من FMCSA (49 CFR 392.80)؛ دليل CDL في أيداهو."},"59":{"q":"سائق رخصة CDL في أيداهو الذي يستخدم هاتفًا محمولاً باليد أثناء قيادة مركبة تجارية آلية ويتراكم لديه إدانتان من هذا النوع في حوادث منفصلة خلال 3 سنوات يواجه إلغاء أهلية لمدة:","options":["60 يومًا","30 يومًا","120 يومًا","سنة واحدة"],"explanation":"استخدام هاتف محمول باليد أثناء قيادة مركبة تجارية آلية هو مخالفة مرورية خطيرة؛ وتؤدي إدانتان خلال 3 سنوات إلى إلغاء أهلية لمدة 60 يومًا (120 يومًا لثلاث إدانات). المصدر: قاعدة الهاتف المحمول من FMCSA (49 CFR 392.82)؛ Idaho Code 49-335؛ 49 CFR 383.51."},"60":{"q":"بموجب قواعد معابر السكك الحديدية في دليل CDL لولاية أيداهو، على سائق مركبة محمّلة بمواد خطرة (HazMat) تحمل لوحات تحذيرية أو حافلة تقل ركابًا أن يتوقف على أي مسافة من أقرب قضيب سكة؟","options":["ضمن مسافة 50 قدمًا ولكن ليس أقل من 15 قدمًا","ضمن مسافة 100 قدم ولكن ليس أقل من 50 قدمًا","ضمن مسافة 25 قدمًا ولكن ليس أقل من 5 أقدام","ضمن مسافة 75 قدمًا ولكن ليس أقل من 25 قدمًا"],"explanation":"تتبع ولاية أيداهو المعيار الفيدرالي (49 CFR 392.10) المعتمد في دليل CDL لولاية أيداهو: على الحافلات التي تقل ركابًا والمركبات المحمّلة بمواد خطرة (HazMat) التي تحمل لوحات تحذيرية أن تتوقف ضمن مسافة 50 قدمًا ولكن ليس أقل من 15 قدمًا من أقرب قضيب سكة. ويستخدم Idaho Code 49-648/49-650 نطاق التوقف نفسه من 15 إلى 50 قدمًا. المصدر: Idaho CDL Manual (ITD)؛ Idaho Code 49-648."},"61":{"q":"عندما يُطلب من حافلة أو مركبة تحمل لوحات تحذيرية في ولاية أيداهو التوقف عند معبر سكة حديدية، ما الإجراء الذي يجب على السائق القيام به أثناء وجود أي جزء من المركبة على القضبان؟","options":["عدم تغيير التروس أثناء العبور","إطلاق البوق بشكل متواصل","التحويل إلى أدنى ترس في منتصف العبور","إطفاء الأضواء الوامضة الرباعية"],"explanation":"يوجّه دليل CDL لولاية أيداهو (الذي يعكس 49 CFR 392.10) السائق إلى اختيار ترس يسحب الوحدة عبر المعبر بالكامل دون تغيير التروس، وعدم تغيير التروس أثناء وجود أي جزء من المركبة على المعبر. المصدر: Idaho CDL Manual (ITD)؛ Idaho Code 49-649."},"62":{"q":"قبل عبور القضبان عند توقف إلزامي، يقول دليل CDL لولاية أيداهو إنه يجب على سائق الحافلة أو المركبة المحمّلة بمواد خطرة (HazMat) ذات اللوحات التحذيرية استخدام أي معدات تحذير أثناء اقتراب المركبة من المعبر؟","options":["تشغيل الأضواء الوامضة الرباعية (أضواء الخطر)","وضع ثلاثة مثلثات عاكسة","إطلاق نفخة طويلة على البوق الهوائي","تشغيل المصابيح الأمامية ذات الشعاع العالي"],"explanation":"يوجّه دليل CDL لولاية أيداهو السائقين الملزمين بالتوقف عند معابر السكك الحديدية إلى تشغيل الأضواء الوامضة الرباعية للطوارئ عند الاقتراب والتوقف، لتحذير حركة المرور التي تتبعهم. المصدر: Idaho CDL Manual (ITD)، قسم معابر السكك الحديدية."},"63":{"q":"بموجب قانون \"أفسح المجال\" (Move Over) في ولاية أيداهو (Idaho Code 49-624)، عندما تقترب من مركبة شرطة أو طوارئ أو قطر أو مركبة استجابة لحوادث الطرق متوقفة وتعرض أضواءً وامضة على طريق به مساران أو أكثر في اتجاهك، يجب عليك:","options":["تخفيض السرعة إلى أقل من الحد المعلن، والانتقال إلى مسار غير مجاور إن كنت في المسار المجاور وكان ذلك ممكنًا","الحفاظ على السرعة المعلنة مع إطلاق البوق","التوقف تمامًا حتى تتحرك مركبة الطوارئ","تغيير المسار فقط إذا أمر بذلك ضابط"],"explanation":"يلزم Idaho Code 49-624 السائقين بتخفيض السرعة إلى أقل من الحد المعلن، وعلى الطريق متعدد المسارات إخلاء المسار المجاور لمركبة الطوارئ/القطر/الاستجابة للحوادث الثابتة (التي تعرض أضواءً وامضة) بالانتقال إلى مسار غير مجاور بأسرع ما يكون ممكنًا بشكل معقول. المصدر: Idaho Code 49-624."},"64":{"q":"ينطبق قانون أفسح المجال (Move Over) في ولاية أيداهو (49-624) على المركبات الثابتة التي تعرض أضواءً وامضة. أي مما يلي ليس نوع مركبة محميًا تحديدًا بموجب القانون؟","options":["سيارة ركاب خاصة متوقفة بسبب إطار مثقوب","شاحنة قطر","مركبة استجابة لحوادث الطرق","مركبة طوارئ مرخّصة"],"explanation":"يحمي Idaho Code 49-624 مركبات الشرطة الثابتة، ومركبات الطوارئ المرخّصة، وشاحنات القطر، ومركبات الاستجابة لحوادث الطرق التي تعرض أضواءً وامضة. أما سيارة الركاب الخاصة العادية فلا يرد ذكرها في قانون أفسح المجال. المصدر: Idaho Code 49-624."},"65":{"q":"على طريق ذي مسارين بمسار واحد فقط في كل اتجاه، يلزم قانون أفسح المجال في ولاية أيداهو السائق الذي يتجاوز مركبة طوارئ ثابتة ذات أضواء وامضة بأن:","options":["يخفّض السرعة إلى أقل من الحد المعلن ويحافظ على سرعة آمنة حتى يتجاوز المركبة بالكامل","يتوقف توقفًا تامًا وينتظر","يعبر خط المنتصف إلى المسارات المقابلة لإفساح المجال","يستمر بالسرعة المعلنة دون تخفيض"],"explanation":"حيث يستحيل الانتقال (مسار واحد في كل اتجاه)، يلزم Idaho Code 49-624 السائق بتخفيض السرعة إلى أقل من الحد المعلن والمتابعة بحذر بسرعة آمنة حتى يتجاوز المركبة الثابتة بالكامل. المصدر: Idaho Code 49-624."},"66":{"q":"بموجب Idaho Code 49-1422، لا يُطلب من سائق مركبة يلتقي حافلة مدرسية متوقفة قادمة من الاتجاه المقابل وقد فُعّلت إشاراتها المرئية الحمراء أن يتوقف إلا حين يكون الطريق ذا:","options":["أكثر من ثلاثة مسارات","أكثر من مسارين","مسار انعطاف مركزي مرسوم","أي جزيرة فاصلة من أي عرض"],"explanation":"ينص Idaho Code 49-1422 على أن حركة المرور القادمة من الاتجاه المقابل على طريق ذي أكثر من ثلاثة (3) مسارات ليست ملزمة بالتوقف عند الالتقاء بحافلة مدرسية مفعّلة إشاراتها. وتربط ولاية أيداهو هذا الاستثناء بعدد المسارات (أكثر من 3 مسارات)، وليس بمجرد وجود جزيرة فاصلة. المصدر: Idaho Code 49-1422."},"67":{"q":"على طريق قياسي ذي مسارين في ولاية أيداهو، على سائق المركبة الذي يلتقي أو يتجاوز حافلة مدرسية متوقفة وإشاراتها المرئية الحمراء وامضة أن:","options":["يتوقف قبل بلوغ الحافلة ولا يتابع حتى تتوقف الإشارات أو تتحرك الحافلة","يبطئ إلى 20 mph ويتجاوز بحذر","يتوقف فقط إذا كان الأطفال مرئيين","يتوقف فقط عند التجاوز من الخلف، وليس عند الالتقاء بها"],"explanation":"يلزم Idaho Code 49-1422 السائق الذي يلتقي أو يتجاوز من أي اتجاه بالتوقف قبل بلوغ حافلة مدرسية تعرض الإشارات المرئية المنصوص عليها في 49-915، وعدم المتابعة حتى تستأنف الحافلة الحركة أو تتوقف الإشارات عن العمل (باستثناء حالة القادمين من الاتجاه المقابل على طريق ذي أكثر من 3 مسارات). المصدر: Idaho Code 49-1422."},"68":{"q":"حتى 1 يوليو 2026، وبموجب Idaho Code 49-654، تقتصر سرعة الشاحنة ذات خمسة محاور أو أكثر التي يزيد وزنها على 26,000 lbs على الطرق السريعة بين الولايات في المناطق غير الحضرية على حد أقصى للسرعة قدره:","options":["10 mph أقل من الحد المسموح به للمركبات الأخف","65 mph بالضبط في كل مكان","5 mph أقل من الحد المسموح به للمركبات الأخف","نفس سرعة سيارات الركاب"],"explanation":"بموجب نسخة Idaho Code 49-654 السارية حتى 30 يونيو 2026، لا يجوز للشاحنات الثقيلة (5 محاور أو أكثر، يزيد وزنها على 26,000 lbs) أن تتجاوز سرعة المركبات الأخف بـ10 mph على الطرق السريعة بين الولايات غير الحضرية. ويعمل مشروع القانون House Bill 664 على معادلة هذه الحدود اعتبارًا من 1 يوليو 2026. المصدر: Idaho Code 49-654؛ HB664 (2026)."},"69":{"q":"اعتبارًا من 1 يوليو 2026، يغيّر مشروع القانون House Bill 664 في ولاية أيداهو قاعدة السرعة للشاحنات الثقيلة (5 محاور أو أكثر، يزيد وزنها على 26,000 lbs) بحيث تصبح سرعتها القصوى القانونية على الطرق السريعة بين الولايات والطرق السريعة للولاية والمواقع الأخرى:","options":["نفس السرعة للمركبات التي تقل عن خمسة محاور ووزنها 26,000 lbs أو أقل","ما زالت 10 mph أقل من سيارات الركاب على الطرق السريعة بين الولايات غير الحضرية","محددة بسقف 70 mph على مستوى الولاية بغض النظر عن الحد المعلن","محددة بسقف 65 mph في جميع المناطق الحضرية فقط"],"explanation":"يعدّل HB664 قانون Idaho Code 49-654 بحيث تخضع الشاحنات الثقيلة، اعتبارًا من 1 يوليو 2026، لنفس حدود السرعة القصوى المعلنة كالمركبات الأخف، ملغيًا حدّي الشاحنات السابقين البالغين 10 mph أقل و65 mph في المناطق الحضرية. المصدر: Idaho HB664 (2026)؛ Idaho Code 49-654."},"70":{"q":"بموجب Idaho Code 49-654، فإن حد السرعة القصوى الذي يمكن إعلانه على الطرق السريعة بين الولايات في أيداهو (للمركبات الأخف، بعد دراسة هندسية) هو:","options":["80 mph","75 mph","70 mph","85 mph"],"explanation":"يحدد Idaho Code 49-654 خط أساس قدره 75 mph على الطرق السريعة بين الولايات لكنه يخوّل ITD رفع الحد إلى 80 mph على الطرق السريعة بين الولايات بعد دراسة هندسية ومرورية؛ وحد 80 mph معلن على العديد من مقاطع الطرق السريعة بين الولايات الريفية في أيداهو. المصدر: Idaho Code 49-654؛ ITD."},"71":{"q":"بموجب Idaho Code 49-654، في حال عدم وجود حد معلن، فإن السرعة القصوى الافتراضية في أي منطقة سكنية أو تجارية أو حضرية هي:","options":["35 mph","25 mph","30 mph","20 mph"],"explanation":"يحدد Idaho Code 49-654 السرعة القصوى الافتراضية بـ35 mph في أي منطقة سكنية أو تجارية أو حضرية ما لم يُعلن خلاف ذلك. المصدر: Idaho Code 49-654."},"72":{"q":"ينظّم Idaho Code 49-630 استخدام المسارات على الطرق السريعة في أيداهو. على المركبة التي تسير بسرعة أبطأ من التدفق الطبيعي لحركة المرور، مثل شاحنة محمّلة تصعد منحدرًا، أن:","options":["تسير في المسار الأيمن أو أقرب ما يكون عمليًا إلى الحافة اليمنى","تستخدم المسار الأوسط لموازنة حركة المرور","تبقى في المسار الأيسر لإبقاء المسار الأيمن خاليًا للاندماج","تختار أي مسار طالما أشّرت"],"explanation":"يلزم Idaho Code 49-630 أي مركبة تسير بأقل من السرعة الطبيعية لحركة المرور بأن تُقاد في المسار الأيمن المتاح، أو أقرب ما يكون عمليًا إلى الرصيف/الحافة اليمنى، باستثناء حالات التجاوز أو الاستعداد للانعطاف يسارًا. المصدر: Idaho Code 49-630."},"73":{"q":"على طريق مقسوم أو باتجاه واحد، يوجّه دليل CDL لولاية أيداهو المركبة التجارية المتوقفة إلى وضع أجهزة التحذير من المخاطر الثلاثة على أي مسافات باتجاه حركة المرور القادمة؟","options":["10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة","10 أقدام و50 قدمًا و100 قدم باتجاه حركة المرور القادمة","15 قدمًا و100 قدم و300 قدم باتجاه حركة المرور القادمة","25 قدمًا و100 قدم و500 قدم باتجاه حركة المرور القادمة"],"explanation":"على طريق باتجاه واحد أو مقسوم، يلزم دليل CDL لولاية أيداهو (وفقًا لـ49 CFR 392.22) وضع أجهزة التحذير على مسافات 10 أقدام و100 قدم و200 قدم من المركبة باتجاه حركة المرور القادمة. المصدر: Idaho CDL Manual (ITD)."},"74":{"q":"على طريق ذي مسارين وباتجاهين في أيداهو، أين يقول دليل CDL لولاية أيداهو إنه يجب وضع أجهزة التحذير الثلاثة المطلوبة لمركبة تجارية (CMV) متوقفة؟","options":["ضمن 10 أقدام من المركبة، و100 قدم خلفها و100 قدم أمامها","الأجهزة الثلاثة جميعها ضمن 10 أقدام من مؤخرة المركبة","على مسافات 50 قدمًا و200 قدم و500 قدم خلفها فقط","100 قدم و200 قدم و300 قدم خلف المركبة"],"explanation":"على طريق ذي مسارين وباتجاهين، يلزم دليل CDL لولاية أيداهو (وفقًا لـ49 CFR 392.22) وضع جهاز واحد ضمن 10 أقدام من المركبة على جانب حركة المرور، وجهاز آخر على بُعد نحو 100 قدم خلفها، وجهاز ثالث على بُعد نحو 100 قدم أمامها، على الكتف أو في مسار التوقف. المصدر: Idaho CDL Manual (ITD)."},"75":{"q":"إذا توقفت مركبة تجارية (CMV) على طريق ذي مسارين في أيداهو ضمن 500 قدم من تلة أو منعطف أو عائق آخر، يقول دليل CDL لولاية أيداهو إنه يجب:","options":["تحريك جهاز التحذير الخلفي إلى الخلف إلى مسافة بين 100 و500 قدم لإعطاء السائقين تحذيرًا أكبر","ترك المثلثات الثلاثة جميعها في المواضع القياسية 10/100/100 قدم","تكديس الأجهزة الثلاثة جميعها خلف المركبة مباشرة","إزالة المثلثات والاعتماد على الأضواء الوامضة فقط"],"explanation":"عند التوقف ضمن 500 قدم من تلة أو منعطف أو عائق يحد من مسافة الرؤية، يوجّه دليل CDL لولاية أيداهو (وفقًا لـ49 CFR 392.22) إلى تحريك أبعد جهاز تحذير إلى الخلف على الطريق إلى نقطة تبعد من 100 إلى 500 قدم عن المركبة كي يحصل السائقون القادمون على تحذير كافٍ. المصدر: Idaho CDL Manual (ITD)."},"76":{"q":"يلزم دليل CDL لولاية أيداهو المركبة التجارية (CMV) المتوقفة بعرض أجهزة التحذير الخاصة بها (الشعلات أو المثلثات) خلال أي مدة بعد التوقف على طريق سريع؟","options":["10 دقائق","5 دقائق","15 دقيقة","30 دقيقة"],"explanation":"يلزم دليل CDL لولاية أيداهو (وفقًا لـ49 CFR 392.22) بوضع أجهزة التحذير من المخاطر خلال 10 دقائق من التوقف على الجزء المخصص للسير أو على كتف الطريق السريع. المصدر: Idaho CDL Manual (ITD)."},"77":{"q":"تشتهر منحدرات الطريق US-95 مثل منحدر Lewiston ومنحدر White Bird في أيداهو بانحداراتها الجبلية الحادة. ما ميزة السلامة التي توفرها هذه المنحدرات للشاحنات التي تفقد قدرتها على الكبح؟","options":["منحدرات هروب طارئة (منحدرات الشاحنات الجامحة)","أكشاك رسوم إلزامية للشاحنات الثقيلة","حظر مسار شاحنات على مستوى الولاية يحوّلها للالتفاف حولها","منظّمات سرعة إلكترونية مدمجة في الطريق"],"explanation":"إن منحدرات الطريق US-95 الجبلية الحادة في أيداهو (منحدر Lewiston ومنحدر White Bird) مزوّدة بمنحدرات هروب/شاحنات جامحة طارئة تستخدم طبقات حصى طويلة لإيقاف المركبة التي فقدت كوابحها. وتضع ITD لافتات تحذيرية مسبقة لهذه الانحدارات. المصدر: Idaho Transportation Department (ITD)، مشاريع منحدرات الهروب على US-95."},"78":{"q":"لا توجد في أيداهو طرق برسوم ولا جسور بين الولايات ممولة برسوم على نظام الطرق السريعة في الولاية. بالنسبة لسائق CDL يخطط لمسار عبر أيداهو، يعني هذا:","options":["لا تُفرض رسوم على الطرق السريعة بين الولايات أو الطرق السريعة للولاية في أيداهو","تُفرض الرسوم فقط على الجسور بين الولايات فوق نهر Snake","تدفع الشاحنات الثقيلة رسومًا لكل ميل على I-84","تنطبق الرسوم فقط في طريق التفافي حول حاضرة Boise"],"explanation":"لا تشغّل أيداهو أي طرق برسوم أو جسور برسوم على نظام طرقها السريعة العامة؛ فالطرق السريعة بين الولايات والطرق السريعة للولاية مجانية من الرسوم. وعلى سائقي CDL بدلًا من ذلك التخطيط لمتطلبات تصاريح الحمولات الزائدة الحجم/الوزن والمسارات المقيدة التي تديرها ITD، وليس الرسوم. المصدر: Idaho Transportation Department (ITD)."},"79":{"q":"أي جهة هي وكالة ترخيص السائقين في الولاية المسؤولة عن إصدار رخص القيادة التجارية في أيداهو؟","options":["إدارة النقل في أيداهو (ITD)","خدمات المركبات التجارية في شرطة ولاية أيداهو","الإدارة الفيدرالية لسلامة شركات النقل بالشاحنات","إدارة سلامة المركبات الآلية في أيداهو"],"explanation":"إن DMV التابع لإدارة النقل في أيداهو (ITD) هو وكالة ترخيص السائقين في الولاية ويُصدر رخص CDL. المصدر: صفحة CDL (رخصة القيادة التجارية) في ITD DMV؛ \"الخطوات العشر للحصول على CDL في أيداهو\" الصادرة عن ITD."},"80":{"q":"في أيداهو، إلى أين يذهب مقدّم طلب CDL فعليًا للتقديم وإجراء الاختبارات الكتابية وإصدار الرخصة؟","options":["امتياز اختبار خاص يديره ITD","مكتب ترخيص السائقين (DMV) التابع لمأمور المقاطعة","مكتب ميداني تابع لـFMCSA","مقر ITD الرئيسي في Boise فقط"],"explanation":"يُدار ترخيص السائقين في أيداهو على مستوى المقاطعة: يذهب مقدّمو الطلبات إلى مكتب ترخيص السائقين التابع لمأمور المقاطعة، الذي يتولى طلب CDL واختبارات المعرفة والإصدار بينما تعالج ITD السجلات. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 4."},"81":{"q":"قبل الترخيص، يجب على كل مقدّم طلب CDL جديد في أيداهو الحصول أولًا على أي وثيقة للتدرب وإجراء اختبار المهارات؟","options":["تصريح متعلّم للقيادة التجارية (CLP)","تصريح تعليمي من الفئة D","بطاقة صلاحية فيدرالية للنقل بين الولايات","تأييد تجاري مؤقت"],"explanation":"تشترط أيداهو على مقدّمي الطلبات الحصول على تصريح متعلّم للقيادة التجارية (CLP) للحصول على رخصة تجارية أو ترقيتها وللتدرب على الطرق العامة قبل اختبار المهارات. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 5."},"82":{"q":"ما مدة صلاحية تصريح المتعلّم للقيادة التجارية (CLP) في أيداهو بعد إصداره؟","options":["180 يومًا","90 يومًا","سنتان","سنة واحدة"],"explanation":"إن CLP في أيداهو صالح لمدة سنة واحدة (تختلف مدة أيداهو عن الحد الأدنى البالغ 180 يومًا المعتمد في بعض الولايات). المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 5."},"83":{"q":"بموجب القواعد الفيدرالية المطبقة في أيداهو، ما المدة التي يجب أن يحتفظ بها مقدّم الطلب بتصريح CLP قبل أن يُسمح له بإجراء اختبار مهارات CDL؟","options":["30 يومًا على الأقل","10 أيام على الأقل","14 يومًا على الأقل","60 يومًا على الأقل"],"explanation":"تشترط قواعد FMCSA المعتمدة من أيداهو الاحتفاظ بتصريح CLP لمدة لا تقل عن 14 يومًا قبل إجراء اختبار المهارات، حتى عند مجرد ترقية رخصة CDL قائمة. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوتان 5 و9."},"84":{"q":"يتكوّن اختبار مهارات CDL في أيداهو من أي ثلاثة أجزاء؟","options":["اختبار كتابي وفحص نظر واختبار طريق","اختبار الكوابح الهوائية واختبار الرجوع للخلف واختبار محطة الوزن","فحص ما قبل الرحلة واختبار محاكاة والقيادة الليلية","فحص ما قبل الرحلة والتحكم الأساسي بالمركبة والقيادة على الطريق"],"explanation":"تتبع أيداهو اختبار المهارات المؤلف من ثلاثة أجزاء وفق FMCSA: فحص ما قبل الرحلة (المركبة)، والتحكم الأساسي بالمركبة (مناورات في مسار مغلق)، واختبار القيادة على الطريق. المصدر: دليل CDL الصادر عن ITD؛ \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوات 6-9."},"85":{"q":"في يوم الاختبار في أيداهو، كم من الوقت يُمنح مقدّم الطلب لإكمال فحص المركبة ما قبل الرحلة؟","options":["45 دقيقة","15 دقيقة","60 دقيقة","30 دقيقة"],"explanation":"تتيح أيداهو 45 دقيقة لإكمال جزء فحص ما قبل الرحلة في يوم الاختبار؛ ويُعد فحص الكوابح غير السليم سببًا شائعًا للرسوب. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 6."},"86":{"q":"في جزء التحكم الأساسي (الرجوع للخلف) في أيداهو، أي مناورتين مطلوبتان من جميع مقدّمي الطلبات؟","options":["الرسو في الزقاق والركن الموازي","الرجوع في خط مستقيم والرسو في الزقاق","الرجوع في خط مستقيم والرجوع المُزاح","الركن الموازي والمسار المتعرج"],"explanation":"تشترط أيداهو الرجوع في خط مستقيم والرجوع المُزاح من كل مقدّم طلب؛ ثم يختار الفاحص إما الرسو في الزقاق أو الركن الموازي. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 7 (مناورات الفصل 12)."},"87":{"q":"أي تدريب يجب أن يكمله مقدّم طلب CDL في أيداهو من مزوّد مسجّل قبل أن يصبح مؤهلًا لإجراء اختبار المهارات؟","options":["دورة قيادة دفاعية معتمدة من الولاية","ندوة توجيه سلامة من ITD","دورة OSHA للمركبات التجارية","تدريب السائقين المبتدئين (ELDT)"],"explanation":"منذ 7 فبراير 2022، يجب على مقدّمي الطلبات إكمال تدريب السائقين المبتدئين (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـFMCSA قبل إجراء اختبارات المهارات المطلوبة. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 5؛ قاعدة ELDT الصادرة عن FMCSA."},"88":{"q":"في التصديق الذاتي لـCDL في أيداهو، من بين كم فئة قيادة يجب على مقدّم الطلب الاختيار؟","options":["اثنتان","ثلاث","خمس","أربع"],"explanation":"يجب على حاملي CDL في أيداهو التصديق ذاتيًا على إحدى أربع فئات: بين الولايات غير معفاة، أو بين الولايات معفاة، أو داخل الولاية غير معفاة، أو داخل الولاية معفاة. المصدر: مخطط \"البطاقات الطبية وفئات التصديق الذاتي\" الصادر عن ITD؛ FMCSA 49 CFR 383.71."},"89":{"q":"أي فئة تصديق ذاتي تصفها أيداهو بأنها \"المعيار الذهبي\" الذي يتطلب بطاقة طبية لمعظم سائقي CDL، ويتيح القيادة عبر حدود الولايات؟","options":["بين الولايات معفاة","داخل الولاية غير معفاة","بين الولايات غير معفاة","داخل الولاية معفاة"],"explanation":"تصف أيداهو فئة \"بين الولايات غير معفاة\" بأنها \"المعيار الذهبي\": فالسائق معتمد طبيًا ويجوز له عبور حدود الولايات ونقل أي شيء. المصدر: مخطط \"البطاقات الطبية وفئات التصديق الذاتي\" الصادر عن ITD."},"90":{"q":"أي فئة تصديق ذاتي في أيداهو تتطلب شهادة طبية سارية من DOT رغم أن كل القيادة تبقى داخل أيداهو؟","options":["داخل الولاية معفاة","داخل الولاية غير معفاة","بين الولايات معفاة","غير CDL معفاة"],"explanation":"يبقى سائقو فئة \"داخل الولاية غير معفاة\" ضمن أيداهو لكنهم مع ذلك معتمدون طبيًا (مثل نقل سلع غير معفاة)، وهذا يضيف قيد \"K\" (داخل الولاية فقط). المصدر: مخطط \"البطاقات الطبية وفئات التصديق الذاتي\" الصادر عن ITD."},"91":{"q":"أي قيد تضيفه أيداهو إلى رخصة CDL عندما يصدّق السائق ذاتيًا على فئة داخل الولاية؟","options":["قيد \"L\" (لا كوابح هوائية)","قيد \"K\" (التشغيل داخل الولاية فقط)","قيد \"E\" (ناقل حركة أوتوماتيكي فقط)","قيد \"O\" (لا عجلة خامسة)"],"explanation":"يضيف التصديق الذاتي على أي من فئتي داخل الولاية (معفاة أو غير معفاة) قيد \"K\" الذي يقصر السائق على التشغيل داخل الولاية. المصدر: مخطط \"البطاقات الطبية وفئات التصديق الذاتي\" الصادر عن ITD؛ 49 CFR 383.95."},"92":{"q":"يحصل حامل CDL غير معفى في أيداهو على شهادة فاحص طبي جديدة من DOT. ماذا يجب أن يفعل بها؟","options":["تقديم نسخة إلى DMV التابع للمقاطعة/ITD لإضافتها إلى سجل القيادة","الاحتفاظ بها في الشاحنة فقط لعمليات التفتيش على جانب الطريق","إرسال الأصل بالبريد إلى FMCSA في واشنطن العاصمة","حفظها لدى صاحب العمل بدلًا من الولاية"],"explanation":"يجب على حاملي CDL غير المعفيين تقديم (تزويد) نسخة من شهادة الفاحص الطبي إلى DMV التابع للمقاطعة/ITD عند الحصول عليها وعند كل تجديد كي تُسجّل في سجل القيادة. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 4."},"93":{"q":"يجوز إصدار شهادة الفاحص الطبي من DOT المستخدمة لرخصة CDL في أيداهو لمدة أقصاها كم؟","options":["حتى 12 شهرًا","حتى 36 شهرًا","حتى 24 شهرًا","حتى 48 شهرًا"],"explanation":"تكون شهادة الفحص البدني/الفاحص الطبي من DOT سارية لمدة تصل إلى 24 شهرًا؛ ويجوز للفاحص إصدارها لمدة أقل لمراقبة حالة طبية. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 2."},"94":{"q":"يجب أن يكون مزوّد الرعاية الطبية الذي يجري الفحص البدني من DOT لمقدّم طلب CDL في أيداهو مدرجًا أين؟","options":["في لجنة CDL التابعة لمجلس الطب في أيداهو","في السجل الوطني للفاحصين الطبيين المعتمدين","في قائمة الأطباء المعتمدين لدى ITD","في كشف سلامة شركات النقل التابع لـFMCSA"],"explanation":"يجب أن يكون مزوّد الفحص مدرجًا في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـFMCSA؛ وقد يؤدي استخدام مزوّد غير مسجّل إلى خفض درجة رخصة CDL. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 2؛ إشعار الشهادة الطبية الصادر عن ITD."},"95":{"q":"ما المدة التي تبقى فيها نتائج اختبار معرفة CDL (الكتابي) الناجح لمقدّم طلب في أيداهو سارية قبل وجوب إعادة جميع الاختبارات الكتابية؟","options":["سنة واحدة من تاريخ النجاح","ستة أشهر من تاريخ النجاح","سنتان من تاريخ النجاح","90 يومًا من تاريخ النجاح"],"explanation":"تبقى نتائج اختبار المعرفة سارية لمدة سنة واحدة من تاريخ النجاح؛ وإذا لم يُحصل على CDL خلال تلك السنة، فيجب إعادة جميع الاختبارات الكتابية. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 4."},"96":{"q":"إذا رسب مقدّم طلب في أيداهو في اختبار معرفة CDL (الكتابي)، بعد كم يجوز له إعادته؟","options":["في اليوم نفسه","بعد ثلاثة أيام","بعد سبعة أيام","بعد أربعة عشر يومًا"],"explanation":"يجوز لمقدّم الطلب الذي يرسب في اختبار كتابي إعادة الاختبار بعد ثلاثة أيام (ودفع رسم كل اختبار مجددًا). المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 4."},"97":{"q":"بعد اجتياز اختبار المهارات، ما مدة صلاحية رخصة CDL القياسية المُصدرة حديثًا في أيداهو؟","options":["سنتان فقط","سنة واحدة فقط","أربع سنوات (مع توفر خيار ثماني سنوات أيضًا)","ست سنوات ثابتة"],"explanation":"تُصدر أيداهو رخصة CDL لمدة أربع سنوات؛ كما توفر ITD خيار ثماني سنوات. ويجب على السائق العودة إلى DMV التابع للمقاطعة لإصدار الرخصة بعد النجاح. المصدر: \"الخطوات العشر للحصول على CDL في أيداهو\" الصادرة عن ITD، الخطوة 10."},"98":{"q":"كيف يُنظَّم رسم اختبار مهارات CDL الذي يتقاضاه الفاحص في أيداهو بموجب Idaho Code؟","options":["هو مبلغ ثابت محدد فيدراليًا في كل ولاية","يُعفى منه جميع مقدّمي الطلبات لأول مرة","يحدده فقط مدرسة تدريب مقدّم الطلب","هو محدد بسقف ولا يجوز أن يتجاوز حدًا أقصى يضعه Idaho Code لكل اختبار"],"explanation":"رسم اختبار المهارات الذي يحدده الفاحص محدد بسقف بموجب Idaho Code (لا يتجاوز الحد الأقصى القانوني لكل اختبار)، منفصلًا عن حصة المقاطعة الصغيرة. وقد تتغير المبالغ الدولارية الدقيقة. المصدر: \"عشر خطوات سهلة للحصول على C.D.L.\" الصادرة عن ITD، الخطوة 9."}}};
